func zend_fetch_static_prop_helper_SPEC(type_ int, execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var prop *Zval
	if UNEXPECTED(ZendFetchStaticPropertyAddress(&prop, nil, opline.GetExtendedValue() & ^ZEND_FETCH_OBJ_FLAGS, type_, opline.GetExtendedValue()&ZEND_FETCH_OBJ_FLAGS, OPLINE_C, EXECUTE_DATA_C) != SUCCESS) {
		ZEND_ASSERT(ExecutorGlobals.GetException() != nil || type_ == BP_VAR_IS)
		prop = &(ExecutorGlobals.GetUninitializedZval())
	}
	if type_ == BP_VAR_R || type_ == BP_VAR_IS {
		ZVAL_COPY_DEREF(EX_VAR(opline.GetResult().GetVar()), prop)
	} else {
		ZVAL_INDIRECT(EX_VAR(opline.GetResult().GetVar()), prop)
	}
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
