func ZEND_ASSIGN_STATIC_PROP_REF_SPEC_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var free_op_data ZendFreeOp
	var prop *Zval
	var value_ptr *Zval
	var prop_info *ZendPropertyInfo
	if ZendFetchStaticPropertyAddress(&prop, &prop_info, opline.GetExtendedValue() & ^ZEND_RETURNS_FUNCTION, BP_VAR_W, 0, OPLINE_C, EXECUTE_DATA_C) != SUCCESS {
		FREE_UNFETCHED_OP((opline + 1).GetOp1Type(), (opline + 1).GetOp1().GetVar())
		UNDEF_RESULT()
		HANDLE_EXCEPTION()
	}
	value_ptr = GetZvalPtrPtr((opline + 1).GetOp1Type(), (opline + 1).GetOp1(), &free_op_data, BP_VAR_W)
	if (opline+1).GetOp1Type() == IS_VAR && UNEXPECTED(Z_ISERROR_P(value_ptr)) {
		prop = &(ExecutorGlobals.GetUninitializedZval())
	} else if (opline+1).GetOp1Type() == IS_VAR && (opline.GetExtendedValue()&ZEND_RETURNS_FUNCTION) != 0 && UNEXPECTED(!(Z_ISREF_P(value_ptr))) {
		if UNEXPECTED(ZendWrongAssignToVariableReference(prop, value_ptr, OPLINE_C, EXECUTE_DATA_C) == nil) {
			prop = &(ExecutorGlobals.GetUninitializedZval())
		}
	} else if UNEXPECTED(prop_info.GetType() != 0) {
		prop = ZendAssignToTypedPropertyReference(prop_info, prop, value_ptr, EXECUTE_DATA_C)
	} else {
		ZendAssignToVariableReference(prop, value_ptr)
	}
	if UNEXPECTED(RETURN_VALUE_USED(opline)) {
		ZVAL_COPY(EX_VAR(opline.GetResult().GetVar()), prop)
	}
	if free_op_data != nil {
		ZvalPtrDtorNogc(free_op_data)
	}
	OPLINE = EX(opline) + 2
	return 0
}
func zend_leave_helper_SPEC(execute_data *ZendExecuteData) int {
	var old_execute_data *ZendExecuteData
	var call_info uint32 = EX_CALL_INFO()
	if EXPECTED((call_info & (ZEND_CALL_CODE | ZEND_CALL_TOP | ZEND_CALL_HAS_SYMBOL_TABLE | ZEND_CALL_FREE_EXTRA_ARGS | ZEND_CALL_ALLOCATED)) == 0) {
		ExecutorGlobals.SetCurrentExecuteData(EX(prev_execute_data))
		IFreeCompiledVariables(execute_data)
		if UNEXPECTED((call_info & ZEND_CALL_RELEASE_THIS) != 0) {
			OBJ_RELEASE(Z_OBJ(execute_data.GetThis()))
		} else if UNEXPECTED((call_info & ZEND_CALL_CLOSURE) != 0) {
			OBJ_RELEASE(ZEND_CLOSURE_OBJECT(EX(func_)))
		}
		ExecutorGlobals.SetVmStackTop((*Zval)(execute_data))
		execute_data = EX(prev_execute_data)
		if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
			ZendRethrowException(execute_data)
			HANDLE_EXCEPTION_LEAVE()
		}
		LOAD_NEXT_OPLINE()
		return 2
	} else if EXPECTED((call_info & (ZEND_CALL_CODE | ZEND_CALL_TOP)) == 0) {
		ExecutorGlobals.SetCurrentExecuteData(EX(prev_execute_data))
		IFreeCompiledVariables(execute_data)
		if UNEXPECTED((call_info & ZEND_CALL_HAS_SYMBOL_TABLE) != 0) {
			ZendCleanAndCacheSymbolTable(EX(symbol_table))
		}

		/* Free extra args before releasing the closure,
		 * as that may free the op_array. */

		ZendVmStackFreeExtraArgsEx(call_info, execute_data)
		if UNEXPECTED((call_info & ZEND_CALL_RELEASE_THIS) != 0) {
			OBJ_RELEASE(Z_OBJ(execute_data.GetThis()))
		} else if UNEXPECTED((call_info & ZEND_CALL_CLOSURE) != 0) {
			OBJ_RELEASE(ZEND_CLOSURE_OBJECT(EX(func_)))
		}
		old_execute_data = execute_data
		execute_data = EX(prev_execute_data)
		ZendVmStackFreeCallFrameEx(call_info, old_execute_data)
		if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
			ZendRethrowException(execute_data)
			HANDLE_EXCEPTION_LEAVE()
		}
		LOAD_NEXT_OPLINE()
		return 2
	} else if EXPECTED((call_info & ZEND_CALL_TOP) == 0) {
		ZendDetachSymbolTable(execute_data)
		DestroyOpArray(&EX(func_).op_array)
		EfreeSize(EX(func_), b.SizeOf("zend_op_array"))
		old_execute_data = execute_data
		ExecutorGlobals.SetCurrentExecuteData(EX(prev_execute_data))
		execute_data = ExecutorGlobals.GetCurrentExecuteData()
		ZendVmStackFreeCallFrameEx(call_info, old_execute_data)
		ZendAttachSymbolTable(execute_data)
		if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
			ZendRethrowException(execute_data)
			HANDLE_EXCEPTION_LEAVE()
		}
		LOAD_NEXT_OPLINE()
		return 2
	} else {
		if EXPECTED((call_info & ZEND_CALL_CODE) == 0) {
			ExecutorGlobals.SetCurrentExecuteData(EX(prev_execute_data))
			IFreeCompiledVariables(execute_data)
			if UNEXPECTED((call_info & (ZEND_CALL_HAS_SYMBOL_TABLE | ZEND_CALL_FREE_EXTRA_ARGS)) != 0) {
				if UNEXPECTED((call_info & ZEND_CALL_HAS_SYMBOL_TABLE) != 0) {
					ZendCleanAndCacheSymbolTable(EX(symbol_table))
				}
				ZendVmStackFreeExtraArgsEx(call_info, execute_data)
			}
			if UNEXPECTED((call_info & ZEND_CALL_CLOSURE) != 0) {
				OBJ_RELEASE(ZEND_CLOSURE_OBJECT(EX(func_)))
			}
			return -1
		} else {
			var symbol_table *ZendArray = EX(symbol_table)
			ZendDetachSymbolTable(execute_data)
			old_execute_data = EX(prev_execute_data)
			for old_execute_data != nil {
				if old_execute_data.GetFunc() != nil && (ZEND_CALL_INFO(old_execute_data)&ZEND_CALL_HAS_SYMBOL_TABLE) != 0 {
					if old_execute_data.GetSymbolTable() == symbol_table {
						ZendAttachSymbolTable(old_execute_data)
					}
					break
				}
				old_execute_data = old_execute_data.GetPrevExecuteData()
			}
			ExecutorGlobals.SetCurrentExecuteData(EX(prev_execute_data))
			return -1
		}
	}
}
