func zend_dispatch_try_catch_finally_helper_SPEC(try_catch_offset uint32, op_num uint32, execute_data *ZendExecuteData) int {
	/* May be NULL during generator closing (only finally blocks are executed) */

	var ex *ZendObject = ExecutorGlobals.GetException()

	/* Walk try/catch/finally structures upwards, performing the necessary actions */

	for try_catch_offset != uint32_t-1 {
		var try_catch *ZendTryCatchElement = &EX(func_).op_array.try_catch_array[try_catch_offset]
		if op_num < try_catch.GetCatchOp() && ex != nil {

			/* Go to catch block */

			CleanupLiveVars(execute_data, op_num, try_catch.GetCatchOp())
			ZEND_VM_JMP_EX(&EX(func_).op_array.opcodes[try_catch.GetCatchOp()], 0)
		} else if op_num < try_catch.GetFinallyOp() {

			/* Go to finally block */

			var fast_call *Zval = EX_VAR(EX(func_).op_array.opcodes[try_catch.GetFinallyEnd()].op1.var_)
			CleanupLiveVars(execute_data, op_num, try_catch.GetFinallyOp())
			Z_OBJ_P(fast_call) = ExecutorGlobals.GetException()
			ExecutorGlobals.SetException(nil)
			Z_OPLINE_NUM_P(fast_call) = uint32_t - 1
			ZEND_VM_JMP_EX(&EX(func_).op_array.opcodes[try_catch.GetFinallyOp()], 0)
		} else if op_num < try_catch.GetFinallyEnd() {
			var fast_call *Zval = EX_VAR(EX(func_).op_array.opcodes[try_catch.GetFinallyEnd()].op1.var_)

			/* cleanup incomplete RETURN statement */

			if Z_OPLINE_NUM_P(fast_call) != uint32_t-1 && (EX(func_).op_array.opcodes[Z_OPLINE_NUM_P(fast_call)].op2_type&(IS_TMP_VAR|IS_VAR)) != 0 {
				var return_value *Zval = EX_VAR(EX(func_).op_array.opcodes[Z_OPLINE_NUM_P(fast_call)].op2.var_)
				ZvalPtrDtor(return_value)
			}

			/* Chain potential exception from wrapping finally block */

			if Z_OBJ_P(fast_call) != nil {
				if ex != nil {
					ZendExceptionSetPrevious(ex, Z_OBJ_P(fast_call))
				} else {
					ExecutorGlobals.SetException(Z_OBJ_P(fast_call))
				}
				ex = Z_OBJ_P(fast_call)
			}

			/* Chain potential exception from wrapping finally block */

		}
		try_catch_offset--
	}

	/* Uncaught exception */

	CleanupLiveVars(execute_data, op_num, 0)
	if UNEXPECTED((EX_CALL_INFO() & ZEND_CALL_GENERATOR) != 0) {
		var generator *ZendGenerator = ZendGetRunningGenerator(EXECUTE_DATA_C)
		ZendGeneratorClose(generator, 1)
		return -1
	} else {

		/* We didn't execute RETURN, and have to initialize return_value */

		if EX(return_value) {
			ZVAL_UNDEF(EX(return_value))
		}
		return zend_leave_helper_SPEC(execute_data)
	}
}
func ZEND_HANDLE_EXCEPTION_SPEC_HANDLER(execute_data *ZendExecuteData) int {
	var throw_op *ZendOp = ExecutorGlobals.GetOplineBeforeException()
	var throw_op_num uint32 = throw_op - EX(func_).op_array.opcodes
	var i int
	var current_try_catch_offset int = -1
	if (throw_op.GetOpcode() == ZEND_FREE || throw_op.GetOpcode() == ZEND_FE_FREE) && (throw_op.GetExtendedValue()&ZEND_FREE_ON_RETURN) != 0 {

		/* exceptions thrown because of loop var destruction on return/break/...
		 * are logically thrown at the end of the foreach loop, so adjust the
		 * throw_op_num.
		 */

		var range_ *ZendLiveRange = FindLiveRange(&EX(func_).op_array, throw_op_num, throw_op.GetOp1().GetVar())
		throw_op_num = range_.GetEnd()
	}

	/* Find the innermost try/catch/finally the exception was thrown in */

	for i = 0; i < EX(func_).op_array.last_try_catch; i++ {
		var try_catch *ZendTryCatchElement = &EX(func_).op_array.try_catch_array[i]
		if try_catch.GetTryOp() > throw_op_num {

			/* further blocks will not be relevant... */

			break

			/* further blocks will not be relevant... */

		}
		if throw_op_num < try_catch.GetCatchOp() || throw_op_num < try_catch.GetFinallyEnd() {
			current_try_catch_offset = i
		}
	}
	CleanupUnfinishedCalls(execute_data, throw_op_num)
	if (throw_op.GetResultType() & (IS_VAR | IS_TMP_VAR)) != 0 {
		switch throw_op.GetOpcode() {
		case ZEND_ADD_ARRAY_ELEMENT:

		case ZEND_ADD_ARRAY_UNPACK:

		case ZEND_ROPE_INIT:

		case ZEND_ROPE_ADD:
			break
		case ZEND_FETCH_CLASS:

		case ZEND_DECLARE_ANON_CLASS:
			break
		default:
			ZvalPtrDtorNogc(EX_VAR(throw_op.GetResult().GetVar()))
		}
	}
	return zend_dispatch_try_catch_finally_helper_SPEC(current_try_catch_offset, throw_op_num, execute_data)
}
func ZEND_USER_OPCODE_SPEC_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var ret int
	ret = ZendUserOpcodeHandlers[opline.GetOpcode()](execute_data)
	opline = EX(opline)
	switch ret {
	case ZEND_USER_OPCODE_CONTINUE:
		return 0
	case ZEND_USER_OPCODE_RETURN:
		if UNEXPECTED((EX_CALL_INFO() & ZEND_CALL_GENERATOR) != 0) {
			var generator *ZendGenerator = ZendGetRunningGenerator(EXECUTE_DATA_C)
			ZendGeneratorClose(generator, 1)
			return -1
		} else {
			return zend_leave_helper_SPEC(execute_data)
		}
	case ZEND_USER_OPCODE_ENTER:
		return 1
	case ZEND_USER_OPCODE_LEAVE:
		return 2
	case ZEND_USER_OPCODE_DISPATCH:
		ZEND_VM_DISPATCH(opline.GetOpcode(), opline)
	default:
		ZEND_VM_DISPATCH(zend_uchar(ret&0xff), opline)
	}
}
func zend_yield_in_closed_generator_helper_SPEC(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	ZendThrowError(nil, "Cannot yield from finally in a force-closed generator")
	FREE_UNFETCHED_OP(opline.GetOp2Type(), opline.GetOp2().GetVar())
	FREE_UNFETCHED_OP(opline.GetOp1Type(), opline.GetOp1().GetVar())
	UNDEF_RESULT()
	HANDLE_EXCEPTION()
}
func ZEND_DISCARD_EXCEPTION_SPEC_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var fast_call *Zval = EX_VAR(opline.GetOp1().GetVar())

	/* cleanup incomplete RETURN statement */

	if Z_OPLINE_NUM_P(fast_call) != uint32_t-1 && (EX(func_).op_array.opcodes[Z_OPLINE_NUM_P(fast_call)].op2_type&(IS_TMP_VAR|IS_VAR)) != 0 {
		var return_value *Zval = EX_VAR(EX(func_).op_array.opcodes[Z_OPLINE_NUM_P(fast_call)].op2.var_)
		ZvalPtrDtor(return_value)
	}

	/* cleanup delayed exception */

	if Z_OBJ_P(fast_call) != nil {

		/* discard the previously thrown exception */

		OBJ_RELEASE(Z_OBJ_P(fast_call))
		Z_OBJ_P(fast_call) = nil
	}
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_FAST_CALL_SPEC_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var fast_call *Zval = EX_VAR(opline.GetResult().GetVar())
	Z_OBJ_P(fast_call) = nil

	/* set return address */

	Z_OPLINE_NUM_P(fast_call) = opline - EX(func_).op_array.opcodes
	ZEND_VM_JMP_EX(OP_JMP_ADDR(opline, opline.GetOp1()), 0)
}
func ZEND_FAST_RET_SPEC_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var fast_call *Zval = EX_VAR(opline.GetOp1().GetVar())
	var current_try_catch_offset uint32
	var current_op_num uint32
	if Z_OPLINE_NUM_P(fast_call) != uint32_t-1 {
		var fast_ret *ZendOp = EX(func_).op_array.opcodes + Z_OPLINE_NUM_P(fast_call)
		ZEND_VM_JMP_EX(fast_ret+1, 0)
	}

	/* special case for unhandled exceptions */

	ExecutorGlobals.SetException(Z_OBJ_P(fast_call))
	Z_OBJ_P(fast_call) = nil
	current_try_catch_offset = opline.GetOp2().GetNum()
	current_op_num = opline - EX(func_).op_array.opcodes
	return zend_dispatch_try_catch_finally_helper_SPEC(current_try_catch_offset, current_op_num, execute_data)
}
func ZEND_ASSERT_CHECK_SPEC_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	if ExecutorGlobals.GetAssertions() <= 0 {
		var target *ZendOp = OP_JMP_ADDR(opline, opline.GetOp2())
		if RETURN_VALUE_USED(opline) {
			ZVAL_TRUE(EX_VAR(opline.GetResult().GetVar()))
		}
		ZEND_VM_JMP_EX(target, 0)
	} else {
		ZEND_VM_NEXT_OPCODE()
	}
}
func ZEND_CALL_TRAMPOLINE_SPEC_HANDLER(execute_data *ZendExecuteData) int {
	var args *ZendArray = nil
	var fbc *ZendFunction = EX(func_)
	var ret *Zval = EX(return_value)
	var call_info uint32 = EX_CALL_INFO() & (ZEND_CALL_NESTED | ZEND_CALL_TOP | ZEND_CALL_RELEASE_THIS)
	var num_args uint32 = EX_NUM_ARGS()
	var call *ZendExecuteData
	if num_args != 0 {
		var p *Zval = ZEND_CALL_ARG(execute_data, 1)
		var end *Zval = p + num_args
		args = ZendNewArray(num_args)
		args.RealInitPacked()
		for {
			var __fill_ht *HashTable = args
			var __fill_bkt *Bucket = __fill_ht.GetArData() + __fill_ht.GetNNumUsed()
			var __fill_idx uint32 = __fill_ht.GetNNumUsed()
			ZEND_ASSERT((__fill_ht.Flags() & HASH_FLAG_PACKED) != 0)
			for {
				ZEND_HASH_FILL_ADD(p)
				p++
				if p == end {
					break
				}
			}
			__fill_ht.SetNNumUsed(__fill_idx)
			__fill_ht.SetNNumOfElements(__fill_idx)
			__fill_ht.SetNNextFreeElement(__fill_idx)
			__fill_ht.SetNInternalPointer(0)
			break
		}
	}
	call = execute_data
	ExecutorGlobals.SetCurrentExecuteData(EX(prev_execute_data))
	execute_data = ExecutorGlobals.GetCurrentExecuteData()
	if fbc.GetOpArray().IsStatic() {
		call.SetFunc(fbc.GetOpArray().GetScope().GetCallstatic())
	} else {
		call.SetFunc(fbc.GetOpArray().GetScope().GetCall())
	}
	ZEND_ASSERT(ZendVmCalcUsedStack(2, call.GetFunc()) <= size_t((*byte)(ExecutorGlobals.GetVmStackEnd())-(*byte)(call)))
	ZEND_CALL_NUM_ARGS(call) = 2
	ZVAL_STR(ZEND_CALL_ARG(call, 1), fbc.GetFunctionName())
	if args != nil {
		ZVAL_ARR(ZEND_CALL_ARG(call, 2), args)
	} else {
		ZVAL_EMPTY_ARRAY(ZEND_CALL_ARG(call, 2))
	}
	ZendFreeTrampoline(fbc)
	fbc = call.GetFunc()
	if EXPECTED(fbc.GetType() == ZEND_USER_FUNCTION) {
		if UNEXPECTED(!(RUN_TIME_CACHE(&fbc.op_array))) {
			InitFuncRunTimeCache(&fbc.op_array)
		}
		execute_data = call
		IInitFuncExecuteData(&fbc.op_array, ret, 0, EXECUTE_DATA_C)
		if EXPECTED(ZendExecuteEx == ExecuteEx) {
			return 1
		} else {
			execute_data = EX(prev_execute_data)
			ZEND_ADD_CALL_FLAG(call, ZEND_CALL_TOP)
			ZendExecuteEx(call)
		}
	} else {
		var retval Zval
		ZEND_ASSERT(fbc.GetType() == ZEND_INTERNAL_FUNCTION)
		ExecutorGlobals.SetCurrentExecuteData(call)
		if UNEXPECTED(fbc.IsHasTypeHints()) && UNEXPECTED(ZendVerifyInternalArgTypes(fbc, call) == 0) {
			ZendVmStackFreeCallFrame(call)
			if ret != nil {
				ZVAL_UNDEF(ret)
			}
			goto call_trampoline_end
		}
		if ret == nil {
			ret = &retval
		}
		ZVAL_NULL(ret)
		if ZendExecuteInternal == nil {

			/* saves one function call if zend_execute_internal is not used */

			fbc.GetInternalFunction().GetHandler()(call, ret)

			/* saves one function call if zend_execute_internal is not used */

		} else {
			ZendExecuteInternal(call, ret)
		}
		ExecutorGlobals.SetCurrentExecuteData(call.GetPrevExecuteData())
	call_trampoline_end:
		ZendVmStackFreeArgs(call)
		if ret == &retval {
			ZvalPtrDtor(ret)
		}
	}
	execute_data = ExecutorGlobals.GetCurrentExecuteData()
	if !(EX(func_)) || !(ZEND_USER_CODE(EX(func_).type_)) || (call_info&ZEND_CALL_TOP) != 0 {
		return -1
	}
	if UNEXPECTED((call_info & ZEND_CALL_RELEASE_THIS) != 0) {
		var object *ZendObject = Z_OBJ(call.GetThis())
		OBJ_RELEASE(object)
	}
	ZendVmStackFreeCallFrame(call)
	if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
		ZendRethrowException(execute_data)
		HANDLE_EXCEPTION_LEAVE()
	}
	ZEND_VM_INC_OPCODE()
	return 2
}
func ZEND_JMP_FORWARD_SPEC_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	OPLINE = OP_JMP_ADDR(opline, opline.GetOp1())
	return 0
}
func zend_interrupt_helper_SPEC(execute_data *ZendExecuteData) int {
	ExecutorGlobals.SetVmInterrupt(0)
	if ExecutorGlobals.GetTimedOut() != 0 {
		ZendTimeout(0)
	} else if ZendInterruptFunction != nil {
		ZendInterruptFunction(execute_data)
		return 1
	}
	return 0
}
func ZEND_INIT_FCALL_BY_NAME_SPEC_CONST_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var fbc *ZendFunction
	var function_name *Zval
	var func_ *Zval
	var call *ZendExecuteData
	fbc = CACHED_PTR(opline.GetResult().GetNum())
	if UNEXPECTED(fbc == nil) {
		function_name = (*Zval)(RT_CONSTANT(opline, opline.GetOp2()))
		func_ = ExecutorGlobals.GetFunctionTable().FindEx(Z_STR_P(function_name+1), 1)
		if UNEXPECTED(func_ == nil) {
			return zend_undefined_function_helper_SPEC(execute_data)
		}
		fbc = Z_FUNC_P(func_)
		if EXPECTED(fbc.GetType() == ZEND_USER_FUNCTION) && UNEXPECTED(!(RUN_TIME_CACHE(&fbc.op_array))) {
			InitFuncRunTimeCache(&fbc.op_array)
		}
		CACHE_PTR(opline.GetResult().GetNum(), fbc)
	}
	call = _zendVmStackPushCallFrame(ZEND_CALL_NESTED_FUNCTION, fbc, opline.GetExtendedValue(), nil)
	call.SetPrevExecuteData(EX(call))
	EX(call) = call
	ZEND_VM_NEXT_OPCODE()
}
func ZEND_INIT_DYNAMIC_CALL_SPEC_CONST_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var function_name *Zval
	var call *ZendExecuteData
	function_name = RT_CONSTANT(opline, opline.GetOp2())
try_function_name:
	if IS_CONST != IS_CONST && EXPECTED(Z_TYPE_P(function_name) == IS_STRING) {
		call = ZendInitDynamicCallString(Z_STR_P(function_name), opline.GetExtendedValue())
	} else if IS_CONST != IS_CONST && EXPECTED(Z_TYPE_P(function_name) == IS_OBJECT) {
		call = ZendInitDynamicCallObject(function_name, opline.GetExtendedValue())
	} else if EXPECTED(Z_TYPE_P(function_name) == IS_ARRAY) {
		call = ZendInitDynamicCallArray(Z_ARRVAL_P(function_name), opline.GetExtendedValue())
	} else if (IS_CONST&(IS_VAR|IS_CV)) != 0 && EXPECTED(Z_TYPE_P(function_name) == IS_REFERENCE) {
		function_name = Z_REFVAL_P(function_name)
		goto try_function_name
	} else {
		if IS_CONST == IS_CV && UNEXPECTED(Z_TYPE_P(function_name) == IS_UNDEF) {
			ZVAL_UNDEFINED_OP2()
			if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
				HANDLE_EXCEPTION()
			}
		}
		ZendThrowError(nil, "Function name must be a string")
		call = nil
	}
	if UNEXPECTED(call == nil) {
		HANDLE_EXCEPTION()
	}
	if (IS_CONST & (IS_VAR | IS_TMP_VAR)) != 0 {
		if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
			if call != nil {
				if call.GetFunc().IsCallViaTrampoline() {
					ZendStringReleaseEx(call.GetFunc().GetFunctionName(), 0)
					ZendFreeTrampoline(call.GetFunc())
				}
				ZendVmStackFreeCallFrame(call)
			}
			HANDLE_EXCEPTION()
		}
	}
	call.SetPrevExecuteData(EX(call))
	EX(call) = call
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
