func ZEND_BOOL_NOT_SPEC_CONST_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var val *Zval
	val = RT_CONSTANT(opline, opline.GetOp1())
	if Z_TYPE_INFO_P(val) == IS_TRUE {
		ZVAL_FALSE(EX_VAR(opline.GetResult().GetVar()))
	} else if EXPECTED(Z_TYPE_INFO_P(val) <= IS_TRUE) {

		/* The result and op1 can be the same cv zval */

		var orig_val_type uint32 = Z_TYPE_INFO_P(val)
		ZVAL_TRUE(EX_VAR(opline.GetResult().GetVar()))
		if IS_CONST == IS_CV && UNEXPECTED(orig_val_type == IS_UNDEF) {
			ZVAL_UNDEFINED_OP1()
			ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
		}
	} else {
		ZVAL_BOOL(EX_VAR(opline.GetResult().GetVar()), !(IZendIsTrue(val)))
		ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
	}
	ZEND_VM_NEXT_OPCODE()
}
func ZEND_ECHO_SPEC_CONST_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var z *Zval
	z = RT_CONSTANT(opline, opline.GetOp1())
	if Z_TYPE_P(z) == IS_STRING {
		var str *ZendString = Z_STR_P(z)
		if ZSTR_LEN(str) != 0 {
			ZendWrite(ZSTR_VAL(str), ZSTR_LEN(str))
		}
	} else {
		var str *ZendString = ZvalGetStringFunc(z)
		if ZSTR_LEN(str) != 0 {
			ZendWrite(ZSTR_VAL(str), ZSTR_LEN(str))
		} else if IS_CONST == IS_CV && UNEXPECTED(Z_TYPE_P(z) == IS_UNDEF) {
			ZVAL_UNDEFINED_OP1()
		}
		ZendStringReleaseEx(str, 0)
	}
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
