func ZEND_RETURN_SPEC_CONST_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var retval_ptr *Zval
	var return_value *Zval
	var free_op1 ZendFreeOp
	retval_ptr = RT_CONSTANT(opline, opline.GetOp1())
	return_value = EX(return_value)
	if IS_CONST == IS_CV && UNEXPECTED(Z_TYPE_INFO_P(retval_ptr) == IS_UNDEF) {
		retval_ptr = ZVAL_UNDEFINED_OP1()
		if return_value != nil {
			ZVAL_NULL(return_value)
		}
	} else if return_value == nil {
		if (IS_CONST & (IS_VAR | IS_TMP_VAR)) != 0 {
			if Z_REFCOUNTED_P(free_op1) && Z_DELREF_P(free_op1) == 0 {
				RcDtorFunc(Z_COUNTED_P(free_op1))
			}
		}
	} else {
		if (IS_CONST & (IS_CONST | IS_TMP_VAR)) != 0 {
			ZVAL_COPY_VALUE(return_value, retval_ptr)
			if IS_CONST == IS_CONST {
				if UNEXPECTED(Z_OPT_REFCOUNTED_P(return_value)) {
					Z_ADDREF_P(return_value)
				}
			}
		} else if IS_CONST == IS_CV {
			for {
				if Z_OPT_REFCOUNTED_P(retval_ptr) {
					if EXPECTED(!(Z_OPT_ISREF_P(retval_ptr))) {
						if EXPECTED((EX_CALL_INFO() & ZEND_CALL_CODE) == 0) {
							var ref *ZendRefcounted = Z_COUNTED_P(retval_ptr)
							ZVAL_COPY_VALUE(return_value, retval_ptr)
							if GC_MAY_LEAK(ref) {
								GcPossibleRoot(ref)
							}
							ZVAL_NULL(retval_ptr)
							break
						} else {
							Z_ADDREF_P(retval_ptr)
						}
					} else {
						retval_ptr = Z_REFVAL_P(retval_ptr)
						if Z_OPT_REFCOUNTED_P(retval_ptr) {
							Z_ADDREF_P(retval_ptr)
						}
					}
				}
				ZVAL_COPY_VALUE(return_value, retval_ptr)
				break
			}
		} else {
			if UNEXPECTED(Z_ISREF_P(retval_ptr)) {
				var ref *ZendRefcounted = Z_COUNTED_P(retval_ptr)
				retval_ptr = Z_REFVAL_P(retval_ptr)
				ZVAL_COPY_VALUE(return_value, retval_ptr)
				if UNEXPECTED(GC_DELREF(ref) == 0) {
					EfreeSize(ref, b.SizeOf("zend_reference"))
				} else if Z_OPT_REFCOUNTED_P(retval_ptr) {
					Z_ADDREF_P(retval_ptr)
				}
			} else {
				ZVAL_COPY_VALUE(return_value, retval_ptr)
			}
		}
	}
	return zend_leave_helper_SPEC(execute_data)
}
func ZEND_RETURN_BY_REF_SPEC_CONST_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var retval_ptr *Zval
	for {
		if (IS_CONST&(IS_CONST|IS_TMP_VAR)) != 0 || IS_CONST == IS_VAR && opline.GetExtendedValue() == ZEND_RETURNS_VALUE {

			/* Not supposed to happen, but we'll allow it */

			ZendError(E_NOTICE, "Only variable references should be returned by reference")
			retval_ptr = RT_CONSTANT(opline, opline.GetOp1())
			if !(EX(return_value)) {

			} else {
				if IS_CONST == IS_VAR && UNEXPECTED(Z_ISREF_P(retval_ptr)) {
					ZVAL_COPY_VALUE(EX(return_value), retval_ptr)
					break
				}
				ZVAL_NEW_REF(EX(return_value), retval_ptr)
				if IS_CONST == IS_CONST {
					Z_TRY_ADDREF_P(retval_ptr)
				}
			}
			break
		}
		retval_ptr = nil
		if IS_CONST == IS_VAR {
			ZEND_ASSERT(retval_ptr != &(ExecutorGlobals.GetUninitializedZval()))
			if opline.GetExtendedValue() == ZEND_RETURNS_FUNCTION && !(Z_ISREF_P(retval_ptr)) {
				ZendError(E_NOTICE, "Only variable references should be returned by reference")
				if EX(return_value) {
					ZVAL_NEW_REF(EX(return_value), retval_ptr)
				}
				break
			}
		}
		if EX(return_value) {
			if Z_ISREF_P(retval_ptr) {
				Z_ADDREF_P(retval_ptr)
			} else {
				ZVAL_MAKE_REF_EX(retval_ptr, 2)
			}
			ZVAL_REF(EX(return_value), Z_REF_P(retval_ptr))
		}
		break
	}
	return zend_leave_helper_SPEC(execute_data)
}
func ZEND_GENERATOR_RETURN_SPEC_CONST_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var retval *Zval
	var generator *ZendGenerator = ZendGetRunningGenerator(EXECUTE_DATA_C)
	retval = RT_CONSTANT(opline, opline.GetOp1())

	/* Copy return value into generator->retval */

	if (IS_CONST & (IS_CONST | IS_TMP_VAR)) != 0 {
		ZVAL_COPY_VALUE(&generator.retval, retval)
		if IS_CONST == IS_CONST {
			if UNEXPECTED(Z_OPT_REFCOUNTED(generator.GetRetval())) {
				Z_ADDREF(generator.GetRetval())
			}
		}
	} else if IS_CONST == IS_CV {
		ZVAL_COPY_DEREF(&generator.retval, retval)
	} else {
		if UNEXPECTED(Z_ISREF_P(retval)) {
			var ref *ZendRefcounted = Z_COUNTED_P(retval)
			retval = Z_REFVAL_P(retval)
			ZVAL_COPY_VALUE(&generator.retval, retval)
			if UNEXPECTED(GC_DELREF(ref) == 0) {
				EfreeSize(ref, b.SizeOf("zend_reference"))
			} else if Z_OPT_REFCOUNTED_P(retval) {
				Z_ADDREF_P(retval)
			}
		} else {
			ZVAL_COPY_VALUE(&generator.retval, retval)
		}
	}

	/* Close the generator to free up resources */

	ZendGeneratorClose(generator, 1)

	/* Pass execution back to handling code */

	return -1

	/* Pass execution back to handling code */
}
func ZEND_THROW_SPEC_CONST_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var value *Zval
	value = RT_CONSTANT(opline, opline.GetOp1())
	for {
		if IS_CONST == IS_CONST || UNEXPECTED(Z_TYPE_P(value) != IS_OBJECT) {
			if (IS_CONST&(IS_VAR|IS_CV)) != 0 && Z_ISREF_P(value) {
				value = Z_REFVAL_P(value)
				if EXPECTED(Z_TYPE_P(value) == IS_OBJECT) {
					break
				}
			}
			if IS_CONST == IS_CV && UNEXPECTED(Z_TYPE_P(value) == IS_UNDEF) {
				ZVAL_UNDEFINED_OP1()
				if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
					HANDLE_EXCEPTION()
				}
			}
			ZendThrowError(nil, "Can only throw objects")
			HANDLE_EXCEPTION()
		}
		break
	}
	ZendExceptionSave()
	if IS_CONST != IS_TMP_VAR {
		Z_TRY_ADDREF_P(value)
	}
	ZendThrowExceptionObject(value)
	ZendExceptionRestore()
	HANDLE_EXCEPTION()
}
func ZEND_CATCH_SPEC_CONST_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var ce *ZendClassEntry
	var catch_ce *ZendClassEntry
	var exception *ZendObject
	var ex *Zval

	/* Check whether an exception has been thrown, if not, jump over code */

	ZendExceptionRestore()
	if ExecutorGlobals.GetException() == nil {
		ZEND_VM_JMP_EX(OP_JMP_ADDR(opline, opline.GetOp2()), 0)
	}
	catch_ce = CACHED_PTR(opline.GetExtendedValue() & ^ZEND_LAST_CATCH)
	if UNEXPECTED(catch_ce == nil) {
		catch_ce = ZendFetchClassByName(Z_STR_P(RT_CONSTANT(opline, opline.GetOp1())), Z_STR_P(RT_CONSTANT(opline, opline.GetOp1())+1), ZEND_FETCH_CLASS_NO_AUTOLOAD)
		CACHE_PTR(opline.GetExtendedValue() & ^ZEND_LAST_CATCH, catch_ce)
	}
	ce = ExecutorGlobals.GetException().GetCe()
	if ce != catch_ce {
		if catch_ce == nil || InstanceofFunction(ce, catch_ce) == 0 {
			if (opline.GetExtendedValue() & ZEND_LAST_CATCH) != 0 {
				ZendRethrowException(execute_data)
				HANDLE_EXCEPTION()
			}
			ZEND_VM_JMP_EX(OP_JMP_ADDR(opline, opline.GetOp2()), 0)
		}
	}
	exception = ExecutorGlobals.GetException()
	ex = EX_VAR(opline.GetResult().GetVar())

	/* Always perform a strict assignment. There is a reasonable expectation that if you
	 * write "catch (Exception $e)" then $e will actually be instanceof Exception. As such,
	 * we should not permit coercion to string here. */

	var tmp Zval
	ZVAL_OBJ(&tmp, exception)
	ExecutorGlobals.SetException(nil)
	ZendAssignToVariable(ex, &tmp, IS_TMP_VAR, 1)
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
