func ZEND_YIELD_FROM_SPEC_CONST_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var generator *ZendGenerator = ZendGetRunningGenerator(EXECUTE_DATA_C)
	var val *Zval
	val = RT_CONSTANT(opline, opline.GetOp1())
	if UNEXPECTED(generator.IsForcedClose()) {
		ZendThrowError(nil, "Cannot use \"yield from\" in a force-closed generator")
		UNDEF_RESULT()
		HANDLE_EXCEPTION()
	}
	if Z_TYPE_P(val) == IS_ARRAY {
		ZVAL_COPY_VALUE(&generator.values, val)
		if IS_CONST != IS_TMP_VAR && Z_OPT_REFCOUNTED_P(val) {
			Z_ADDREF_P(val)
		}
		Z_FE_POS(generator.GetValues()) = 0
	} else if IS_CONST != IS_CONST && Z_TYPE_P(val) == IS_OBJECT && Z_OBJCE_P(val).GetGetIterator() != nil {
		var ce *ZendClassEntry = Z_OBJCE_P(val)
		if ce == ZendCeGenerator {
			var new_gen *ZendGenerator = (*ZendGenerator)(Z_OBJ_P(val))
			if IS_CONST != IS_TMP_VAR {
				Z_ADDREF_P(val)
			}
			if Z_ISUNDEF(new_gen.GetRetval()) {
				if UNEXPECTED(ZendGeneratorGetCurrent(new_gen) == generator) {
					ZendThrowError(nil, "Impossible to yield from the Generator being currently run")
					ZvalPtrDtor(val)
					UNDEF_RESULT()
					HANDLE_EXCEPTION()
				} else {
					ZendGeneratorYieldFrom(generator, new_gen)
				}
			} else if UNEXPECTED(new_gen.GetExecuteData() == nil) {
				ZendThrowError(nil, "Generator passed to yield from was aborted without proper return and is unable to continue")
				ZvalPtrDtor(val)
				UNDEF_RESULT()
				HANDLE_EXCEPTION()
			} else {
				if RETURN_VALUE_USED(opline) {
					ZVAL_COPY(EX_VAR(opline.GetResult().GetVar()), &new_gen.retval)
				}
				ZEND_VM_NEXT_OPCODE()
			}
		} else {
			var iter *ZendObjectIterator = ce.GetGetIterator()(ce, val, 0)
			if UNEXPECTED(iter == nil) || UNEXPECTED(ExecutorGlobals.GetException() != nil) {
				if ExecutorGlobals.GetException() == nil {
					ZendThrowError(nil, "Object of type %s did not create an Iterator", ZSTR_VAL(ce.GetName()))
				}
				UNDEF_RESULT()
				HANDLE_EXCEPTION()
			}
			iter.SetIndex(0)
			if iter.GetFuncs().GetRewind() != nil {
				iter.GetFuncs().GetRewind()(iter)
				if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
					OBJ_RELEASE(&iter.std)
					UNDEF_RESULT()
					HANDLE_EXCEPTION()
				}
			}
			ZVAL_OBJ(&generator.values, &iter.std)
		}
	} else {
		ZendThrowError(nil, "Can use \"yield from\" only with arrays and Traversables")
		UNDEF_RESULT()
		HANDLE_EXCEPTION()
	}

	/* This is the default return value
	 * when the expression is a Generator, it will be overwritten in zend_generator_resume() */

	if RETURN_VALUE_USED(opline) {
		ZVAL_NULL(EX_VAR(opline.GetResult().GetVar()))
	}

	/* This generator has no send target (though the generator we delegate to might have one) */

	generator.SetSendTarget(nil)

	/* We increment to the next op, so we are at the correct position when the
	 * generator is resumed. */

	ZEND_VM_INC_OPCODE()

	/* The GOTO VM uses a local opline variable. We need to set the opline
	 * variable in execute_data so we don't resume at an old position. */

	return -1
}
func ZEND_STRLEN_SPEC_CONST_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var value *Zval
	value = RT_CONSTANT(opline, opline.GetOp1())
	if EXPECTED(Z_TYPE_P(value) == IS_STRING) {
		ZVAL_LONG(EX_VAR(opline.GetResult().GetVar()), Z_STRLEN_P(value))
		ZEND_VM_NEXT_OPCODE()
	} else {
		var strict ZendBool
		if (IS_CONST&(IS_VAR|IS_CV)) != 0 && Z_TYPE_P(value) == IS_REFERENCE {
			value = Z_REFVAL_P(value)
			if EXPECTED(Z_TYPE_P(value) == IS_STRING) {
				ZVAL_LONG(EX_VAR(opline.GetResult().GetVar()), Z_STRLEN_P(value))
				ZEND_VM_NEXT_OPCODE()
			}
		}
		if IS_CONST == IS_CV && UNEXPECTED(Z_TYPE_P(value) == IS_UNDEF) {
			value = ZVAL_UNDEFINED_OP1()
		}
		strict = EX_USES_STRICT_TYPES()
		for {
			if EXPECTED(strict == 0) {
				var str *ZendString
				var tmp Zval
				ZVAL_COPY(&tmp, value)
				if ZendParseArgStrWeak(&tmp, &str) != 0 {
					ZVAL_LONG(EX_VAR(opline.GetResult().GetVar()), ZSTR_LEN(str))
					ZvalPtrDtor(&tmp)
					break
				}
				ZvalPtrDtor(&tmp)
			}
			if ExecutorGlobals.GetException() == nil {
				ZendInternalTypeError(strict, "strlen() expects parameter 1 to be string, %s given", ZendGetTypeByConst(Z_TYPE_P(value)))
			}
			ZVAL_NULL(EX_VAR(opline.GetResult().GetVar()))
			break
		}
	}
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_TYPE_CHECK_SPEC_CONST_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var value *Zval
	var result int = 0
	value = RT_CONSTANT(opline, opline.GetOp1())
	if (opline.GetExtendedValue() >> uint32(Z_TYPE_P(value)) & 1) != 0 {
	type_check_resource:
		if EXPECTED(Z_TYPE_P(value) != IS_RESOURCE) || EXPECTED(nil != ZendRsrcListGetRsrcType(Z_RES_P(value))) {
			result = 1
		}
	} else if (IS_CONST&(IS_CV|IS_VAR)) != 0 && Z_ISREF_P(value) {
		value = Z_REFVAL_P(value)
		if (opline.GetExtendedValue() >> uint32(Z_TYPE_P(value)) & 1) != 0 {
			goto type_check_resource
		}
	} else if IS_CONST == IS_CV && UNEXPECTED(Z_TYPE_P(value) == IS_UNDEF) {
		result = (1 << IS_NULL & opline.GetExtendedValue()) != 0
		ZVAL_UNDEFINED_OP1()
		if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
			ZVAL_UNDEF(EX_VAR(opline.GetResult().GetVar()))
			HANDLE_EXCEPTION()
		}
	}
	if (IS_CONST & (IS_TMP_VAR | IS_VAR)) != 0 {
		ZEND_VM_SMART_BRANCH(result, 1)
		ZVAL_BOOL(EX_VAR(opline.GetResult().GetVar()), result)
		ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
	} else {
		ZEND_VM_SMART_BRANCH(result, 0)
		ZVAL_BOOL(EX_VAR(opline.GetResult().GetVar()), result)
		ZEND_VM_NEXT_OPCODE()
	}
}
func ZEND_DEFINED_SPEC_CONST_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var c *ZendConstant
	c = CACHED_PTR(opline.GetExtendedValue())
	if EXPECTED(c != nil) {
		if IS_SPECIAL_CACHE_VAL(c) == 0 {
		defined_true:
			ZEND_VM_SMART_BRANCH_TRUE()
			ZVAL_TRUE(EX_VAR(opline.GetResult().GetVar()))
			ZEND_VM_NEXT_OPCODE()
		} else if EXPECTED(ExecutorGlobals.GetZendConstants().NumElements() == DECODE_SPECIAL_CACHE_NUM(c)) {
		defined_false:
			ZEND_VM_SMART_BRANCH_FALSE()
			ZVAL_FALSE(EX_VAR(opline.GetResult().GetVar()))
			ZEND_VM_NEXT_OPCODE()
		}
	}
	if ZendQuickCheckConstant(RT_CONSTANT(opline, opline.GetOp1()), OPLINE_C, EXECUTE_DATA_C) != SUCCESS {
		CACHE_PTR(opline.GetExtendedValue(), ENCODE_SPECIAL_CACHE_NUM(ExecutorGlobals.GetZendConstants().NumElements()))
		goto defined_false
	} else {
		goto defined_true
	}
}
