	ZEND_VM_SMART_BRANCH(result == IS_TRUE, 1)
	Z_TYPE_INFO_P(EX_VAR(opline.GetResult().GetVar())) = result
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
