func ZEND_FETCH_DIM_R_INDEX_SPEC_CONST_TMPVARCV_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var container *Zval
	var dim *Zval
	var value *Zval
	var offset ZendLong
	var ht *HashTable
	container = RT_CONSTANT(opline, opline.GetOp1())
	dim = EX_VAR(opline.GetOp2().GetVar())
	if EXPECTED(Z_TYPE_P(container) == IS_ARRAY) {
	fetch_dim_r_index_array:
		if EXPECTED(Z_TYPE_P(dim) == IS_LONG) {
			offset = Z_LVAL_P(dim)
		} else {
			offset = ZvalGetLong(dim)
		}
		ht = Z_ARRVAL_P(container)
		ZEND_HASH_INDEX_FIND(ht, offset, value, fetch_dim_r_index_undef)
		ZVAL_COPY_DEREF(EX_VAR(opline.GetResult().GetVar()), value)
		if (IS_CONST & (IS_TMP_VAR | IS_VAR)) != 0 {
			ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
		} else {
			ZEND_VM_NEXT_OPCODE()
		}
	} else if IS_CONST != IS_CONST && EXPECTED(Z_TYPE_P(container) == IS_REFERENCE) {
		container = Z_REFVAL_P(container)
		if EXPECTED(Z_TYPE_P(container) == IS_ARRAY) {
			goto fetch_dim_r_index_array
		} else {
			goto fetch_dim_r_index_slow
		}
	} else {
	fetch_dim_r_index_slow:
		if (IS_TMP_VAR|IS_VAR|IS_CV) == IS_CONST && Z_EXTRA_P(dim) == ZEND_EXTRA_VALUE {
			dim++
		}
		zend_fetch_dimension_address_read_R_slow(container, dim, OPLINE_C, EXECUTE_DATA_C)
		ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
	}
fetch_dim_r_index_undef:
	ZVAL_NULL(EX_VAR(opline.GetResult().GetVar()))
	ZendUndefinedOffset(offset)
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
