func ZEND_FETCH_OBJ_R_SPEC_CONST_TMPVAR_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var container *Zval
	var free_op2 ZendFreeOp
	var offset *Zval
	var cache_slot *any = nil
	container = RT_CONSTANT(opline, opline.GetOp1())
	if IS_CONST == IS_UNUSED && UNEXPECTED(Z_TYPE_P(container) == IS_UNDEF) {
		return zend_this_not_in_object_context_helper_SPEC(execute_data)
	}
	offset = _getZvalPtrVar(opline.GetOp2().GetVar(), &free_op2, EXECUTE_DATA_C)
	if IS_CONST == IS_CONST || IS_CONST != IS_UNUSED && UNEXPECTED(Z_TYPE_P(container) != IS_OBJECT) {
		for {
			if (IS_CONST&(IS_VAR|IS_CV)) != 0 && Z_ISREF_P(container) {
				container = Z_REFVAL_P(container)
				if EXPECTED(Z_TYPE_P(container) == IS_OBJECT) {
					break
				}
			}
			if IS_CONST == IS_CV && UNEXPECTED(Z_TYPE_P(container) == IS_UNDEF) {
				ZVAL_UNDEFINED_OP1()
			}
			if (IS_TMP_VAR|IS_VAR) == IS_CV && UNEXPECTED(Z_TYPE_P(offset) == IS_UNDEF) {
				ZVAL_UNDEFINED_OP2()
			}
			ZendWrongPropertyRead(offset)
			ZVAL_NULL(EX_VAR(opline.GetResult().GetVar()))
			goto fetch_obj_r_finish
			break
		}
	}

	/* here we are sure we are dealing with an object */

	var zobj *ZendObject = Z_OBJ_P(container)
	var retval *Zval
	if (IS_TMP_VAR | IS_VAR) == IS_CONST {
		cache_slot = CACHE_ADDR(opline.GetExtendedValue() & ^ZEND_FETCH_REF)
		if EXPECTED(zobj.GetCe() == CACHED_PTR_EX(cache_slot)) {
			var prop_offset uintPtr = uintPtr(CACHED_PTR_EX(cache_slot + 1))
			if EXPECTED(IS_VALID_PROPERTY_OFFSET(prop_offset)) {
				retval = OBJ_PROP(zobj, prop_offset)
				if EXPECTED(Z_TYPE_INFO_P(retval) != IS_UNDEF) {
					if (IS_CONST & (IS_TMP_VAR | IS_VAR)) != 0 {
						goto fetch_obj_r_copy
					} else {
					fetch_obj_r_fast_copy:
						ZVAL_COPY_DEREF(EX_VAR(opline.GetResult().GetVar()), retval)
						ZEND_VM_NEXT_OPCODE()
					}
				}
			} else if EXPECTED(zobj.GetProperties() != nil) {
				if !(IS_UNKNOWN_DYNAMIC_PROPERTY_OFFSET(prop_offset)) {
					var idx uintPtr = ZEND_DECODE_DYN_PROP_OFFSET(prop_offset)
					if EXPECTED(idx < zobj.GetProperties().GetNNumUsed()*b.SizeOf("Bucket")) {
						var p *Bucket = (*Bucket)((*byte)(zobj.GetProperties().GetArData() + idx))
						if EXPECTED(Z_TYPE(p.GetVal()) != IS_UNDEF) && (EXPECTED(p.GetKey() == Z_STR_P(offset)) || EXPECTED(p.GetH() == ZSTR_H(Z_STR_P(offset))) && EXPECTED(p.GetKey() != nil) && EXPECTED(ZendStringEqualContent(p.GetKey(), Z_STR_P(offset)) != 0)) {
							retval = &p.val
							if (IS_CONST & (IS_TMP_VAR | IS_VAR)) != 0 {
								goto fetch_obj_r_copy
							} else {
								goto fetch_obj_r_fast_copy
							}
						}
					}
					CACHE_PTR_EX(cache_slot+1, any(ZEND_DYNAMIC_PROPERTY_OFFSET))
				}
				retval = zobj.GetProperties().FindEx(Z_STR_P(offset), 1)
				if EXPECTED(retval != nil) {
					var idx uintPtr = (*byte)(retval - (*byte)(zobj.GetProperties().GetArData()))
					CACHE_PTR_EX(cache_slot+1, any(ZEND_ENCODE_DYN_PROP_OFFSET(idx)))
					if (IS_CONST & (IS_TMP_VAR | IS_VAR)) != 0 {
						goto fetch_obj_r_copy
					} else {
						goto fetch_obj_r_fast_copy
					}
				}
			}
		}
	} else if (IS_TMP_VAR|IS_VAR) == IS_CV && UNEXPECTED(Z_TYPE_INFO_P(offset) == IS_UNDEF) {
		ZVAL_UNDEFINED_OP2()
	}
	retval = zobj.GetHandlers().GetReadProperty()(container, offset, BP_VAR_R, cache_slot, EX_VAR(opline.GetResult().GetVar()))
	if retval != EX_VAR(opline.GetResult().GetVar()) {
	fetch_obj_r_copy:
		ZVAL_COPY_DEREF(EX_VAR(opline.GetResult().GetVar()), retval)
	} else if UNEXPECTED(Z_ISREF_P(retval)) {
		ZendUnwrapReference(retval)
	}
fetch_obj_r_finish:
	ZvalPtrDtorNogc(free_op2)
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
