func ZEND_FAST_CONCAT_SPEC_CONST_TMPVAR_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var free_op2 ZendFreeOp
	var op1 *Zval
	var op2 *Zval
	var op1_str *ZendString
	var op2_str *ZendString
	var str *ZendString
	op1 = RT_CONSTANT(opline, opline.GetOp1())
	op2 = _getZvalPtrVar(opline.GetOp2().GetVar(), &free_op2, EXECUTE_DATA_C)
	if (IS_CONST == IS_CONST || EXPECTED(Z_TYPE_P(op1) == IS_STRING)) && ((IS_TMP_VAR|IS_VAR) == IS_CONST || EXPECTED(Z_TYPE_P(op2) == IS_STRING)) {
		var op1_str *ZendString = Z_STR_P(op1)
		var op2_str *ZendString = Z_STR_P(op2)
		var str *ZendString
		if IS_CONST != IS_CONST && UNEXPECTED(ZSTR_LEN(op1_str) == 0) {
			if (IS_TMP_VAR|IS_VAR) == IS_CONST || (IS_TMP_VAR|IS_VAR) == IS_CV {
				ZVAL_STR_COPY(EX_VAR(opline.GetResult().GetVar()), op2_str)
			} else {
				ZVAL_STR(EX_VAR(opline.GetResult().GetVar()), op2_str)
			}
			if (IS_CONST & (IS_TMP_VAR | IS_VAR)) != 0 {
				ZendStringReleaseEx(op1_str, 0)
			}
		} else if (IS_TMP_VAR|IS_VAR) != IS_CONST && UNEXPECTED(ZSTR_LEN(op2_str) == 0) {
			if IS_CONST == IS_CONST || IS_CONST == IS_CV {
				ZVAL_STR_COPY(EX_VAR(opline.GetResult().GetVar()), op1_str)
			} else {
				ZVAL_STR(EX_VAR(opline.GetResult().GetVar()), op1_str)
			}
			if ((IS_TMP_VAR | IS_VAR) & (IS_TMP_VAR | IS_VAR)) != 0 {
				ZendStringReleaseEx(op2_str, 0)
			}
		} else if IS_CONST != IS_CONST && IS_CONST != IS_CV && ZSTR_IS_INTERNED(op1_str) == 0 && GC_REFCOUNT(op1_str) == 1 {
			var len_ int = ZSTR_LEN(op1_str)
			if UNEXPECTED(len_ > ZSTR_MAX_LEN-ZSTR_LEN(op2_str)) {
				ZendErrorNoreturn(E_ERROR, "Integer overflow in memory allocation")
			}
			str = ZendStringExtend(op1_str, len_+ZSTR_LEN(op2_str), 0)
			memcpy(ZSTR_VAL(str)+len_, ZSTR_VAL(op2_str), ZSTR_LEN(op2_str)+1)
			ZVAL_NEW_STR(EX_VAR(opline.GetResult().GetVar()), str)
			if ((IS_TMP_VAR | IS_VAR) & (IS_TMP_VAR | IS_VAR)) != 0 {
				ZendStringReleaseEx(op2_str, 0)
			}
		} else {
			str = ZendStringAlloc(ZSTR_LEN(op1_str)+ZSTR_LEN(op2_str), 0)
			memcpy(ZSTR_VAL(str), ZSTR_VAL(op1_str), ZSTR_LEN(op1_str))
			memcpy(ZSTR_VAL(str)+ZSTR_LEN(op1_str), ZSTR_VAL(op2_str), ZSTR_LEN(op2_str)+1)
			ZVAL_NEW_STR(EX_VAR(opline.GetResult().GetVar()), str)
			if (IS_CONST & (IS_TMP_VAR | IS_VAR)) != 0 {
				ZendStringReleaseEx(op1_str, 0)
			}
			if ((IS_TMP_VAR | IS_VAR) & (IS_TMP_VAR | IS_VAR)) != 0 {
				ZendStringReleaseEx(op2_str, 0)
			}
		}
		ZEND_VM_NEXT_OPCODE()
	}
	if IS_CONST == IS_CONST {
		op1_str = Z_STR_P(op1)
	} else if EXPECTED(Z_TYPE_P(op1) == IS_STRING) {
		op1_str = ZendStringCopy(Z_STR_P(op1))
	} else {
		if IS_CONST == IS_CV && UNEXPECTED(Z_TYPE_P(op1) == IS_UNDEF) {
			ZVAL_UNDEFINED_OP1()
		}
		op1_str = ZvalGetStringFunc(op1)
	}
	if (IS_TMP_VAR | IS_VAR) == IS_CONST {
		op2_str = Z_STR_P(op2)
	} else if EXPECTED(Z_TYPE_P(op2) == IS_STRING) {
		op2_str = ZendStringCopy(Z_STR_P(op2))
	} else {
		if (IS_TMP_VAR|IS_VAR) == IS_CV && UNEXPECTED(Z_TYPE_P(op2) == IS_UNDEF) {
			ZVAL_UNDEFINED_OP2()
		}
		op2_str = ZvalGetStringFunc(op2)
	}
	for {
		if IS_CONST != IS_CONST {
			if UNEXPECTED(ZSTR_LEN(op1_str) == 0) {
				if (IS_TMP_VAR | IS_VAR) == IS_CONST {
					if UNEXPECTED(Z_REFCOUNTED_P(op2)) {
						GC_ADDREF(op2_str)
					}
				}
				ZVAL_STR(EX_VAR(opline.GetResult().GetVar()), op2_str)
				ZendStringReleaseEx(op1_str, 0)
				break
			}
		}
		if (IS_TMP_VAR | IS_VAR) != IS_CONST {
			if UNEXPECTED(ZSTR_LEN(op2_str) == 0) {
				if IS_CONST == IS_CONST {
					if UNEXPECTED(Z_REFCOUNTED_P(op1)) {
						GC_ADDREF(op1_str)
					}
				}
				ZVAL_STR(EX_VAR(opline.GetResult().GetVar()), op1_str)
				ZendStringReleaseEx(op2_str, 0)
				break
			}
		}
		str = ZendStringAlloc(ZSTR_LEN(op1_str)+ZSTR_LEN(op2_str), 0)
		memcpy(ZSTR_VAL(str), ZSTR_VAL(op1_str), ZSTR_LEN(op1_str))
		memcpy(ZSTR_VAL(str)+ZSTR_LEN(op1_str), ZSTR_VAL(op2_str), ZSTR_LEN(op2_str)+1)
		ZVAL_NEW_STR(EX_VAR(opline.GetResult().GetVar()), str)
		if IS_CONST != IS_CONST {
			ZendStringReleaseEx(op1_str, 0)
		}
		if (IS_TMP_VAR | IS_VAR) != IS_CONST {
			ZendStringReleaseEx(op2_str, 0)
		}
		break
	}
	ZvalPtrDtorNogc(free_op2)
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_INIT_METHOD_CALL_SPEC_CONST_TMPVAR_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var function_name *Zval
	var free_op1 ZendFreeOp
	var free_op2 ZendFreeOp
	var object *Zval
	var fbc *ZendFunction
	var called_scope *ZendClassEntry
	var obj *ZendObject
	var call *ZendExecuteData
	var call_info uint32
	object = RT_CONSTANT(opline, opline.GetOp1())
	if IS_CONST == IS_UNUSED && UNEXPECTED(Z_TYPE_P(object) == IS_UNDEF) {
		return zend_this_not_in_object_context_helper_SPEC(execute_data)
	}
	if (IS_TMP_VAR | IS_VAR) != IS_CONST {
		function_name = _getZvalPtrVar(opline.GetOp2().GetVar(), &free_op2, EXECUTE_DATA_C)
	}
	if (IS_TMP_VAR|IS_VAR) != IS_CONST && UNEXPECTED(Z_TYPE_P(function_name) != IS_STRING) {
		for {
			if ((IS_TMP_VAR|IS_VAR)&(IS_VAR|IS_CV)) != 0 && Z_ISREF_P(function_name) {
				function_name = Z_REFVAL_P(function_name)
				if EXPECTED(Z_TYPE_P(function_name) == IS_STRING) {
					break
				}
			} else if (IS_TMP_VAR|IS_VAR) == IS_CV && UNEXPECTED(Z_TYPE_P(function_name) == IS_UNDEF) {
				ZVAL_UNDEFINED_OP2()
				if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
					HANDLE_EXCEPTION()
				}
			}
			ZendThrowError(nil, "Method name must be a string")
			ZvalPtrDtorNogc(free_op2)
			HANDLE_EXCEPTION()
			break
		}
	}
	if IS_CONST != IS_UNUSED {
		for {
			if IS_CONST == IS_CONST || UNEXPECTED(Z_TYPE_P(object) != IS_OBJECT) {
				if (IS_CONST&(IS_VAR|IS_CV)) != 0 && EXPECTED(Z_ISREF_P(object)) {
					object = Z_REFVAL_P(object)
					if EXPECTED(Z_TYPE_P(object) == IS_OBJECT) {
						break
					}
				}
				if IS_CONST == IS_CV && UNEXPECTED(Z_TYPE_P(object) == IS_UNDEF) {
					object = ZVAL_UNDEFINED_OP1()
					if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
						if (IS_TMP_VAR | IS_VAR) != IS_CONST {
							ZvalPtrDtorNogc(free_op2)
						}
						HANDLE_EXCEPTION()
					}
				}
				if (IS_TMP_VAR | IS_VAR) == IS_CONST {
					function_name = _getZvalPtrVar(opline.GetOp2().GetVar(), &free_op2, EXECUTE_DATA_C)
				}
				ZendInvalidMethodCall(object, function_name)
				ZvalPtrDtorNogc(free_op2)
				HANDLE_EXCEPTION()
			}
			break
		}
	}
	obj = Z_OBJ_P(object)
	called_scope = obj.GetCe()
	if (IS_TMP_VAR|IS_VAR) == IS_CONST && EXPECTED(CACHED_PTR(opline.GetResult().GetNum()) == called_scope) {
		fbc = CACHED_PTR(opline.GetResult().GetNum() + b.SizeOf("void *"))
	} else {
		var orig_obj *ZendObject = obj
		if (IS_TMP_VAR | IS_VAR) == IS_CONST {
			function_name = _getZvalPtrVar(opline.GetOp2().GetVar(), &free_op2, EXECUTE_DATA_C)
		}

		/* First, locate the function. */

		fbc = obj.GetHandlers().GetGetMethod()(&obj, Z_STR_P(function_name), b.CondF1((IS_TMP_VAR|IS_VAR) == IS_CONST, func() *Zval { return RT_CONSTANT(opline, opline.GetOp2()) + 1 }, nil))
		if UNEXPECTED(fbc == nil) {
			if EXPECTED(ExecutorGlobals.GetException() == nil) {
				ZendUndefinedMethod(obj.GetCe(), Z_STR_P(function_name))
			}
			ZvalPtrDtorNogc(free_op2)
			HANDLE_EXCEPTION()
		}
		if (IS_TMP_VAR|IS_VAR) == IS_CONST && EXPECTED(fbc.GetType() <= ZEND_USER_FUNCTION) && EXPECTED(!fbc.HasFnFlags(ZEND_ACC_CALL_VIA_TRAMPOLINE|ZEND_ACC_NEVER_CACHE)) && EXPECTED(obj == orig_obj) {
			CACHE_POLYMORPHIC_PTR(opline.GetResult().GetNum(), called_scope, fbc)
		}
		if (IS_CONST&(IS_VAR|IS_TMP_VAR)) != 0 && UNEXPECTED(obj != orig_obj) {

			/* Reset "object" to trigger reference counting */

			object = nil

			/* Reset "object" to trigger reference counting */

		}
		if EXPECTED(fbc.GetType() == ZEND_USER_FUNCTION) && UNEXPECTED(!(RUN_TIME_CACHE(&fbc.op_array))) {
			InitFuncRunTimeCache(&fbc.op_array)
		}
	}
	if (IS_TMP_VAR | IS_VAR) != IS_CONST {
		ZvalPtrDtorNogc(free_op2)
	}
	call_info = ZEND_CALL_NESTED_FUNCTION | ZEND_CALL_HAS_THIS
	if UNEXPECTED(fbc.IsStatic()) {
		if (IS_CONST&(IS_VAR|IS_TMP_VAR)) != 0 && UNEXPECTED(ExecutorGlobals.GetException() != nil) {
			HANDLE_EXCEPTION()
		}

		/* call static method */

		obj = (*ZendObject)(called_scope)
		call_info = ZEND_CALL_NESTED_FUNCTION
	} else if (IS_CONST & (IS_VAR | IS_TMP_VAR | IS_CV)) != 0 {
		if IS_CONST == IS_CV {
			GC_ADDREF(obj)
		} else if free_op1 != object {
			GC_ADDREF(obj)
		}

		/* CV may be changed indirectly (e.g. when it's a reference) */

		call_info = ZEND_CALL_NESTED_FUNCTION | ZEND_CALL_HAS_THIS | ZEND_CALL_RELEASE_THIS

		/* CV may be changed indirectly (e.g. when it's a reference) */

	}
	call = ZendVmStackPushCallFrame(call_info, fbc, opline.GetExtendedValue(), obj)
	call.SetPrevExecuteData(EX(call))
	EX(call) = call
	ZEND_VM_NEXT_OPCODE()
}
func ZEND_INIT_STATIC_METHOD_CALL_SPEC_CONST_TMPVAR_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var function_name *Zval
	var ce *ZendClassEntry
	var call_info uint32
	var fbc *ZendFunction
	var call *ZendExecuteData
	if IS_CONST == IS_CONST {

		/* no function found. try a static method in class */

		ce = CACHED_PTR(opline.GetResult().GetNum())
		if UNEXPECTED(ce == nil) {
			ce = ZendFetchClassByName(Z_STR_P(RT_CONSTANT(opline, opline.GetOp1())), Z_STR_P(RT_CONSTANT(opline, opline.GetOp1())+1), ZEND_FETCH_CLASS_DEFAULT|ZEND_FETCH_CLASS_EXCEPTION)
			if UNEXPECTED(ce == nil) {
				ZEND_ASSERT(ExecutorGlobals.GetException() != nil)
				ZvalPtrDtorNogc(EX_VAR(opline.GetOp2().GetVar()))
				HANDLE_EXCEPTION()
			}
			if (IS_TMP_VAR | IS_VAR) != IS_CONST {
				CACHE_PTR(opline.GetResult().GetNum(), ce)
			}
		}
	} else if IS_CONST == IS_UNUSED {
		ce = ZendFetchClass(nil, opline.GetOp1().GetNum())
		if UNEXPECTED(ce == nil) {
			ZEND_ASSERT(ExecutorGlobals.GetException() != nil)
			ZvalPtrDtorNogc(EX_VAR(opline.GetOp2().GetVar()))
			HANDLE_EXCEPTION()
		}
	} else {
		ce = Z_CE_P(EX_VAR(opline.GetOp1().GetVar()))
	}
	if IS_CONST == IS_CONST && (IS_TMP_VAR|IS_VAR) == IS_CONST && EXPECTED(b.Assign(&fbc, CACHED_PTR(opline.GetResult().GetNum()+b.SizeOf("void *"))) != nil) {

	} else if IS_CONST != IS_CONST && (IS_TMP_VAR|IS_VAR) == IS_CONST && EXPECTED(CACHED_PTR(opline.GetResult().GetNum()) == ce) {
		fbc = CACHED_PTR(opline.GetResult().GetNum() + b.SizeOf("void *"))
	} else if (IS_TMP_VAR | IS_VAR) != IS_UNUSED {
		var free_op2 ZendFreeOp
		function_name = _getZvalPtrVar(opline.GetOp2().GetVar(), &free_op2, EXECUTE_DATA_C)
		if (IS_TMP_VAR | IS_VAR) != IS_CONST {
			if UNEXPECTED(Z_TYPE_P(function_name) != IS_STRING) {
				for {
					if ((IS_TMP_VAR|IS_VAR)&(IS_VAR|IS_CV)) != 0 && Z_ISREF_P(function_name) {
						function_name = Z_REFVAL_P(function_name)
						if EXPECTED(Z_TYPE_P(function_name) == IS_STRING) {
							break
						}
					} else if (IS_TMP_VAR|IS_VAR) == IS_CV && UNEXPECTED(Z_TYPE_P(function_name) == IS_UNDEF) {
						ZVAL_UNDEFINED_OP2()
						if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
							HANDLE_EXCEPTION()
						}
					}
					ZendThrowError(nil, "Function name must be a string")
					ZvalPtrDtorNogc(free_op2)
					HANDLE_EXCEPTION()
					break
				}
			}
		}
		if ce.GetGetStaticMethod() != nil {
			fbc = ce.GetGetStaticMethod()(ce, Z_STR_P(function_name))
		} else {
			fbc = ZendStdGetStaticMethod(ce, Z_STR_P(function_name), b.CondF1((IS_TMP_VAR|IS_VAR) == IS_CONST, func() *Zval { return RT_CONSTANT(opline, opline.GetOp2()) + 1 }, nil))
		}
		if UNEXPECTED(fbc == nil) {
			if EXPECTED(ExecutorGlobals.GetException() == nil) {
				ZendUndefinedMethod(ce, Z_STR_P(function_name))
			}
			ZvalPtrDtorNogc(free_op2)
			HANDLE_EXCEPTION()
		}
		if (IS_TMP_VAR|IS_VAR) == IS_CONST && EXPECTED(fbc.GetType() <= ZEND_USER_FUNCTION) && EXPECTED(!fbc.HasFnFlags(ZEND_ACC_CALL_VIA_TRAMPOLINE|ZEND_ACC_NEVER_CACHE)) {
			CACHE_POLYMORPHIC_PTR(opline.GetResult().GetNum(), ce, fbc)
		}
		if EXPECTED(fbc.GetType() == ZEND_USER_FUNCTION) && UNEXPECTED(!(RUN_TIME_CACHE(&fbc.op_array))) {
			InitFuncRunTimeCache(&fbc.op_array)
		}
		if (IS_TMP_VAR | IS_VAR) != IS_CONST {
			ZvalPtrDtorNogc(free_op2)
		}
	} else {
		if UNEXPECTED(ce.GetConstructor() == nil) {
			ZendThrowError(nil, "Cannot call constructor")
			HANDLE_EXCEPTION()
		}
		if Z_TYPE(EX(This)) == IS_OBJECT && Z_OBJ(EX(This)).GetCe() != ce.GetConstructor().GetScope() && ce.GetConstructor().IsPrivate() {
			ZendThrowError(nil, "Cannot call private %s::__construct()", ZSTR_VAL(ce.GetName()))
			HANDLE_EXCEPTION()
		}
		fbc = ce.GetConstructor()
		if EXPECTED(fbc.GetType() == ZEND_USER_FUNCTION) && UNEXPECTED(!(RUN_TIME_CACHE(&fbc.op_array))) {
			InitFuncRunTimeCache(&fbc.op_array)
		}
	}
	if !fbc.IsStatic() {
		if Z_TYPE(EX(This)) == IS_OBJECT && InstanceofFunction(Z_OBJCE(EX(This)), ce) != 0 {
			ce = (*ZendClassEntry)(Z_OBJ(EX(This)))
			call_info = ZEND_CALL_NESTED_FUNCTION | ZEND_CALL_HAS_THIS
		} else {
			ZendNonStaticMethodCall(fbc)
			if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
				HANDLE_EXCEPTION()
			}
			goto check_parent_and_self
		}
	} else {
	check_parent_and_self:

		/* previous opcode is ZEND_FETCH_CLASS */

		if IS_CONST == IS_UNUSED && ((opline.GetOp1().GetNum()&ZEND_FETCH_CLASS_MASK) == ZEND_FETCH_CLASS_PARENT || (opline.GetOp1().GetNum()&ZEND_FETCH_CLASS_MASK) == ZEND_FETCH_CLASS_SELF) {
			if Z_TYPE(EX(This)) == IS_OBJECT {
				ce = Z_OBJCE(EX(This))
			} else {
				ce = Z_CE(EX(This))
			}
		}
		call_info = ZEND_CALL_NESTED_FUNCTION
	}
	call = ZendVmStackPushCallFrame(call_info, fbc, opline.GetExtendedValue(), ce)
	call.SetPrevExecuteData(EX(call))
	EX(call) = call
	ZEND_VM_NEXT_OPCODE()
}
func ZEND_INIT_USER_CALL_SPEC_CONST_TMPVAR_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var free_op2 ZendFreeOp
	var function_name *Zval
	var fcc ZendFcallInfoCache
	var error *byte = nil
	var func_ *ZendFunction
	var object_or_called_scope any
	var call *ZendExecuteData
	var call_info uint32 = ZEND_CALL_NESTED_FUNCTION | ZEND_CALL_DYNAMIC
	function_name = _getZvalPtrVar(opline.GetOp2().GetVar(), &free_op2, EXECUTE_DATA_C)
	if ZendIsCallableEx(function_name, nil, 0, nil, &fcc, &error) != 0 {
		func_ = fcc.GetFunctionHandler()
		if error != nil {
			Efree(error)

			/* This is the only soft error is_callable() can generate */

			ZendNonStaticMethodCall(func_)
			if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
				ZvalPtrDtorNogc(free_op2)
				HANDLE_EXCEPTION()
			}
		}
		object_or_called_scope = fcc.GetCalledScope()
		if func_.IsClosure() {

			/* Delay closure destruction until its invocation */

			GC_ADDREF(ZEND_CLOSURE_OBJECT(func_))
			call_info |= ZEND_CALL_CLOSURE
			if func_.IsFakeClosure() {
				call_info |= ZEND_CALL_FAKE_CLOSURE
			}
			if fcc.GetObject() != nil {
				object_or_called_scope = fcc.GetObject()
				call_info |= ZEND_CALL_HAS_THIS
			}
		} else if fcc.GetObject() != nil {
			GC_ADDREF(fcc.GetObject())
			object_or_called_scope = fcc.GetObject()
			call_info |= ZEND_CALL_RELEASE_THIS | ZEND_CALL_HAS_THIS
		}
		ZvalPtrDtorNogc(free_op2)
		if ((IS_TMP_VAR|IS_VAR)&(IS_TMP_VAR|IS_VAR)) != 0 && UNEXPECTED(ExecutorGlobals.GetException() != nil) {
			if (call_info & ZEND_CALL_CLOSURE) != 0 {
				ZendObjectRelease(ZEND_CLOSURE_OBJECT(func_))
			} else if (call_info & ZEND_CALL_RELEASE_THIS) != 0 {
				ZendObjectRelease(fcc.GetObject())
			}
			HANDLE_EXCEPTION()
		}
		if EXPECTED(func_.GetType() == ZEND_USER_FUNCTION) && UNEXPECTED(!(RUN_TIME_CACHE(&func_.op_array))) {
			InitFuncRunTimeCache(&func_.op_array)
		}
	} else {
		ZendInternalTypeError(EX_USES_STRICT_TYPES(), "%s() expects parameter 1 to be a valid callback, %s", Z_STRVAL_P(RT_CONSTANT(opline, opline.GetOp1())), error)
		Efree(error)
		ZvalPtrDtorNogc(free_op2)
		if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
			HANDLE_EXCEPTION()
		}
		func_ = (*ZendFunction)(&ZendPassFunction)
		object_or_called_scope = nil
	}
	call = ZendVmStackPushCallFrame(call_info, func_, opline.GetExtendedValue(), object_or_called_scope)
	call.SetPrevExecuteData(EX(call))
	EX(call) = call
	ZEND_VM_NEXT_OPCODE()
}
