func ZEND_INIT_USER_CALL_SPEC_CONST_CV_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var function_name *Zval
	var fcc ZendFcallInfoCache
	var error *byte = nil
	var func_ *ZendFunction
	var object_or_called_scope any
	var call *ZendExecuteData
	var call_info uint32 = ZEND_CALL_NESTED_FUNCTION | ZEND_CALL_DYNAMIC
	function_name = _get_zval_ptr_cv_BP_VAR_R(opline.GetOp2().GetVar(), EXECUTE_DATA_C)
	if ZendIsCallableEx(function_name, nil, 0, nil, &fcc, &error) != 0 {
		func_ = fcc.GetFunctionHandler()
		if error != nil {
			Efree(error)

			/* This is the only soft error is_callable() can generate */

			ZendNonStaticMethodCall(func_)
			if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
				HANDLE_EXCEPTION()
			}
		}
		object_or_called_scope = fcc.GetCalledScope()
		if func_.IsClosure() {

			/* Delay closure destruction until its invocation */

			GC_ADDREF(ZEND_CLOSURE_OBJECT(func_))
			call_info |= ZEND_CALL_CLOSURE
			if func_.IsFakeClosure() {
				call_info |= ZEND_CALL_FAKE_CLOSURE
			}
			if fcc.GetObject() != nil {
				object_or_called_scope = fcc.GetObject()
				call_info |= ZEND_CALL_HAS_THIS
			}
		} else if fcc.GetObject() != nil {
			GC_ADDREF(fcc.GetObject())
			object_or_called_scope = fcc.GetObject()
			call_info |= ZEND_CALL_RELEASE_THIS | ZEND_CALL_HAS_THIS
		}
		if (IS_CV&(IS_TMP_VAR|IS_VAR)) != 0 && UNEXPECTED(ExecutorGlobals.GetException() != nil) {
			if (call_info & ZEND_CALL_CLOSURE) != 0 {
				ZendObjectRelease(ZEND_CLOSURE_OBJECT(func_))
			} else if (call_info & ZEND_CALL_RELEASE_THIS) != 0 {
				ZendObjectRelease(fcc.GetObject())
			}
			HANDLE_EXCEPTION()
		}
		if EXPECTED(func_.GetType() == ZEND_USER_FUNCTION) && UNEXPECTED(!(RUN_TIME_CACHE(&func_.op_array))) {
			InitFuncRunTimeCache(&func_.op_array)
		}
	} else {
		ZendInternalTypeError(EX_USES_STRICT_TYPES(), "%s() expects parameter 1 to be a valid callback, %s", Z_STRVAL_P(RT_CONSTANT(opline, opline.GetOp1())), error)
		Efree(error)
		if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
			HANDLE_EXCEPTION()
		}
		func_ = (*ZendFunction)(&ZendPassFunction)
		object_or_called_scope = nil
	}
	call = ZendVmStackPushCallFrame(call_info, func_, opline.GetExtendedValue(), object_or_called_scope)
	call.SetPrevExecuteData(EX(call))
	EX(call) = call
	ZEND_VM_NEXT_OPCODE()
}
