func ZEND_ROPE_ADD_SPEC_TMP_CV_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var rope **ZendString
	var var_ *Zval

	/* op1 and result are the same */

	rope = (**ZendString)(EX_VAR(opline.GetOp1().GetVar()))
	if IS_CV == IS_CONST {
		var_ = _get_zval_ptr_cv_BP_VAR_R(opline.GetOp2().GetVar(), EXECUTE_DATA_C)
		rope[opline.GetExtendedValue()] = Z_STR_P(var_)
		if UNEXPECTED(Z_REFCOUNTED_P(var_)) {
			Z_ADDREF_P(var_)
		}
	} else {
		var_ = EX_VAR(opline.GetOp2().GetVar())
		if EXPECTED(Z_TYPE_P(var_) == IS_STRING) {
			if IS_CV == IS_CV {
				rope[opline.GetExtendedValue()] = ZendStringCopy(Z_STR_P(var_))
			} else {
				rope[opline.GetExtendedValue()] = Z_STR_P(var_)
			}
		} else {
			if IS_CV == IS_CV && UNEXPECTED(Z_TYPE_P(var_) == IS_UNDEF) {
				ZVAL_UNDEFINED_OP2()
			}
			rope[opline.GetExtendedValue()] = ZvalGetStringFunc(var_)
			ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
		}
	}
	ZEND_VM_NEXT_OPCODE()
}
func ZEND_ROPE_END_SPEC_TMP_CV_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var rope **ZendString
	var var_ *Zval
	var ret *Zval
	var i uint32
	var len_ int = 0
	var target *byte
	rope = (**ZendString)(EX_VAR(opline.GetOp1().GetVar()))
	if IS_CV == IS_CONST {
		var_ = _get_zval_ptr_cv_BP_VAR_R(opline.GetOp2().GetVar(), EXECUTE_DATA_C)
		rope[opline.GetExtendedValue()] = Z_STR_P(var_)
		if UNEXPECTED(Z_REFCOUNTED_P(var_)) {
			Z_ADDREF_P(var_)
		}
	} else {
		var_ = EX_VAR(opline.GetOp2().GetVar())
		if EXPECTED(Z_TYPE_P(var_) == IS_STRING) {
			if IS_CV == IS_CV {
				rope[opline.GetExtendedValue()] = ZendStringCopy(Z_STR_P(var_))
			} else {
				rope[opline.GetExtendedValue()] = Z_STR_P(var_)
			}
		} else {
			if IS_CV == IS_CV && UNEXPECTED(Z_TYPE_P(var_) == IS_UNDEF) {
				ZVAL_UNDEFINED_OP2()
			}
			rope[opline.GetExtendedValue()] = ZvalGetStringFunc(var_)
			if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
				for i = 0; i <= opline.GetExtendedValue(); i++ {
					ZendStringReleaseEx(rope[i], 0)
				}
				ZVAL_UNDEF(EX_VAR(opline.GetResult().GetVar()))
				HANDLE_EXCEPTION()
			}
		}
	}
	for i = 0; i <= opline.GetExtendedValue(); i++ {
		len_ += ZSTR_LEN(rope[i])
	}
	ret = EX_VAR(opline.GetResult().GetVar())
	ZVAL_STR(ret, ZendStringAlloc(len_, 0))
	target = Z_STRVAL_P(ret)
	for i = 0; i <= opline.GetExtendedValue(); i++ {
		memcpy(target, ZSTR_VAL(rope[i]), ZSTR_LEN(rope[i]))
		target += ZSTR_LEN(rope[i])
		ZendStringReleaseEx(rope[i], 0)
	}
	*target = '0'
	ZEND_VM_NEXT_OPCODE()
}
func ZEND_ADD_ARRAY_ELEMENT_SPEC_TMP_CV_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var free_op1 ZendFreeOp
	var expr_ptr *Zval
	var new_expr Zval
	if (IS_TMP_VAR == IS_VAR || IS_TMP_VAR == IS_CV) && UNEXPECTED((opline.GetExtendedValue()&ZEND_ARRAY_ELEMENT_REF) != 0) {
		expr_ptr = nil
		if Z_ISREF_P(expr_ptr) {
			Z_ADDREF_P(expr_ptr)
		} else {
			ZVAL_MAKE_REF_EX(expr_ptr, 2)
		}
	} else {
		expr_ptr = _getZvalPtrTmp(opline.GetOp1().GetVar(), &free_op1, EXECUTE_DATA_C)
		if IS_TMP_VAR == IS_TMP_VAR {

		} else if IS_TMP_VAR == IS_CONST {
			Z_TRY_ADDREF_P(expr_ptr)
		} else if IS_TMP_VAR == IS_CV {
			ZVAL_DEREF(expr_ptr)
			Z_TRY_ADDREF_P(expr_ptr)
		} else {
			if UNEXPECTED(Z_ISREF_P(expr_ptr)) {
				var ref *ZendRefcounted = Z_COUNTED_P(expr_ptr)
				expr_ptr = Z_REFVAL_P(expr_ptr)
				if UNEXPECTED(GC_DELREF(ref) == 0) {
					ZVAL_COPY_VALUE(&new_expr, expr_ptr)
					expr_ptr = &new_expr
					EfreeSize(ref, b.SizeOf("zend_reference"))
				} else if Z_OPT_REFCOUNTED_P(expr_ptr) {
					Z_ADDREF_P(expr_ptr)
				}
			}
		}
	}
	if IS_CV != IS_UNUSED {
		var offset *Zval = EX_VAR(opline.GetOp2().GetVar())
		var str *ZendString
		var hval ZendUlong
	add_again:
		if EXPECTED(Z_TYPE_P(offset) == IS_STRING) {
			str = Z_STR_P(offset)
			if IS_CV != IS_CONST {
				if ZEND_HANDLE_NUMERIC(str, hval) != 0 {
					goto num_index
				}
			}
		str_index:
			Z_ARRVAL_P(EX_VAR(opline.GetResult().GetVar())).Update(str, expr_ptr)
		} else if EXPECTED(Z_TYPE_P(offset) == IS_LONG) {
			hval = Z_LVAL_P(offset)
		num_index:
			Z_ARRVAL_P(EX_VAR(opline.GetResult().GetVar())).IndexUpdate(hval, expr_ptr)
		} else if (IS_CV&(IS_VAR|IS_CV)) != 0 && EXPECTED(Z_TYPE_P(offset) == IS_REFERENCE) {
			offset = Z_REFVAL_P(offset)
			goto add_again
		} else if Z_TYPE_P(offset) == IS_NULL {
			str = ZSTR_EMPTY_ALLOC()
			goto str_index
		} else if Z_TYPE_P(offset) == IS_DOUBLE {
			hval = ZendDvalToLval(Z_DVAL_P(offset))
			goto num_index
		} else if Z_TYPE_P(offset) == IS_FALSE {
			hval = 0
			goto num_index
		} else if Z_TYPE_P(offset) == IS_TRUE {
			hval = 1
			goto num_index
		} else if Z_TYPE_P(offset) == IS_RESOURCE {
			ZendUseResourceAsOffset(offset)
			hval = Z_RES_HANDLE_P(offset)
			goto num_index
		} else if IS_CV == IS_CV && Z_TYPE_P(offset) == IS_UNDEF {
			ZVAL_UNDEFINED_OP2()
			str = ZSTR_EMPTY_ALLOC()
			goto str_index
		} else {
			ZendIllegalOffset()
			ZvalPtrDtorNogc(expr_ptr)
		}
	} else {
		if Z_ARRVAL_P(EX_VAR(opline.GetResult().GetVar())).NextIndexInsert(expr_ptr) == nil {
			ZendCannotAddElement()
			ZvalPtrDtorNogc(expr_ptr)
		}
	}
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
