func ZEND_CAST_SPEC_VAR_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var free_op1 ZendFreeOp
	var expr *Zval
	var result *Zval = EX_VAR(opline.GetResult().GetVar())
	var ht *HashTable
	expr = _getZvalPtrVar(opline.GetOp1().GetVar(), &free_op1, EXECUTE_DATA_C)
	switch opline.GetExtendedValue() {
	case IS_NULL:
		ZVAL_NULL(result)
		break
	case _IS_BOOL:
		ZVAL_BOOL(result, ZendIsTrue(expr))
		break
	case IS_LONG:
		ZVAL_LONG(result, ZvalGetLong(expr))
		break
	case IS_DOUBLE:
		ZVAL_DOUBLE(result, ZvalGetDouble(expr))
		break
	case IS_STRING:
		ZVAL_STR(result, ZvalGetString(expr))
		break
	default:
		if (IS_VAR & (IS_VAR | IS_CV)) != 0 {
			ZVAL_DEREF(expr)
		}

		/* If value is already of correct type, return it directly */

		if Z_TYPE_P(expr) == opline.GetExtendedValue() {
			ZVAL_COPY_VALUE(result, expr)
			if IS_VAR == IS_CONST {
				if UNEXPECTED(Z_OPT_REFCOUNTED_P(result)) {
					Z_ADDREF_P(result)
				}
			} else if IS_VAR != IS_TMP_VAR {
				if Z_OPT_REFCOUNTED_P(result) {
					Z_ADDREF_P(result)
				}
			}
			ZvalPtrDtorNogc(free_op1)
			ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
		}
		if opline.GetExtendedValue() == IS_ARRAY {
			if IS_VAR == IS_CONST || Z_TYPE_P(expr) != IS_OBJECT || Z_OBJCE_P(expr) == ZendCeClosure {
				if Z_TYPE_P(expr) != IS_NULL {
					ZVAL_ARR(result, ZendNewArray(1))
					expr = Z_ARRVAL_P(result).IndexAddNew(0, expr)
					if IS_VAR == IS_CONST {
						if UNEXPECTED(Z_OPT_REFCOUNTED_P(expr)) {
							Z_ADDREF_P(expr)
						}
					} else {
						if Z_OPT_REFCOUNTED_P(expr) {
							Z_ADDREF_P(expr)
						}
					}
				} else {
					ZVAL_EMPTY_ARRAY(result)
				}
			} else {
				var obj_ht *HashTable = ZendGetPropertiesFor(expr, ZEND_PROP_PURPOSE_ARRAY_CAST)
				if obj_ht != nil {

					/* fast copy */

					ZVAL_ARR(result, ZendProptableToSymtable(obj_ht, Z_OBJCE_P(expr).GetDefaultPropertiesCount() != 0 || Z_OBJ_P(expr).GetHandlers() != &StdObjectHandlers || GC_IS_RECURSIVE(obj_ht) != 0))
					ZendReleaseProperties(obj_ht)
				} else {
					ZVAL_EMPTY_ARRAY(result)
				}
			}
		} else {
			ZVAL_OBJ(result, ZendObjectsNew(ZendStandardClassDef))
			if Z_TYPE_P(expr) == IS_ARRAY {
				ht = ZendSymtableToProptable(Z_ARR_P(expr))
				if (GC_FLAGS(ht) & IS_ARRAY_IMMUTABLE) != 0 {

					/* TODO: try not to duplicate immutable arrays as well ??? */

					ht = ZendArrayDup(ht)

					/* TODO: try not to duplicate immutable arrays as well ??? */

				}
				Z_OBJ_P(result).SetProperties(ht)
			} else if Z_TYPE_P(expr) != IS_NULL {
				ht = ZendNewArray(1)
				Z_OBJ_P(result).SetProperties(ht)
				expr = ht.AddNew(ZSTR_KNOWN(ZEND_STR_SCALAR), expr)
				if IS_VAR == IS_CONST {
					if UNEXPECTED(Z_OPT_REFCOUNTED_P(expr)) {
						Z_ADDREF_P(expr)
					}
				} else {
					if Z_OPT_REFCOUNTED_P(expr) {
						Z_ADDREF_P(expr)
					}
				}
			}
		}
	}
	ZvalPtrDtorNogc(free_op1)
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_FE_RESET_R_SPEC_VAR_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var free_op1 ZendFreeOp
	var array_ptr *Zval
	var result *Zval
	array_ptr = _getZvalPtrVarDeref(opline.GetOp1().GetVar(), &free_op1, EXECUTE_DATA_C)
	if EXPECTED(Z_TYPE_P(array_ptr) == IS_ARRAY) {
		result = EX_VAR(opline.GetResult().GetVar())
		ZVAL_COPY_VALUE(result, array_ptr)
		if IS_VAR != IS_TMP_VAR && Z_OPT_REFCOUNTED_P(result) {
			Z_ADDREF_P(array_ptr)
		}
		Z_FE_POS_P(result) = 0
		ZvalPtrDtorNogc(free_op1)
		ZEND_VM_NEXT_OPCODE()
	} else if IS_VAR != IS_CONST && EXPECTED(Z_TYPE_P(array_ptr) == IS_OBJECT) {
		if Z_OBJCE_P(array_ptr).GetGetIterator() == nil {
			var properties *HashTable
			if Z_OBJ_P(array_ptr).GetProperties() != nil && UNEXPECTED(GC_REFCOUNT(Z_OBJ_P(array_ptr).GetProperties()) > 1) {
				if EXPECTED((GC_FLAGS(Z_OBJ_P(array_ptr).GetProperties()) & IS_ARRAY_IMMUTABLE) == 0) {
					GC_DELREF(Z_OBJ_P(array_ptr).GetProperties())
				}
				Z_OBJ_P(array_ptr).SetProperties(ZendArrayDup(Z_OBJ_P(array_ptr).GetProperties()))
			}
			properties = Z_OBJPROP_P(array_ptr)
			result = EX_VAR(opline.GetResult().GetVar())
			ZVAL_COPY_VALUE(result, array_ptr)
			if IS_VAR != IS_TMP_VAR {
				Z_ADDREF_P(array_ptr)
			}
			if properties.NumElements() == 0 {
				Z_FE_ITER_P(result) = uint32_t - 1
				ZvalPtrDtorNogc(free_op1)
				ZEND_VM_JMP(OP_JMP_ADDR(opline, opline.GetOp2()))
			}
			Z_FE_ITER_P(result) = properties.IteratorAdd(0)
			ZvalPtrDtorNogc(free_op1)
			ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
		} else {
			var is_empty ZendBool = ZendFeResetIterator(array_ptr, 0, OPLINE_C, EXECUTE_DATA_C)
			ZvalPtrDtorNogc(free_op1)
			if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
				HANDLE_EXCEPTION()
			} else if is_empty != 0 {
				ZEND_VM_JMP_EX(OP_JMP_ADDR(opline, opline.GetOp2()), 0)
			} else {
				ZEND_VM_NEXT_OPCODE()
			}
		}
	} else {
		ZendError(E_WARNING, "Invalid argument supplied for foreach()")
		ZVAL_UNDEF(EX_VAR(opline.GetResult().GetVar()))
		Z_FE_ITER_P(EX_VAR(opline.GetResult().GetVar())) = uint32_t - 1
		ZvalPtrDtorNogc(free_op1)
		ZEND_VM_JMP(OP_JMP_ADDR(opline, opline.GetOp2()))
	}
}
func ZEND_FE_RESET_RW_SPEC_VAR_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var free_op1 ZendFreeOp
	var array_ptr *Zval
	var array_ref *Zval
	if IS_VAR == IS_VAR || IS_VAR == IS_CV {
		array_ptr = _getZvalPtrPtrVar(opline.GetOp1().GetVar(), &free_op1, EXECUTE_DATA_C)
		array_ref = array_ptr
		if Z_ISREF_P(array_ref) {
			array_ptr = Z_REFVAL_P(array_ref)
		}
	} else {
		array_ptr = _getZvalPtrVar(opline.GetOp1().GetVar(), &free_op1, EXECUTE_DATA_C)
		array_ref = array_ptr
	}
	if EXPECTED(Z_TYPE_P(array_ptr) == IS_ARRAY) {
		if IS_VAR == IS_VAR || IS_VAR == IS_CV {
			if array_ptr == array_ref {
				ZVAL_NEW_REF(array_ref, array_ref)
				array_ptr = Z_REFVAL_P(array_ref)
			}
			Z_ADDREF_P(array_ref)
			ZVAL_COPY_VALUE(EX_VAR(opline.GetResult().GetVar()), array_ref)
		} else {
			array_ref = EX_VAR(opline.GetResult().GetVar())
			ZVAL_NEW_REF(array_ref, array_ptr)
			array_ptr = Z_REFVAL_P(array_ref)
		}
		if IS_VAR == IS_CONST {
			ZVAL_ARR(array_ptr, ZendArrayDup(Z_ARRVAL_P(array_ptr)))
		} else {
			SEPARATE_ARRAY(array_ptr)
		}
		Z_FE_ITER_P(EX_VAR(opline.GetResult().GetVar())) = Z_ARRVAL_P(array_ptr).IteratorAdd(0)
		if IS_VAR == IS_VAR {
			if UNEXPECTED(free_op1 != nil) {
				ZvalPtrDtorNogc(free_op1)
			}
		}
		ZEND_VM_NEXT_OPCODE()
	} else if IS_VAR != IS_CONST && EXPECTED(Z_TYPE_P(array_ptr) == IS_OBJECT) {
		if Z_OBJCE_P(array_ptr).GetGetIterator() == nil {
			var properties *HashTable
			if IS_VAR == IS_VAR || IS_VAR == IS_CV {
				if array_ptr == array_ref {
					ZVAL_NEW_REF(array_ref, array_ref)
					array_ptr = Z_REFVAL_P(array_ref)
				}
				Z_ADDREF_P(array_ref)
				ZVAL_COPY_VALUE(EX_VAR(opline.GetResult().GetVar()), array_ref)
			} else {
				array_ptr = EX_VAR(opline.GetResult().GetVar())
				ZVAL_COPY_VALUE(array_ptr, array_ref)
			}
			if Z_OBJ_P(array_ptr).GetProperties() != nil && UNEXPECTED(GC_REFCOUNT(Z_OBJ_P(array_ptr).GetProperties()) > 1) {
				if EXPECTED((GC_FLAGS(Z_OBJ_P(array_ptr).GetProperties()) & IS_ARRAY_IMMUTABLE) == 0) {
					GC_DELREF(Z_OBJ_P(array_ptr).GetProperties())
				}
				Z_OBJ_P(array_ptr).SetProperties(ZendArrayDup(Z_OBJ_P(array_ptr).GetProperties()))
			}
			properties = Z_OBJPROP_P(array_ptr)
			if properties.NumElements() == 0 {
				Z_FE_ITER_P(EX_VAR(opline.GetResult().GetVar())) = uint32_t - 1
				if UNEXPECTED(free_op1 != nil) {
					ZvalPtrDtorNogc(free_op1)
				}
				ZEND_VM_JMP(OP_JMP_ADDR(opline, opline.GetOp2()))
			}
			Z_FE_ITER_P(EX_VAR(opline.GetResult().GetVar())) = properties.IteratorAdd(0)
			if UNEXPECTED(free_op1 != nil) {
				ZvalPtrDtorNogc(free_op1)
			}
			ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
		} else {
			var is_empty ZendBool = ZendFeResetIterator(array_ptr, 1, OPLINE_C, EXECUTE_DATA_C)
			if IS_VAR == IS_VAR {
				if UNEXPECTED(free_op1 != nil) {
					ZvalPtrDtorNogc(free_op1)
				}
			} else {
				ZvalPtrDtorNogc(free_op1)
			}
			if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
				HANDLE_EXCEPTION()
			} else if is_empty != 0 {
				ZEND_VM_JMP_EX(OP_JMP_ADDR(opline, opline.GetOp2()), 0)
			} else {
				ZEND_VM_NEXT_OPCODE()
			}
		}
	} else {
		ZendError(E_WARNING, "Invalid argument supplied for foreach()")
		ZVAL_UNDEF(EX_VAR(opline.GetResult().GetVar()))
		Z_FE_ITER_P(EX_VAR(opline.GetResult().GetVar())) = uint32_t - 1
		if IS_VAR == IS_VAR {
			if UNEXPECTED(free_op1 != nil) {
				ZvalPtrDtorNogc(free_op1)
			}
		} else {
			ZvalPtrDtorNogc(free_op1)
		}
		ZEND_VM_JMP(OP_JMP_ADDR(opline, opline.GetOp2()))
	}
}
func ZEND_FE_FETCH_R_SPEC_VAR_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var array *Zval
	var value *Zval
	var value_type uint32
	var fe_ht *HashTable
	var pos HashPosition
	var p *Bucket
	array = EX_VAR(opline.GetOp1().GetVar())
	if EXPECTED(Z_TYPE_P(array) == IS_ARRAY) {
		fe_ht = Z_ARRVAL_P(array)
		pos = Z_FE_POS_P(array)
		p = fe_ht.GetArData() + pos
		for true {
			if UNEXPECTED(pos >= fe_ht.GetNNumUsed()) {

				/* reached end of iteration */

			fe_fetch_r_exit:
				ZEND_VM_SET_RELATIVE_OPCODE(opline, opline.GetExtendedValue())
				return 0
			}
			value = &p.val
			value_type = Z_TYPE_INFO_P(value)
			if EXPECTED(value_type != IS_UNDEF) {
				if UNEXPECTED(value_type == IS_INDIRECT) {
					value = Z_INDIRECT_P(value)
					value_type = Z_TYPE_INFO_P(value)
					if EXPECTED(value_type != IS_UNDEF) {
						break
					}
				} else {
					break
				}
			}
			pos++
			p++
		}
		Z_FE_POS_P(array) = pos + 1
		if RETURN_VALUE_USED(opline) {
			if p.GetKey() == nil {
				ZVAL_LONG(EX_VAR(opline.GetResult().GetVar()), p.GetH())
			} else {
				ZVAL_STR_COPY(EX_VAR(opline.GetResult().GetVar()), p.GetKey())
			}
		}
	} else {
		var iter *ZendObjectIterator
		ZEND_ASSERT(Z_TYPE_P(array) == IS_OBJECT)
		if b.Assign(&iter, ZendIteratorUnwrap(array)) == nil {

			/* plain object */

			fe_ht = Z_OBJPROP_P(array)
			pos = ZendHashIteratorPos(Z_FE_ITER_P(array), fe_ht)
			p = fe_ht.GetArData() + pos
			for true {
				if UNEXPECTED(pos >= fe_ht.GetNNumUsed()) {

					/* reached end of iteration */

					goto fe_fetch_r_exit

					/* reached end of iteration */

				}
				value = &p.val
				value_type = Z_TYPE_INFO_P(value)
				if EXPECTED(value_type != IS_UNDEF) {
					if UNEXPECTED(value_type == IS_INDIRECT) {
						value = Z_INDIRECT_P(value)
						value_type = Z_TYPE_INFO_P(value)
						if EXPECTED(value_type != IS_UNDEF) && EXPECTED(ZendCheckPropertyAccess(Z_OBJ_P(array), p.GetKey(), 0) == SUCCESS) {
							break
						}
					} else if EXPECTED(Z_OBJCE_P(array).GetDefaultPropertiesCount() == 0) || p.GetKey() == nil || ZendCheckPropertyAccess(Z_OBJ_P(array), p.GetKey(), 1) == SUCCESS {
						break
					}
				}
				pos++
				p++
			}
			if RETURN_VALUE_USED(opline) {
				if UNEXPECTED(p.GetKey() == nil) {
					ZVAL_LONG(EX_VAR(opline.GetResult().GetVar()), p.GetH())
				} else if ZSTR_VAL(p.GetKey())[0] {
					ZVAL_STR_COPY(EX_VAR(opline.GetResult().GetVar()), p.GetKey())
				} else {
					var class_name *byte
					var prop_name *byte
					var prop_name_len int
					ZendUnmanglePropertyNameEx(p.GetKey(), &class_name, &prop_name, &prop_name_len)
					ZVAL_STRINGL(EX_VAR(opline.GetResult().GetVar()), prop_name, prop_name_len)
				}
			}
			ExecutorGlobals.GetHtIterators()[Z_FE_ITER_P(array)].SetPos(pos + 1)
		} else {
			if EXPECTED(b.PreInc(&(iter.GetIndex())) > 0) {

				/* This could cause an endless loop if index becomes zero again.
				 * In case that ever happens we need an additional flag. */

				iter.GetFuncs().GetMoveForward()(iter)
				if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
					UNDEF_RESULT()
					HANDLE_EXCEPTION()
				}
				if UNEXPECTED(iter.GetFuncs().GetValid()(iter) == FAILURE) {

					/* reached end of iteration */

					if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
						UNDEF_RESULT()
						HANDLE_EXCEPTION()
					}
					goto fe_fetch_r_exit
				}
			}
			value = iter.GetFuncs().GetGetCurrentData()(iter)
			if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
				UNDEF_RESULT()
				HANDLE_EXCEPTION()
			}
			if value == nil {

				/* failure in get_current_data */

				goto fe_fetch_r_exit

				/* failure in get_current_data */

			}
			if RETURN_VALUE_USED(opline) {
				if iter.GetFuncs().GetGetCurrentKey() != nil {
					iter.GetFuncs().GetGetCurrentKey()(iter, EX_VAR(opline.GetResult().GetVar()))
					if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
						UNDEF_RESULT()
						HANDLE_EXCEPTION()
					}
				} else {
					ZVAL_LONG(EX_VAR(opline.GetResult().GetVar()), iter.GetIndex())
				}
			}
			value_type = Z_TYPE_INFO_P(value)
		}
	}
	if EXPECTED(opline.GetOp2Type() == IS_CV) {
		var variable_ptr *Zval = EX_VAR(opline.GetOp2().GetVar())
		ZendAssignToVariable(variable_ptr, value, IS_CV, EX_USES_STRICT_TYPES())
	} else {
		var res *Zval = EX_VAR(opline.GetOp2().GetVar())
		var gc *ZendRefcounted = Z_COUNTED_P(value)
		ZVAL_COPY_VALUE_EX(res, value, gc, value_type)
		if Z_TYPE_INFO_REFCOUNTED(value_type) {
			GC_ADDREF(gc)
		}
	}
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_FE_FETCH_RW_SPEC_VAR_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var array *Zval
	var value *Zval
	var value_type uint32
	var fe_ht *HashTable
	var pos HashPosition
	var p *Bucket
	array = EX_VAR(opline.GetOp1().GetVar())
	ZVAL_DEREF(array)
	if EXPECTED(Z_TYPE_P(array) == IS_ARRAY) {
		pos = ZendHashIteratorPosEx(Z_FE_ITER_P(EX_VAR(opline.GetOp1().GetVar())), array)
		fe_ht = Z_ARRVAL_P(array)
		p = fe_ht.GetArData() + pos
		for true {
			if UNEXPECTED(pos >= fe_ht.GetNNumUsed()) {

				/* reached end of iteration */

				goto fe_fetch_w_exit

				/* reached end of iteration */

			}
			value = &p.val
			value_type = Z_TYPE_INFO_P(value)
			if EXPECTED(value_type != IS_UNDEF) {
				if UNEXPECTED(value_type == IS_INDIRECT) {
					value = Z_INDIRECT_P(value)
					value_type = Z_TYPE_INFO_P(value)
					if EXPECTED(value_type != IS_UNDEF) {
						break
					}
				} else {
					break
				}
			}
			pos++
			p++
		}
		if RETURN_VALUE_USED(opline) {
			if p.GetKey() == nil {
				ZVAL_LONG(EX_VAR(opline.GetResult().GetVar()), p.GetH())
			} else {
				ZVAL_STR_COPY(EX_VAR(opline.GetResult().GetVar()), p.GetKey())
			}
		}
		ExecutorGlobals.GetHtIterators()[Z_FE_ITER_P(EX_VAR(opline.GetOp1().GetVar()))].SetPos(pos + 1)
	} else if EXPECTED(Z_TYPE_P(array) == IS_OBJECT) {
		var iter *ZendObjectIterator
		if b.Assign(&iter, ZendIteratorUnwrap(array)) == nil {

			/* plain object */

			fe_ht = Z_OBJPROP_P(array)
			pos = ZendHashIteratorPos(Z_FE_ITER_P(EX_VAR(opline.GetOp1().GetVar())), fe_ht)
			p = fe_ht.GetArData() + pos
			for true {
				if UNEXPECTED(pos >= fe_ht.GetNNumUsed()) {

					/* reached end of iteration */

					goto fe_fetch_w_exit

					/* reached end of iteration */

				}
				value = &p.val
				value_type = Z_TYPE_INFO_P(value)
				if EXPECTED(value_type != IS_UNDEF) {
					if UNEXPECTED(value_type == IS_INDIRECT) {
						value = Z_INDIRECT_P(value)
						value_type = Z_TYPE_INFO_P(value)
						if EXPECTED(value_type != IS_UNDEF) && EXPECTED(ZendCheckPropertyAccess(Z_OBJ_P(array), p.GetKey(), 0) == SUCCESS) {
							if (value_type & Z_TYPE_MASK) != IS_REFERENCE {
								var prop_info *ZendPropertyInfo = ZendGetTypedPropertyInfoForSlot(Z_OBJ_P(array), value)
								if UNEXPECTED(prop_info != nil) {
									ZVAL_NEW_REF(value, value)
									ZEND_REF_ADD_TYPE_SOURCE(Z_REF_P(value), prop_info)
									value_type = IS_REFERENCE_EX
								}
							}
							break
						}
					} else if EXPECTED(Z_OBJCE_P(array).GetDefaultPropertiesCount() == 0) || p.GetKey() == nil || ZendCheckPropertyAccess(Z_OBJ_P(array), p.GetKey(), 1) == SUCCESS {
						break
					}
				}
				pos++
				p++
			}
			if RETURN_VALUE_USED(opline) {
				if UNEXPECTED(p.GetKey() == nil) {
					ZVAL_LONG(EX_VAR(opline.GetResult().GetVar()), p.GetH())
				} else if ZSTR_VAL(p.GetKey())[0] {
					ZVAL_STR_COPY(EX_VAR(opline.GetResult().GetVar()), p.GetKey())
				} else {
					var class_name *byte
					var prop_name *byte
					var prop_name_len int
					ZendUnmanglePropertyNameEx(p.GetKey(), &class_name, &prop_name, &prop_name_len)
					ZVAL_STRINGL(EX_VAR(opline.GetResult().GetVar()), prop_name, prop_name_len)
				}
			}
			ExecutorGlobals.GetHtIterators()[Z_FE_ITER_P(EX_VAR(opline.GetOp1().GetVar()))].SetPos(pos + 1)
		} else {
			if b.PreInc(&(iter.GetIndex())) > 0 {

				/* This could cause an endless loop if index becomes zero again.
				 * In case that ever happens we need an additional flag. */

				iter.GetFuncs().GetMoveForward()(iter)
				if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
					UNDEF_RESULT()
					HANDLE_EXCEPTION()
				}
				if UNEXPECTED(iter.GetFuncs().GetValid()(iter) == FAILURE) {

					/* reached end of iteration */

					if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
						UNDEF_RESULT()
						HANDLE_EXCEPTION()
					}
					goto fe_fetch_w_exit
				}
			}
			value = iter.GetFuncs().GetGetCurrentData()(iter)
			if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
				UNDEF_RESULT()
				HANDLE_EXCEPTION()
			}
			if value == nil {

				/* failure in get_current_data */

				goto fe_fetch_w_exit

				/* failure in get_current_data */

			}
			if RETURN_VALUE_USED(opline) {
				if iter.GetFuncs().GetGetCurrentKey() != nil {
					iter.GetFuncs().GetGetCurrentKey()(iter, EX_VAR(opline.GetResult().GetVar()))
					if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
						UNDEF_RESULT()
						HANDLE_EXCEPTION()
					}
				} else {
					ZVAL_LONG(EX_VAR(opline.GetResult().GetVar()), iter.GetIndex())
				}
			}
			value_type = Z_TYPE_INFO_P(value)
		}
	} else {
		ZendError(E_WARNING, "Invalid argument supplied for foreach()")
		if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
			UNDEF_RESULT()
			HANDLE_EXCEPTION()
		}
	fe_fetch_w_exit:
		ZEND_VM_SET_RELATIVE_OPCODE(opline, opline.GetExtendedValue())
		return 0
	}
	if EXPECTED((value_type & Z_TYPE_MASK) != IS_REFERENCE) {
		var gc *ZendRefcounted = Z_COUNTED_P(value)
		var ref *Zval
		ZVAL_NEW_EMPTY_REF(value)
		ref = Z_REFVAL_P(value)
		ZVAL_COPY_VALUE_EX(ref, value, gc, value_type)
	}
	if EXPECTED(opline.GetOp2Type() == IS_CV) {
		var variable_ptr *Zval = EX_VAR(opline.GetOp2().GetVar())
		if EXPECTED(variable_ptr != value) {
			var ref *ZendReference
			ref = Z_REF_P(value)
			GC_ADDREF(ref)
			IZvalPtrDtor(variable_ptr)
			ZVAL_REF(variable_ptr, ref)
		}
	} else {
		Z_ADDREF_P(value)
		ZVAL_REF(EX_VAR(opline.GetOp2().GetVar()), Z_REF_P(value))
	}
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_JMP_SET_SPEC_VAR_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var free_op1 ZendFreeOp
	var value *Zval
	var ref *Zval = nil
	var ret int
	value = _getZvalPtrVar(opline.GetOp1().GetVar(), &free_op1, EXECUTE_DATA_C)
	if (IS_VAR == IS_VAR || IS_VAR == IS_CV) && Z_ISREF_P(value) {
		if IS_VAR == IS_VAR {
			ref = value
		}
		value = Z_REFVAL_P(value)
	}
	ret = IZendIsTrue(value)
	if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
		ZvalPtrDtorNogc(free_op1)
		ZVAL_UNDEF(EX_VAR(opline.GetResult().GetVar()))
		HANDLE_EXCEPTION()
	}
	if ret != 0 {
		var result *Zval = EX_VAR(opline.GetResult().GetVar())
		ZVAL_COPY_VALUE(result, value)
		if IS_VAR == IS_CONST {
			if UNEXPECTED(Z_OPT_REFCOUNTED_P(result)) {
				Z_ADDREF_P(result)
			}
		} else if IS_VAR == IS_CV {
			if Z_OPT_REFCOUNTED_P(result) {
				Z_ADDREF_P(result)
			}
		} else if IS_VAR == IS_VAR && ref != nil {
			var r *ZendReference = Z_REF_P(ref)
			if UNEXPECTED(GC_DELREF(r) == 0) {
				EfreeSize(r, b.SizeOf("zend_reference"))
			} else if Z_OPT_REFCOUNTED_P(result) {
				Z_ADDREF_P(result)
			}
		}
		ZEND_VM_JMP_EX(OP_JMP_ADDR(opline, opline.GetOp2()), 0)
	}
	ZvalPtrDtorNogc(free_op1)
	ZEND_VM_NEXT_OPCODE()
}
func ZEND_COALESCE_SPEC_VAR_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var free_op1 ZendFreeOp
	var value *Zval
	var ref *Zval = nil
	value = _getZvalPtrVar(opline.GetOp1().GetVar(), &free_op1, EXECUTE_DATA_C)
	if (IS_VAR&(IS_VAR|IS_CV)) != 0 && Z_ISREF_P(value) {
		if (IS_VAR & IS_VAR) != 0 {
			ref = value
		}
		value = Z_REFVAL_P(value)
	}
	if Z_TYPE_P(value) > IS_NULL {
		var result *Zval = EX_VAR(opline.GetResult().GetVar())
		ZVAL_COPY_VALUE(result, value)
		if IS_VAR == IS_CONST {
			if UNEXPECTED(Z_OPT_REFCOUNTED_P(result)) {
				Z_ADDREF_P(result)
			}
		} else if IS_VAR == IS_CV {
			if Z_OPT_REFCOUNTED_P(result) {
				Z_ADDREF_P(result)
			}
		} else if (IS_VAR&IS_VAR) != 0 && ref != nil {
			var r *ZendReference = Z_REF_P(ref)
			if UNEXPECTED(GC_DELREF(r) == 0) {
				EfreeSize(r, b.SizeOf("zend_reference"))
			} else if Z_OPT_REFCOUNTED_P(result) {
				Z_ADDREF_P(result)
			}
		}
		ZEND_VM_JMP_EX(OP_JMP_ADDR(opline, opline.GetOp2()), 0)
	}
	ZvalPtrDtorNogc(free_op1)
	ZEND_VM_NEXT_OPCODE()
}
func ZEND_QM_ASSIGN_SPEC_VAR_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var free_op1 ZendFreeOp
	var value *Zval
	var result *Zval = EX_VAR(opline.GetResult().GetVar())
	value = _getZvalPtrVar(opline.GetOp1().GetVar(), &free_op1, EXECUTE_DATA_C)
	if IS_VAR == IS_CV && UNEXPECTED(Z_TYPE_P(value) == IS_UNDEF) {
		ZVAL_UNDEFINED_OP1()
		ZVAL_NULL(result)
		ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
	}
	if IS_VAR == IS_CV {
		ZVAL_COPY_DEREF(result, value)
	} else if IS_VAR == IS_VAR {
		if UNEXPECTED(Z_ISREF_P(value)) {
			ZVAL_COPY_VALUE(result, Z_REFVAL_P(value))
			if UNEXPECTED(Z_DELREF_P(value) == 0) {
				EfreeSize(Z_REF_P(value), b.SizeOf("zend_reference"))
			} else if Z_OPT_REFCOUNTED_P(result) {
				Z_ADDREF_P(result)
			}
		} else {
			ZVAL_COPY_VALUE(result, value)
		}
	} else {
		ZVAL_COPY_VALUE(result, value)
		if IS_VAR == IS_CONST {
			if UNEXPECTED(Z_OPT_REFCOUNTED_P(result)) {
				Z_ADDREF_P(result)
			}
		}
	}
	ZEND_VM_NEXT_OPCODE()
}
func ZEND_YIELD_FROM_SPEC_VAR_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var generator *ZendGenerator = ZendGetRunningGenerator(EXECUTE_DATA_C)
	var val *Zval
	var free_op1 ZendFreeOp
	val = _getZvalPtrVarDeref(opline.GetOp1().GetVar(), &free_op1, EXECUTE_DATA_C)
	if UNEXPECTED(generator.IsForcedClose()) {
		ZendThrowError(nil, "Cannot use \"yield from\" in a force-closed generator")
		ZvalPtrDtorNogc(free_op1)
		UNDEF_RESULT()
		HANDLE_EXCEPTION()
	}
	if Z_TYPE_P(val) == IS_ARRAY {
		ZVAL_COPY_VALUE(&generator.values, val)
		if IS_VAR != IS_TMP_VAR && Z_OPT_REFCOUNTED_P(val) {
			Z_ADDREF_P(val)
		}
		Z_FE_POS(generator.GetValues()) = 0
		ZvalPtrDtorNogc(free_op1)
	} else if IS_VAR != IS_CONST && Z_TYPE_P(val) == IS_OBJECT && Z_OBJCE_P(val).GetGetIterator() != nil {
		var ce *ZendClassEntry = Z_OBJCE_P(val)
		if ce == ZendCeGenerator {
			var new_gen *ZendGenerator = (*ZendGenerator)(Z_OBJ_P(val))
			if IS_VAR != IS_TMP_VAR {
				Z_ADDREF_P(val)
			}
			ZvalPtrDtorNogc(free_op1)
			if Z_ISUNDEF(new_gen.GetRetval()) {
				if UNEXPECTED(ZendGeneratorGetCurrent(new_gen) == generator) {
					ZendThrowError(nil, "Impossible to yield from the Generator being currently run")
					ZvalPtrDtor(val)
					UNDEF_RESULT()
					HANDLE_EXCEPTION()
				} else {
					ZendGeneratorYieldFrom(generator, new_gen)
				}
			} else if UNEXPECTED(new_gen.GetExecuteData() == nil) {
				ZendThrowError(nil, "Generator passed to yield from was aborted without proper return and is unable to continue")
				ZvalPtrDtor(val)
				UNDEF_RESULT()
				HANDLE_EXCEPTION()
			} else {
				if RETURN_VALUE_USED(opline) {
					ZVAL_COPY(EX_VAR(opline.GetResult().GetVar()), &new_gen.retval)
				}
				ZEND_VM_NEXT_OPCODE()
			}
		} else {
			var iter *ZendObjectIterator = ce.GetGetIterator()(ce, val, 0)
			ZvalPtrDtorNogc(free_op1)
			if UNEXPECTED(iter == nil) || UNEXPECTED(ExecutorGlobals.GetException() != nil) {
				if ExecutorGlobals.GetException() == nil {
					ZendThrowError(nil, "Object of type %s did not create an Iterator", ZSTR_VAL(ce.GetName()))
				}
				UNDEF_RESULT()
				HANDLE_EXCEPTION()
			}
			iter.SetIndex(0)
			if iter.GetFuncs().GetRewind() != nil {
				iter.GetFuncs().GetRewind()(iter)
				if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
					OBJ_RELEASE(&iter.std)
					UNDEF_RESULT()
					HANDLE_EXCEPTION()
				}
			}
			ZVAL_OBJ(&generator.values, &iter.std)
		}
	} else {
		ZendThrowError(nil, "Can use \"yield from\" only with arrays and Traversables")
		ZvalPtrDtorNogc(free_op1)
		UNDEF_RESULT()
		HANDLE_EXCEPTION()
	}

	/* This is the default return value
	 * when the expression is a Generator, it will be overwritten in zend_generator_resume() */

	if RETURN_VALUE_USED(opline) {
		ZVAL_NULL(EX_VAR(opline.GetResult().GetVar()))
	}

	/* This generator has no send target (though the generator we delegate to might have one) */

	generator.SetSendTarget(nil)

	/* We increment to the next op, so we are at the correct position when the
	 * generator is resumed. */

	ZEND_VM_INC_OPCODE()

	/* The GOTO VM uses a local opline variable. We need to set the opline
	 * variable in execute_data so we don't resume at an old position. */

	return -1
}
func ZEND_SEND_VAR_SIMPLE_SPEC_VAR_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var varptr *Zval
	var arg *Zval
	var free_op1 ZendFreeOp
	varptr = _getZvalPtrVar(opline.GetOp1().GetVar(), &free_op1, EXECUTE_DATA_C)
	arg = ZEND_CALL_VAR(EX(call), opline.GetResult().GetVar())
	if IS_VAR == IS_CV {
		ZVAL_COPY(arg, varptr)
	} else {
		ZVAL_COPY_VALUE(arg, varptr)
	}
	ZEND_VM_NEXT_OPCODE()
}
