func ZEND_ASSIGN_OBJ_OP_SPEC_VAR_CONST_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var free_op1 ZendFreeOp
	var free_op_data ZendFreeOp
	var object *Zval
	var property *Zval
	var value *Zval
	var zptr *Zval
	var cache_slot *any
	var prop_info *ZendPropertyInfo
	object = _getZvalPtrPtrVar(opline.GetOp1().GetVar(), &free_op1, EXECUTE_DATA_C)
	if IS_VAR == IS_UNUSED && UNEXPECTED(Z_TYPE_P(object) == IS_UNDEF) {
		return zend_this_not_in_object_context_helper_SPEC(execute_data)
	}
	property = RT_CONSTANT(opline, opline.GetOp2())
	for {
		value = GetOpDataZvalPtrR((opline + 1).GetOp1Type(), (opline + 1).GetOp1(), &free_op_data)
		if IS_VAR != IS_UNUSED && UNEXPECTED(Z_TYPE_P(object) != IS_OBJECT) {
			if Z_ISREF_P(object) && Z_TYPE_P(Z_REFVAL_P(object)) == IS_OBJECT {
				object = Z_REFVAL_P(object)
				goto assign_op_object
			}
			if IS_VAR == IS_CV && UNEXPECTED(Z_TYPE_P(object) == IS_UNDEF) {
				ZVAL_UNDEFINED_OP1()
			}
			object = MakeRealObject(object, property, OPLINE_C, EXECUTE_DATA_C)
			if UNEXPECTED(object == nil) {
				break
			}
		}
	assign_op_object:

		/* here we are sure we are dealing with an object */

		if IS_CONST == IS_CONST {
			cache_slot = CACHE_ADDR((opline + 1).GetExtendedValue())
		} else {
			cache_slot = nil
		}
		if EXPECTED(b.Assign(&zptr, Z_OBJ_HT_P(object).GetGetPropertyPtrPtr()(object, property, BP_VAR_RW, cache_slot)) != nil) {
			if UNEXPECTED(Z_ISERROR_P(zptr)) {
				if UNEXPECTED(RETURN_VALUE_USED(opline)) {
					ZVAL_NULL(EX_VAR(opline.GetResult().GetVar()))
				}
			} else {
				var orig_zptr *Zval = zptr
				var ref *ZendReference
				for {
					if UNEXPECTED(Z_ISREF_P(zptr)) {
						ref = Z_REF_P(zptr)
						zptr = Z_REFVAL_P(zptr)
						if UNEXPECTED(ZEND_REF_HAS_TYPE_SOURCES(ref)) {
							ZendBinaryAssignOpTypedRef(ref, value, OPLINE_C, EXECUTE_DATA_C)
							break
						}
					}
					if IS_CONST == IS_CONST {
						prop_info = (*ZendPropertyInfo)(CACHED_PTR_EX(cache_slot + 2))
					} else {
						prop_info = ZendObjectFetchPropertyTypeInfo(Z_OBJ_P(object), orig_zptr)
					}
					if UNEXPECTED(prop_info != nil) {

						/* special case for typed properties */

						ZendBinaryAssignOpTypedProp(prop_info, zptr, value, OPLINE_C, EXECUTE_DATA_C)

						/* special case for typed properties */

					} else {
						ZendBinaryOp(zptr, zptr, value, OPLINE_C)
					}
					break
				}
				if UNEXPECTED(RETURN_VALUE_USED(opline)) {
					ZVAL_COPY(EX_VAR(opline.GetResult().GetVar()), zptr)
				}
			}
		} else {
			ZendAssignOpOverloadedProperty(object, property, cache_slot, value, OPLINE_C, EXECUTE_DATA_C)
		}
		break
	}
	FREE_OP(free_op_data)
	if UNEXPECTED(free_op1 != nil) {
		ZvalPtrDtorNogc(free_op1)
	}

	/* assign_obj has two opcodes! */

	OPLINE = EX(opline) + 2
	return 0
}
func ZEND_ASSIGN_DIM_OP_SPEC_VAR_CONST_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var free_op1 ZendFreeOp
	var free_op_data1 ZendFreeOp
	var var_ptr *Zval
	var value *Zval
	var container *Zval
	var dim *Zval
	container = _getZvalPtrPtrVar(opline.GetOp1().GetVar(), &free_op1, EXECUTE_DATA_C)
	if EXPECTED(Z_TYPE_P(container) == IS_ARRAY) {
	assign_dim_op_array:
		SEPARATE_ARRAY(container)
	assign_dim_op_new_array:
		dim = RT_CONSTANT(opline, opline.GetOp2())
		if IS_CONST == IS_UNUSED {
			var_ptr = Z_ARRVAL_P(container).NextIndexInsert(&(ExecutorGlobals.GetUninitializedZval()))
			if UNEXPECTED(var_ptr == nil) {
				ZendCannotAddElement()
				goto assign_dim_op_ret_null
			}
		} else {
			if IS_CONST == IS_CONST {
				var_ptr = zend_fetch_dimension_address_inner_RW_CONST(Z_ARRVAL_P(container), dim, EXECUTE_DATA_C)
			} else {
				var_ptr = zend_fetch_dimension_address_inner_RW(Z_ARRVAL_P(container), dim, EXECUTE_DATA_C)
			}
			if UNEXPECTED(var_ptr == nil) {
				goto assign_dim_op_ret_null
			}
		}
		value = GetOpDataZvalPtrR((opline + 1).GetOp1Type(), (opline + 1).GetOp1(), &free_op_data1)
		for {
			if IS_CONST != IS_UNUSED && UNEXPECTED(Z_ISREF_P(var_ptr)) {
				var ref *ZendReference = Z_REF_P(var_ptr)
				var_ptr = Z_REFVAL_P(var_ptr)
				if UNEXPECTED(ZEND_REF_HAS_TYPE_SOURCES(ref)) {
					ZendBinaryAssignOpTypedRef(ref, value, OPLINE_C, EXECUTE_DATA_C)
					break
				}
			}
			ZendBinaryOp(var_ptr, var_ptr, value, OPLINE_C)
			break
		}
		if UNEXPECTED(RETURN_VALUE_USED(opline)) {
			ZVAL_COPY(EX_VAR(opline.GetResult().GetVar()), var_ptr)
		}
		FREE_OP(free_op_data1)
	} else {
		if EXPECTED(Z_ISREF_P(container)) {
			container = Z_REFVAL_P(container)
			if EXPECTED(Z_TYPE_P(container) == IS_ARRAY) {
				goto assign_dim_op_array
			}
		}
		dim = RT_CONSTANT(opline, opline.GetOp2())
		if EXPECTED(Z_TYPE_P(container) == IS_OBJECT) {
			if IS_CONST == IS_CONST && Z_EXTRA_P(dim) == ZEND_EXTRA_VALUE {
				dim++
			}
			ZendBinaryAssignOpObjDim(container, dim, OPLINE_C, EXECUTE_DATA_C)
		} else if EXPECTED(Z_TYPE_P(container) <= IS_FALSE) {
			if IS_VAR == IS_CV && UNEXPECTED(Z_TYPE_INFO_P(container) == IS_UNDEF) {
				ZVAL_UNDEFINED_OP1()
			}
			ZVAL_ARR(container, ZendNewArray(8))
			goto assign_dim_op_new_array
		} else {
			ZendBinaryAssignOpDimSlow(container, dim, OPLINE_C, EXECUTE_DATA_C)
		assign_dim_op_ret_null:
			FREE_UNFETCHED_OP((opline + 1).GetOp1Type(), (opline + 1).GetOp1().GetVar())
			if UNEXPECTED(RETURN_VALUE_USED(opline)) {
				ZVAL_NULL(EX_VAR(opline.GetResult().GetVar()))
			}
		}
	}
	if UNEXPECTED(free_op1 != nil) {
		ZvalPtrDtorNogc(free_op1)
	}
	OPLINE = EX(opline) + 2
	return 0
}
