func ZEND_ASSIGN_DIM_SPEC_VAR_CONST_OP_DATA_CONST_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var free_op1 ZendFreeOp
	var object_ptr *Zval
	var orig_object_ptr *Zval
	var free_op_data ZendFreeOp
	var value *Zval
	var variable_ptr *Zval
	var dim *Zval
	object_ptr = _getZvalPtrPtrVar(opline.GetOp1().GetVar(), &free_op1, EXECUTE_DATA_C)
	orig_object_ptr = object_ptr
	if EXPECTED(Z_TYPE_P(object_ptr) == IS_ARRAY) {
	try_assign_dim_array:
		value = RT_CONSTANT(opline+1, (opline + 1).GetOp1())
		SEPARATE_ARRAY(object_ptr)
		if IS_CONST == IS_UNUSED {
			if IS_CONST == IS_CV || IS_CONST == IS_VAR {
				ZVAL_DEREF(value)
			}
			variable_ptr = Z_ARRVAL_P(object_ptr).NextIndexInsert(value)
			if UNEXPECTED(variable_ptr == nil) {
				ZendCannotAddElement()
				goto assign_dim_error
			} else if IS_CONST == IS_CV {
				if Z_REFCOUNTED_P(value) {
					Z_ADDREF_P(value)
				}
			} else if IS_CONST == IS_VAR {
				if value != free_op_data {
					if Z_REFCOUNTED_P(value) {
						Z_ADDREF_P(value)
					}
				}
			} else if IS_CONST == IS_CONST {
				if UNEXPECTED(Z_REFCOUNTED_P(value)) {
					Z_ADDREF_P(value)
				}
			}
		} else {
			dim = RT_CONSTANT(opline, opline.GetOp2())
			if IS_CONST == IS_CONST {
				variable_ptr = zend_fetch_dimension_address_inner_W_CONST(Z_ARRVAL_P(object_ptr), dim, EXECUTE_DATA_C)
			} else {
				variable_ptr = zend_fetch_dimension_address_inner_W(Z_ARRVAL_P(object_ptr), dim, EXECUTE_DATA_C)
			}
			if UNEXPECTED(variable_ptr == nil) {
				goto assign_dim_error
			}
			value = ZendAssignToVariable(variable_ptr, value, IS_CONST, EX_USES_STRICT_TYPES())
		}
		if UNEXPECTED(RETURN_VALUE_USED(opline)) {
			ZVAL_COPY(EX_VAR(opline.GetResult().GetVar()), value)
		}
	} else {
		if EXPECTED(Z_ISREF_P(object_ptr)) {
			object_ptr = Z_REFVAL_P(object_ptr)
			if EXPECTED(Z_TYPE_P(object_ptr) == IS_ARRAY) {
				goto try_assign_dim_array
			}
		}
		if EXPECTED(Z_TYPE_P(object_ptr) == IS_OBJECT) {
			dim = RT_CONSTANT(opline, opline.GetOp2())
			value = RT_CONSTANT(opline+1, (opline + 1).GetOp1())
			if IS_CONST == IS_CONST && Z_EXTRA_P(dim) == ZEND_EXTRA_VALUE {
				dim++
			}
			ZendAssignToObjectDim(object_ptr, dim, value, OPLINE_C, EXECUTE_DATA_C)
		} else if EXPECTED(Z_TYPE_P(object_ptr) == IS_STRING) {
			if IS_CONST == IS_UNUSED {
				ZendUseNewElementForString()
				UNDEF_RESULT()
			} else {
				dim = RT_CONSTANT(opline, opline.GetOp2())
				value = RT_CONSTANT(opline+1, (opline + 1).GetOp1())
				ZendAssignToStringOffset(object_ptr, dim, value, OPLINE_C, EXECUTE_DATA_C)
			}
		} else if EXPECTED(Z_TYPE_P(object_ptr) <= IS_FALSE) {
			if Z_ISREF_P(orig_object_ptr) && ZEND_REF_HAS_TYPE_SOURCES(Z_REF_P(orig_object_ptr)) && ZendVerifyRefArrayAssignable(Z_REF_P(orig_object_ptr)) == 0 {
				dim = RT_CONSTANT(opline, opline.GetOp2())
				UNDEF_RESULT()
			} else {
				ZVAL_ARR(object_ptr, ZendNewArray(8))
				goto try_assign_dim_array
			}
		} else {
			if IS_VAR != IS_VAR || EXPECTED(!(Z_ISERROR_P(object_ptr))) {
				ZendUseScalarAsArray()
			}
			dim = RT_CONSTANT(opline, opline.GetOp2())
		assign_dim_error:
			if UNEXPECTED(RETURN_VALUE_USED(opline)) {
				ZVAL_NULL(EX_VAR(opline.GetResult().GetVar()))
			}
		}
	}
	if IS_CONST != IS_UNUSED {

	}
	if UNEXPECTED(free_op1 != nil) {
		ZvalPtrDtorNogc(free_op1)
	}

	/* assign_dim has two opcodes! */

	OPLINE = EX(opline) + 2
	return 0
}
