func ZEND_INIT_STATIC_METHOD_CALL_SPEC_VAR_CONST_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var function_name *Zval
	var ce *ZendClassEntry
	var call_info uint32
	var fbc *ZendFunction
	var call *ZendExecuteData
	if IS_VAR == IS_CONST {

		/* no function found. try a static method in class */

		ce = CACHED_PTR(opline.GetResult().GetNum())
		if UNEXPECTED(ce == nil) {
			ce = ZendFetchClassByName(Z_STR_P(RT_CONSTANT(opline, opline.GetOp1())), Z_STR_P(RT_CONSTANT(opline, opline.GetOp1())+1), ZEND_FETCH_CLASS_DEFAULT|ZEND_FETCH_CLASS_EXCEPTION)
			if UNEXPECTED(ce == nil) {
				ZEND_ASSERT(ExecutorGlobals.GetException() != nil)
				HANDLE_EXCEPTION()
			}
			if IS_CONST != IS_CONST {
				CACHE_PTR(opline.GetResult().GetNum(), ce)
			}
		}
	} else if IS_VAR == IS_UNUSED {
		ce = ZendFetchClass(nil, opline.GetOp1().GetNum())
		if UNEXPECTED(ce == nil) {
			ZEND_ASSERT(ExecutorGlobals.GetException() != nil)
			HANDLE_EXCEPTION()
		}
	} else {
		ce = Z_CE_P(EX_VAR(opline.GetOp1().GetVar()))
	}
	if IS_VAR == IS_CONST && IS_CONST == IS_CONST && EXPECTED(b.Assign(&fbc, CACHED_PTR(opline.GetResult().GetNum()+b.SizeOf("void *"))) != nil) {

	} else if IS_VAR != IS_CONST && IS_CONST == IS_CONST && EXPECTED(CACHED_PTR(opline.GetResult().GetNum()) == ce) {
		fbc = CACHED_PTR(opline.GetResult().GetNum() + b.SizeOf("void *"))
	} else if IS_CONST != IS_UNUSED {
		function_name = RT_CONSTANT(opline, opline.GetOp2())
		if IS_CONST != IS_CONST {
			if UNEXPECTED(Z_TYPE_P(function_name) != IS_STRING) {
				for {
					if (IS_CONST&(IS_VAR|IS_CV)) != 0 && Z_ISREF_P(function_name) {
						function_name = Z_REFVAL_P(function_name)
						if EXPECTED(Z_TYPE_P(function_name) == IS_STRING) {
							break
						}
					} else if IS_CONST == IS_CV && UNEXPECTED(Z_TYPE_P(function_name) == IS_UNDEF) {
						ZVAL_UNDEFINED_OP2()
						if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
							HANDLE_EXCEPTION()
						}
					}
					ZendThrowError(nil, "Function name must be a string")
					HANDLE_EXCEPTION()
					break
				}
			}
		}
		if ce.GetGetStaticMethod() != nil {
			fbc = ce.GetGetStaticMethod()(ce, Z_STR_P(function_name))
		} else {
			fbc = ZendStdGetStaticMethod(ce, Z_STR_P(function_name), b.CondF1(IS_CONST == IS_CONST, func() *Zval { return RT_CONSTANT(opline, opline.GetOp2()) + 1 }, nil))
		}
		if UNEXPECTED(fbc == nil) {
			if EXPECTED(ExecutorGlobals.GetException() == nil) {
				ZendUndefinedMethod(ce, Z_STR_P(function_name))
			}
			HANDLE_EXCEPTION()
		}
		if IS_CONST == IS_CONST && EXPECTED(fbc.GetType() <= ZEND_USER_FUNCTION) && EXPECTED(!fbc.HasFnFlags(ZEND_ACC_CALL_VIA_TRAMPOLINE|ZEND_ACC_NEVER_CACHE)) {
			CACHE_POLYMORPHIC_PTR(opline.GetResult().GetNum(), ce, fbc)
		}
		if EXPECTED(fbc.GetType() == ZEND_USER_FUNCTION) && UNEXPECTED(!(RUN_TIME_CACHE(&fbc.op_array))) {
			InitFuncRunTimeCache(&fbc.op_array)
		}
		if IS_CONST != IS_CONST {

		}
	} else {
		if UNEXPECTED(ce.GetConstructor() == nil) {
			ZendThrowError(nil, "Cannot call constructor")
			HANDLE_EXCEPTION()
		}
		if Z_TYPE(EX(This)) == IS_OBJECT && Z_OBJ(EX(This)).GetCe() != ce.GetConstructor().GetScope() && ce.GetConstructor().IsPrivate() {
			ZendThrowError(nil, "Cannot call private %s::__construct()", ZSTR_VAL(ce.GetName()))
			HANDLE_EXCEPTION()
		}
		fbc = ce.GetConstructor()
		if EXPECTED(fbc.GetType() == ZEND_USER_FUNCTION) && UNEXPECTED(!(RUN_TIME_CACHE(&fbc.op_array))) {
			InitFuncRunTimeCache(&fbc.op_array)
		}
	}
	if !fbc.IsStatic() {
		if Z_TYPE(EX(This)) == IS_OBJECT && InstanceofFunction(Z_OBJCE(EX(This)), ce) != 0 {
			ce = (*ZendClassEntry)(Z_OBJ(EX(This)))
			call_info = ZEND_CALL_NESTED_FUNCTION | ZEND_CALL_HAS_THIS
		} else {
			ZendNonStaticMethodCall(fbc)
			if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
				HANDLE_EXCEPTION()
			}
			goto check_parent_and_self
		}
	} else {
	check_parent_and_self:

		/* previous opcode is ZEND_FETCH_CLASS */

		if IS_VAR == IS_UNUSED && ((opline.GetOp1().GetNum()&ZEND_FETCH_CLASS_MASK) == ZEND_FETCH_CLASS_PARENT || (opline.GetOp1().GetNum()&ZEND_FETCH_CLASS_MASK) == ZEND_FETCH_CLASS_SELF) {
			if Z_TYPE(EX(This)) == IS_OBJECT {
				ce = Z_OBJCE(EX(This))
			} else {
				ce = Z_CE(EX(This))
			}
		}
		call_info = ZEND_CALL_NESTED_FUNCTION
	}
	call = ZendVmStackPushCallFrame(call_info, fbc, opline.GetExtendedValue(), ce)
	call.SetPrevExecuteData(EX(call))
	EX(call) = call
	ZEND_VM_NEXT_OPCODE()
}
