func ZEND_PRE_INC_OBJ_SPEC_VAR_TMPVAR_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var free_op1 ZendFreeOp
	var free_op2 ZendFreeOp
	var object *Zval
	var property *Zval
	var zptr *Zval
	var cache_slot *any
	var prop_info *ZendPropertyInfo
	object = _getZvalPtrPtrVar(opline.GetOp1().GetVar(), &free_op1, EXECUTE_DATA_C)
	if IS_VAR == IS_UNUSED && UNEXPECTED(Z_TYPE_P(object) == IS_UNDEF) {
		return zend_this_not_in_object_context_helper_SPEC(execute_data)
	}
	property = _getZvalPtrVar(opline.GetOp2().GetVar(), &free_op2, EXECUTE_DATA_C)
	for {
		if IS_VAR != IS_UNUSED && UNEXPECTED(Z_TYPE_P(object) != IS_OBJECT) {
			if Z_ISREF_P(object) && Z_TYPE_P(Z_REFVAL_P(object)) == IS_OBJECT {
				object = Z_REFVAL_P(object)
				goto pre_incdec_object
			}
			if IS_VAR == IS_CV && UNEXPECTED(Z_TYPE_P(object) == IS_UNDEF) {
				ZVAL_UNDEFINED_OP1()
			}
			object = MakeRealObject(object, property, OPLINE_C, EXECUTE_DATA_C)
			if UNEXPECTED(object == nil) {
				break
			}
		}
	pre_incdec_object:

		/* here we are sure we are dealing with an object */

		if (IS_TMP_VAR | IS_VAR) == IS_CONST {
			cache_slot = CACHE_ADDR(opline.GetExtendedValue())
		} else {
			cache_slot = nil
		}
		if EXPECTED(b.Assign(&zptr, Z_OBJ_HT_P(object).GetGetPropertyPtrPtr()(object, property, BP_VAR_RW, cache_slot)) != nil) {
			if UNEXPECTED(Z_ISERROR_P(zptr)) {
				if UNEXPECTED(RETURN_VALUE_USED(opline)) {
					ZVAL_NULL(EX_VAR(opline.GetResult().GetVar()))
				}
			} else {
				if (IS_TMP_VAR | IS_VAR) == IS_CONST {
					prop_info = (*ZendPropertyInfo)(CACHED_PTR_EX(cache_slot + 2))
				} else {
					prop_info = ZendObjectFetchPropertyTypeInfo(Z_OBJ_P(object), zptr)
				}
				ZendPreIncdecPropertyZval(zptr, prop_info, OPLINE_C, EXECUTE_DATA_C)
			}
		} else {
			ZendPreIncdecOverloadedProperty(object, property, cache_slot, OPLINE_C, EXECUTE_DATA_C)
		}
		break
	}
	ZvalPtrDtorNogc(free_op2)
	if UNEXPECTED(free_op1 != nil) {
		ZvalPtrDtorNogc(free_op1)
	}
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
