func ZEND_ASSIGN_SPEC_VAR_TMP_RETVAL_UNUSED_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var free_op1 ZendFreeOp
	var free_op2 ZendFreeOp
	var value *Zval
	var variable_ptr *Zval
	value = _getZvalPtrTmp(opline.GetOp2().GetVar(), &free_op2, EXECUTE_DATA_C)
	variable_ptr = _getZvalPtrPtrVar(opline.GetOp1().GetVar(), &free_op1, EXECUTE_DATA_C)
	if IS_VAR == IS_VAR && UNEXPECTED(Z_ISERROR_P(variable_ptr)) {
		ZvalPtrDtorNogc(free_op2)
		if UNEXPECTED(false) {
			ZVAL_NULL(EX_VAR(opline.GetResult().GetVar()))
		}
	} else {
		value = ZendAssignToVariable(variable_ptr, value, IS_TMP_VAR, EX_USES_STRICT_TYPES())
		if UNEXPECTED(false) {
			ZVAL_COPY(EX_VAR(opline.GetResult().GetVar()), value)
		}
		if UNEXPECTED(free_op1 != nil) {
			ZvalPtrDtorNogc(free_op1)
		}
	}
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_ASSIGN_SPEC_VAR_TMP_RETVAL_USED_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var free_op1 ZendFreeOp
	var free_op2 ZendFreeOp
	var value *Zval
	var variable_ptr *Zval
	value = _getZvalPtrTmp(opline.GetOp2().GetVar(), &free_op2, EXECUTE_DATA_C)
	variable_ptr = _getZvalPtrPtrVar(opline.GetOp1().GetVar(), &free_op1, EXECUTE_DATA_C)
	if IS_VAR == IS_VAR && UNEXPECTED(Z_ISERROR_P(variable_ptr)) {
		ZvalPtrDtorNogc(free_op2)
		if UNEXPECTED(true) {
			ZVAL_NULL(EX_VAR(opline.GetResult().GetVar()))
		}
	} else {
		value = ZendAssignToVariable(variable_ptr, value, IS_TMP_VAR, EX_USES_STRICT_TYPES())
		if UNEXPECTED(true) {
			ZVAL_COPY(EX_VAR(opline.GetResult().GetVar()), value)
		}
		if UNEXPECTED(free_op1 != nil) {
			ZvalPtrDtorNogc(free_op1)
		}
	}
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_YIELD_SPEC_VAR_TMP_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var generator *ZendGenerator = ZendGetRunningGenerator(EXECUTE_DATA_C)
	if UNEXPECTED(generator.IsForcedClose()) {
		return zend_yield_in_closed_generator_helper_SPEC(execute_data)
	}

	/* Destroy the previously yielded value */

	ZvalPtrDtor(&generator.value)

	/* Destroy the previously yielded key */

	ZvalPtrDtor(&generator.key)

	/* Set the new yielded value */

	if IS_VAR != IS_UNUSED {
		var free_op1 ZendFreeOp
		if UNEXPECTED((EX(func_).op_array.fn_flags & ZEND_ACC_RETURN_REFERENCE) != 0) {

			/* Constants and temporary variables aren't yieldable by reference,
			 * but we still allow them with a notice. */

			if (IS_VAR & (IS_CONST | IS_TMP_VAR)) != 0 {
				var value *Zval
				ZendError(E_NOTICE, "Only variable references should be yielded by reference")
				value = _getZvalPtrVar(opline.GetOp1().GetVar(), &free_op1, EXECUTE_DATA_C)
				ZVAL_COPY_VALUE(&generator.value, value)
				if IS_VAR == IS_CONST {
					if UNEXPECTED(Z_OPT_REFCOUNTED(generator.GetValue())) {
						Z_ADDREF(generator.GetValue())
					}
				}
			} else {
				var value_ptr *Zval = _getZvalPtrPtrVar(opline.GetOp1().GetVar(), &free_op1, EXECUTE_DATA_C)

				/* If a function call result is yielded and the function did
				 * not return by reference we throw a notice. */

				for {
					if IS_VAR == IS_VAR {
						ZEND_ASSERT(value_ptr != &(ExecutorGlobals.GetUninitializedZval()))
						if opline.GetExtendedValue() == ZEND_RETURNS_FUNCTION && !(Z_ISREF_P(value_ptr)) {
							ZendError(E_NOTICE, "Only variable references should be yielded by reference")
							ZVAL_COPY(&generator.value, value_ptr)
							break
						}
					}
					if Z_ISREF_P(value_ptr) {
						Z_ADDREF_P(value_ptr)
					} else {
						ZVAL_MAKE_REF_EX(value_ptr, 2)
					}
					ZVAL_REF(&generator.value, Z_REF_P(value_ptr))
					break
				}
				if UNEXPECTED(free_op1 != nil) {
					ZvalPtrDtorNogc(free_op1)
				}
			}

			/* Constants and temporary variables aren't yieldable by reference,
			 * but we still allow them with a notice. */

		} else {
			var value *Zval = _getZvalPtrVar(opline.GetOp1().GetVar(), &free_op1, EXECUTE_DATA_C)

			/* Consts, temporary variables and references need copying */

			if IS_VAR == IS_CONST {
				ZVAL_COPY_VALUE(&generator.value, value)
				if UNEXPECTED(Z_OPT_REFCOUNTED(generator.GetValue())) {
					Z_ADDREF(generator.GetValue())
				}
			} else if IS_VAR == IS_TMP_VAR {
				ZVAL_COPY_VALUE(&generator.value, value)
			} else if (IS_VAR&(IS_VAR|IS_CV)) != 0 && Z_ISREF_P(value) {
				ZVAL_COPY(&generator.value, Z_REFVAL_P(value))
				ZvalPtrDtorNogc(free_op1)
			} else {
				ZVAL_COPY_VALUE(&generator.value, value)
				if IS_VAR == IS_CV {
					if Z_OPT_REFCOUNTED_P(value) {
						Z_ADDREF_P(value)
					}
				}
			}

			/* Consts, temporary variables and references need copying */

		}
	} else {

		/* If no value was specified yield null */

		ZVAL_NULL(&generator.value)

		/* If no value was specified yield null */

	}

	/* Set the new yielded key */

	if IS_TMP_VAR != IS_UNUSED {
		var free_op2 ZendFreeOp
		var key *Zval = _getZvalPtrTmp(opline.GetOp2().GetVar(), &free_op2, EXECUTE_DATA_C)

		/* Consts, temporary variables and references need copying */

		if IS_TMP_VAR == IS_CONST {
			ZVAL_COPY_VALUE(&generator.key, key)
			if UNEXPECTED(Z_OPT_REFCOUNTED(generator.GetKey())) {
				Z_ADDREF(generator.GetKey())
			}
		} else if IS_TMP_VAR == IS_TMP_VAR {
			ZVAL_COPY_VALUE(&generator.key, key)
		} else if (IS_TMP_VAR&(IS_VAR|IS_CV)) != 0 && Z_ISREF_P(key) {
			ZVAL_COPY(&generator.key, Z_REFVAL_P(key))
		} else {
			ZVAL_COPY_VALUE(&generator.key, key)
			if IS_TMP_VAR == IS_CV {
				if Z_OPT_REFCOUNTED_P(key) {
					Z_ADDREF_P(key)
				}
			}
		}
		if Z_TYPE(generator.GetKey()) == IS_LONG && Z_LVAL(generator.GetKey()) > generator.GetLargestUsedIntegerKey() {
			generator.SetLargestUsedIntegerKey(Z_LVAL(generator.GetKey()))
		}
	} else {

		/* If no key was specified we use auto-increment keys */

		generator.GetLargestUsedIntegerKey()++
		ZVAL_LONG(&generator.key, generator.GetLargestUsedIntegerKey())
	}
	if RETURN_VALUE_USED(opline) {

		/* If the return value of yield is used set the send
		 * target and initialize it to NULL */

		generator.SetSendTarget(EX_VAR(opline.GetResult().GetVar()))
		ZVAL_NULL(generator.GetSendTarget())
	} else {
		generator.SetSendTarget(nil)
	}

	/* We increment to the next op, so we are at the correct position when the
	 * generator is resumed. */

	ZEND_VM_INC_OPCODE()

	/* The GOTO VM uses a local opline variable. We need to set the opline
	 * variable in execute_data so we don't resume at an old position. */

	return -1
}
