	op1 = _getZvalPtrVarDeref(opline.GetOp1().GetVar(), &free_op1, EXECUTE_DATA_C)
	op2 = _getZvalPtrVarDeref(opline.GetOp2().GetVar(), &free_op2, EXECUTE_DATA_C)
