func ZEND_INIT_STATIC_METHOD_CALL_SPEC_VAR_CV_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var function_name *Zval
	var ce *ZendClassEntry
	var call_info uint32
	var fbc *ZendFunction
	var call *ZendExecuteData
	if IS_VAR == IS_CONST {

		/* no function found. try a static method in class */

		ce = CACHED_PTR(opline.GetResult().GetNum())
		if UNEXPECTED(ce == nil) {
			ce = ZendFetchClassByName(Z_STR_P(RT_CONSTANT(opline, opline.GetOp1())), Z_STR_P(RT_CONSTANT(opline, opline.GetOp1())+1), ZEND_FETCH_CLASS_DEFAULT|ZEND_FETCH_CLASS_EXCEPTION)
			if UNEXPECTED(ce == nil) {
				ZEND_ASSERT(ExecutorGlobals.GetException() != nil)
				HANDLE_EXCEPTION()
			}
			if IS_CV != IS_CONST {
				CACHE_PTR(opline.GetResult().GetNum(), ce)
			}
		}
	} else if IS_VAR == IS_UNUSED {
		ce = ZendFetchClass(nil, opline.GetOp1().GetNum())
		if UNEXPECTED(ce == nil) {
			ZEND_ASSERT(ExecutorGlobals.GetException() != nil)
			HANDLE_EXCEPTION()
		}
	} else {
		ce = Z_CE_P(EX_VAR(opline.GetOp1().GetVar()))
	}
	if IS_VAR == IS_CONST && IS_CV == IS_CONST && EXPECTED(b.Assign(&fbc, CACHED_PTR(opline.GetResult().GetNum()+b.SizeOf("void *"))) != nil) {

	} else if IS_VAR != IS_CONST && IS_CV == IS_CONST && EXPECTED(CACHED_PTR(opline.GetResult().GetNum()) == ce) {
		fbc = CACHED_PTR(opline.GetResult().GetNum() + b.SizeOf("void *"))
	} else if IS_CV != IS_UNUSED {
		function_name = EX_VAR(opline.GetOp2().GetVar())
		if IS_CV != IS_CONST {
			if UNEXPECTED(Z_TYPE_P(function_name) != IS_STRING) {
				for {
					if (IS_CV&(IS_VAR|IS_CV)) != 0 && Z_ISREF_P(function_name) {
						function_name = Z_REFVAL_P(function_name)
						if EXPECTED(Z_TYPE_P(function_name) == IS_STRING) {
							break
						}
					} else if IS_CV == IS_CV && UNEXPECTED(Z_TYPE_P(function_name) == IS_UNDEF) {
						ZVAL_UNDEFINED_OP2()
						if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
							HANDLE_EXCEPTION()
						}
					}
					ZendThrowError(nil, "Function name must be a string")
					HANDLE_EXCEPTION()
					break
				}
			}
		}
		if ce.GetGetStaticMethod() != nil {
			fbc = ce.GetGetStaticMethod()(ce, Z_STR_P(function_name))
		} else {
			fbc = ZendStdGetStaticMethod(ce, Z_STR_P(function_name), b.CondF1(IS_CV == IS_CONST, func() *Zval { return RT_CONSTANT(opline, opline.GetOp2()) + 1 }, nil))
		}
		if UNEXPECTED(fbc == nil) {
			if EXPECTED(ExecutorGlobals.GetException() == nil) {
				ZendUndefinedMethod(ce, Z_STR_P(function_name))
			}
			HANDLE_EXCEPTION()
		}
		if IS_CV == IS_CONST && EXPECTED(fbc.GetType() <= ZEND_USER_FUNCTION) && EXPECTED(!fbc.HasFnFlags(ZEND_ACC_CALL_VIA_TRAMPOLINE|ZEND_ACC_NEVER_CACHE)) {
			CACHE_POLYMORPHIC_PTR(opline.GetResult().GetNum(), ce, fbc)
		}
		if EXPECTED(fbc.GetType() == ZEND_USER_FUNCTION) && UNEXPECTED(!(RUN_TIME_CACHE(&fbc.op_array))) {
			InitFuncRunTimeCache(&fbc.op_array)
		}
		if IS_CV != IS_CONST {

		}
	} else {
		if UNEXPECTED(ce.GetConstructor() == nil) {
			ZendThrowError(nil, "Cannot call constructor")
			HANDLE_EXCEPTION()
		}
		if Z_TYPE(EX(This)) == IS_OBJECT && Z_OBJ(EX(This)).GetCe() != ce.GetConstructor().GetScope() && ce.GetConstructor().IsPrivate() {
			ZendThrowError(nil, "Cannot call private %s::__construct()", ZSTR_VAL(ce.GetName()))
			HANDLE_EXCEPTION()
		}
		fbc = ce.GetConstructor()
		if EXPECTED(fbc.GetType() == ZEND_USER_FUNCTION) && UNEXPECTED(!(RUN_TIME_CACHE(&fbc.op_array))) {
			InitFuncRunTimeCache(&fbc.op_array)
		}
	}
	if !fbc.IsStatic() {
		if Z_TYPE(EX(This)) == IS_OBJECT && InstanceofFunction(Z_OBJCE(EX(This)), ce) != 0 {
			ce = (*ZendClassEntry)(Z_OBJ(EX(This)))
			call_info = ZEND_CALL_NESTED_FUNCTION | ZEND_CALL_HAS_THIS
		} else {
			ZendNonStaticMethodCall(fbc)
			if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
				HANDLE_EXCEPTION()
			}
			goto check_parent_and_self
		}
	} else {
	check_parent_and_self:

		/* previous opcode is ZEND_FETCH_CLASS */

		if IS_VAR == IS_UNUSED && ((opline.GetOp1().GetNum()&ZEND_FETCH_CLASS_MASK) == ZEND_FETCH_CLASS_PARENT || (opline.GetOp1().GetNum()&ZEND_FETCH_CLASS_MASK) == ZEND_FETCH_CLASS_SELF) {
			if Z_TYPE(EX(This)) == IS_OBJECT {
				ce = Z_OBJCE(EX(This))
			} else {
				ce = Z_CE(EX(This))
			}
		}
		call_info = ZEND_CALL_NESTED_FUNCTION
	}
	call = ZendVmStackPushCallFrame(call_info, fbc, opline.GetExtendedValue(), ce)
	call.SetPrevExecuteData(EX(call))
	EX(call) = call
	ZEND_VM_NEXT_OPCODE()
}
func ZEND_ADD_ARRAY_ELEMENT_SPEC_VAR_CV_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var free_op1 ZendFreeOp
	var expr_ptr *Zval
	var new_expr Zval
	if (IS_VAR == IS_VAR || IS_VAR == IS_CV) && UNEXPECTED((opline.GetExtendedValue()&ZEND_ARRAY_ELEMENT_REF) != 0) {
		expr_ptr = _getZvalPtrPtrVar(opline.GetOp1().GetVar(), &free_op1, EXECUTE_DATA_C)
		if Z_ISREF_P(expr_ptr) {
			Z_ADDREF_P(expr_ptr)
		} else {
			ZVAL_MAKE_REF_EX(expr_ptr, 2)
		}
		if UNEXPECTED(free_op1 != nil) {
			ZvalPtrDtorNogc(free_op1)
		}
	} else {
		expr_ptr = _getZvalPtrVar(opline.GetOp1().GetVar(), &free_op1, EXECUTE_DATA_C)
		if IS_VAR == IS_TMP_VAR {

		} else if IS_VAR == IS_CONST {
			Z_TRY_ADDREF_P(expr_ptr)
		} else if IS_VAR == IS_CV {
			ZVAL_DEREF(expr_ptr)
			Z_TRY_ADDREF_P(expr_ptr)
		} else {
			if UNEXPECTED(Z_ISREF_P(expr_ptr)) {
				var ref *ZendRefcounted = Z_COUNTED_P(expr_ptr)
				expr_ptr = Z_REFVAL_P(expr_ptr)
				if UNEXPECTED(GC_DELREF(ref) == 0) {
					ZVAL_COPY_VALUE(&new_expr, expr_ptr)
					expr_ptr = &new_expr
					EfreeSize(ref, b.SizeOf("zend_reference"))
				} else if Z_OPT_REFCOUNTED_P(expr_ptr) {
					Z_ADDREF_P(expr_ptr)
				}
			}
		}
	}
	if IS_CV != IS_UNUSED {
		var offset *Zval = EX_VAR(opline.GetOp2().GetVar())
		var str *ZendString
		var hval ZendUlong
	add_again:
		if EXPECTED(Z_TYPE_P(offset) == IS_STRING) {
			str = Z_STR_P(offset)
			if IS_CV != IS_CONST {
				if ZEND_HANDLE_NUMERIC(str, hval) != 0 {
					goto num_index
				}
			}
		str_index:
			Z_ARRVAL_P(EX_VAR(opline.GetResult().GetVar())).Update(str, expr_ptr)
		} else if EXPECTED(Z_TYPE_P(offset) == IS_LONG) {
			hval = Z_LVAL_P(offset)
		num_index:
			Z_ARRVAL_P(EX_VAR(opline.GetResult().GetVar())).IndexUpdate(hval, expr_ptr)
		} else if (IS_CV&(IS_VAR|IS_CV)) != 0 && EXPECTED(Z_TYPE_P(offset) == IS_REFERENCE) {
			offset = Z_REFVAL_P(offset)
			goto add_again
		} else if Z_TYPE_P(offset) == IS_NULL {
			str = ZSTR_EMPTY_ALLOC()
			goto str_index
		} else if Z_TYPE_P(offset) == IS_DOUBLE {
			hval = ZendDvalToLval(Z_DVAL_P(offset))
			goto num_index
		} else if Z_TYPE_P(offset) == IS_FALSE {
			hval = 0
			goto num_index
		} else if Z_TYPE_P(offset) == IS_TRUE {
			hval = 1
			goto num_index
		} else if Z_TYPE_P(offset) == IS_RESOURCE {
			ZendUseResourceAsOffset(offset)
			hval = Z_RES_HANDLE_P(offset)
			goto num_index
		} else if IS_CV == IS_CV && Z_TYPE_P(offset) == IS_UNDEF {
			ZVAL_UNDEFINED_OP2()
			str = ZSTR_EMPTY_ALLOC()
			goto str_index
		} else {
			ZendIllegalOffset()
			ZvalPtrDtorNogc(expr_ptr)
		}
	} else {
		if Z_ARRVAL_P(EX_VAR(opline.GetResult().GetVar())).NextIndexInsert(expr_ptr) == nil {
			ZendCannotAddElement()
			ZvalPtrDtorNogc(expr_ptr)
		}
	}
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_INIT_ARRAY_SPEC_VAR_CV_HANDLER(execute_data *ZendExecuteData) int {
	var array *Zval
	var size uint32
	var opline *ZendOp = EX(opline)
	array = EX_VAR(opline.GetResult().GetVar())
	if IS_VAR != IS_UNUSED {
		size = opline.GetExtendedValue() >> ZEND_ARRAY_SIZE_SHIFT
		ZVAL_ARR(array, ZendNewArray(size))

		/* Explicitly initialize array as not-packed if flag is set */

		if (opline.GetExtendedValue() & ZEND_ARRAY_NOT_PACKED) != 0 {
			Z_ARRVAL_P(array).RealInitMixed()
		}
		return ZEND_ADD_ARRAY_ELEMENT_SPEC_VAR_CV_HANDLER(execute_data)
	} else {
		ZVAL_ARR(array, ZendNewArray(0))
		ZEND_VM_NEXT_OPCODE()
	}
}
func ZEND_UNSET_DIM_SPEC_VAR_CV_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var free_op1 ZendFreeOp
	var container *Zval
	var offset *Zval
	var hval ZendUlong
	var key *ZendString
	container = _getZvalPtrPtrVar(opline.GetOp1().GetVar(), &free_op1, EXECUTE_DATA_C)
	offset = EX_VAR(opline.GetOp2().GetVar())
	for {
		if EXPECTED(Z_TYPE_P(container) == IS_ARRAY) {
			var ht *HashTable
		unset_dim_array:
			SEPARATE_ARRAY(container)
			ht = Z_ARRVAL_P(container)
		offset_again:
			if EXPECTED(Z_TYPE_P(offset) == IS_STRING) {
				key = Z_STR_P(offset)
				if IS_CV != IS_CONST {
					if ZEND_HANDLE_NUMERIC(key, hval) != 0 {
						goto num_index_dim
					}
				}
			str_index_dim:
				if ht == &(ExecutorGlobals.GetSymbolTable()) {
					ZendDeleteGlobalVariable(key)
				} else {
					ht.Del(key)
				}
			} else if EXPECTED(Z_TYPE_P(offset) == IS_LONG) {
				hval = Z_LVAL_P(offset)
			num_index_dim:
				ht.IndexDel(hval)
			} else if (IS_CV&(IS_VAR|IS_CV)) != 0 && EXPECTED(Z_TYPE_P(offset) == IS_REFERENCE) {
				offset = Z_REFVAL_P(offset)
				goto offset_again
			} else if Z_TYPE_P(offset) == IS_DOUBLE {
				hval = ZendDvalToLval(Z_DVAL_P(offset))
				goto num_index_dim
			} else if Z_TYPE_P(offset) == IS_NULL {
				key = ZSTR_EMPTY_ALLOC()
				goto str_index_dim
			} else if Z_TYPE_P(offset) == IS_FALSE {
				hval = 0
				goto num_index_dim
			} else if Z_TYPE_P(offset) == IS_TRUE {
				hval = 1
				goto num_index_dim
			} else if Z_TYPE_P(offset) == IS_RESOURCE {
				hval = Z_RES_HANDLE_P(offset)
				goto num_index_dim
			} else if IS_CV == IS_CV && Z_TYPE_P(offset) == IS_UNDEF {
				ZVAL_UNDEFINED_OP2()
				key = ZSTR_EMPTY_ALLOC()
				goto str_index_dim
			} else {
				ZendError(E_WARNING, "Illegal offset type in unset")
			}
			break
		} else if Z_ISREF_P(container) {
			container = Z_REFVAL_P(container)
			if EXPECTED(Z_TYPE_P(container) == IS_ARRAY) {
				goto unset_dim_array
			}
		}
		if IS_VAR == IS_CV && UNEXPECTED(Z_TYPE_P(container) == IS_UNDEF) {
			container = ZVAL_UNDEFINED_OP1()
		}
		if IS_CV == IS_CV && UNEXPECTED(Z_TYPE_P(offset) == IS_UNDEF) {
			offset = ZVAL_UNDEFINED_OP2()
		}
		if EXPECTED(Z_TYPE_P(container) == IS_OBJECT) {
			if IS_CV == IS_CONST && Z_EXTRA_P(offset) == ZEND_EXTRA_VALUE {
				offset++
			}
			Z_OBJ_HT_P(container).GetUnsetDimension()(container, offset)
		} else if IS_VAR != IS_UNUSED && UNEXPECTED(Z_TYPE_P(container) == IS_STRING) {
			ZendThrowError(nil, "Cannot unset string offsets")
		}
		break
	}
	if UNEXPECTED(free_op1 != nil) {
		ZvalPtrDtorNogc(free_op1)
	}
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_UNSET_OBJ_SPEC_VAR_CV_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var free_op1 ZendFreeOp
	var container *Zval
	var offset *Zval
	container = _getZvalPtrPtrVar(opline.GetOp1().GetVar(), &free_op1, EXECUTE_DATA_C)
	if IS_VAR == IS_UNUSED && UNEXPECTED(Z_TYPE_P(container) == IS_UNDEF) {
		return zend_this_not_in_object_context_helper_SPEC(execute_data)
	}
	offset = _get_zval_ptr_cv_BP_VAR_R(opline.GetOp2().GetVar(), EXECUTE_DATA_C)
	for {
		if IS_VAR != IS_UNUSED && UNEXPECTED(Z_TYPE_P(container) != IS_OBJECT) {
			if Z_ISREF_P(container) {
				container = Z_REFVAL_P(container)
				if Z_TYPE_P(container) != IS_OBJECT {
					if IS_VAR == IS_CV && UNEXPECTED(Z_TYPE_P(container) == IS_UNDEF) {
						ZVAL_UNDEFINED_OP1()
					}
					break
				}
			} else {
				break
			}
		}
		Z_OBJ_HT_P(container).GetUnsetProperty()(container, offset, b.CondF1(IS_CV == IS_CONST, func() *any { return CACHE_ADDR(opline.GetExtendedValue()) }, nil))
		break
	}
	if UNEXPECTED(free_op1 != nil) {
		ZvalPtrDtorNogc(free_op1)
	}
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_YIELD_SPEC_VAR_CV_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var generator *ZendGenerator = ZendGetRunningGenerator(EXECUTE_DATA_C)
	if UNEXPECTED(generator.IsForcedClose()) {
		return zend_yield_in_closed_generator_helper_SPEC(execute_data)
	}

	/* Destroy the previously yielded value */

	ZvalPtrDtor(&generator.value)

	/* Destroy the previously yielded key */

	ZvalPtrDtor(&generator.key)

	/* Set the new yielded value */

	if IS_VAR != IS_UNUSED {
		var free_op1 ZendFreeOp
		if UNEXPECTED((EX(func_).op_array.fn_flags & ZEND_ACC_RETURN_REFERENCE) != 0) {

			/* Constants and temporary variables aren't yieldable by reference,
			 * but we still allow them with a notice. */

			if (IS_VAR & (IS_CONST | IS_TMP_VAR)) != 0 {
				var value *Zval
				ZendError(E_NOTICE, "Only variable references should be yielded by reference")
				value = _getZvalPtrVar(opline.GetOp1().GetVar(), &free_op1, EXECUTE_DATA_C)
				ZVAL_COPY_VALUE(&generator.value, value)
				if IS_VAR == IS_CONST {
					if UNEXPECTED(Z_OPT_REFCOUNTED(generator.GetValue())) {
						Z_ADDREF(generator.GetValue())
					}
				}
			} else {
				var value_ptr *Zval = _getZvalPtrPtrVar(opline.GetOp1().GetVar(), &free_op1, EXECUTE_DATA_C)

				/* If a function call result is yielded and the function did
				 * not return by reference we throw a notice. */

				for {
					if IS_VAR == IS_VAR {
						ZEND_ASSERT(value_ptr != &(ExecutorGlobals.GetUninitializedZval()))
						if opline.GetExtendedValue() == ZEND_RETURNS_FUNCTION && !(Z_ISREF_P(value_ptr)) {
							ZendError(E_NOTICE, "Only variable references should be yielded by reference")
							ZVAL_COPY(&generator.value, value_ptr)
							break
						}
					}
					if Z_ISREF_P(value_ptr) {
						Z_ADDREF_P(value_ptr)
					} else {
						ZVAL_MAKE_REF_EX(value_ptr, 2)
					}
					ZVAL_REF(&generator.value, Z_REF_P(value_ptr))
					break
				}
				if UNEXPECTED(free_op1 != nil) {
					ZvalPtrDtorNogc(free_op1)
				}
			}

			/* Constants and temporary variables aren't yieldable by reference,
			 * but we still allow them with a notice. */

		} else {
			var value *Zval = _getZvalPtrVar(opline.GetOp1().GetVar(), &free_op1, EXECUTE_DATA_C)

			/* Consts, temporary variables and references need copying */

			if IS_VAR == IS_CONST {
				ZVAL_COPY_VALUE(&generator.value, value)
				if UNEXPECTED(Z_OPT_REFCOUNTED(generator.GetValue())) {
					Z_ADDREF(generator.GetValue())
				}
			} else if IS_VAR == IS_TMP_VAR {
				ZVAL_COPY_VALUE(&generator.value, value)
			} else if (IS_VAR&(IS_VAR|IS_CV)) != 0 && Z_ISREF_P(value) {
				ZVAL_COPY(&generator.value, Z_REFVAL_P(value))
				ZvalPtrDtorNogc(free_op1)
			} else {
				ZVAL_COPY_VALUE(&generator.value, value)
				if IS_VAR == IS_CV {
					if Z_OPT_REFCOUNTED_P(value) {
						Z_ADDREF_P(value)
					}
				}
			}

			/* Consts, temporary variables and references need copying */

		}
	} else {

		/* If no value was specified yield null */

		ZVAL_NULL(&generator.value)

		/* If no value was specified yield null */

	}

	/* Set the new yielded key */

	if IS_CV != IS_UNUSED {
		var key *Zval = _get_zval_ptr_cv_BP_VAR_R(opline.GetOp2().GetVar(), EXECUTE_DATA_C)

		/* Consts, temporary variables and references need copying */

		if IS_CV == IS_CONST {
			ZVAL_COPY_VALUE(&generator.key, key)
			if UNEXPECTED(Z_OPT_REFCOUNTED(generator.GetKey())) {
				Z_ADDREF(generator.GetKey())
			}
		} else if IS_CV == IS_TMP_VAR {
			ZVAL_COPY_VALUE(&generator.key, key)
		} else if (IS_CV&(IS_VAR|IS_CV)) != 0 && Z_ISREF_P(key) {
			ZVAL_COPY(&generator.key, Z_REFVAL_P(key))
		} else {
			ZVAL_COPY_VALUE(&generator.key, key)
			if IS_CV == IS_CV {
				if Z_OPT_REFCOUNTED_P(key) {
					Z_ADDREF_P(key)
				}
			}
		}
		if Z_TYPE(generator.GetKey()) == IS_LONG && Z_LVAL(generator.GetKey()) > generator.GetLargestUsedIntegerKey() {
			generator.SetLargestUsedIntegerKey(Z_LVAL(generator.GetKey()))
		}
	} else {

		/* If no key was specified we use auto-increment keys */

		generator.GetLargestUsedIntegerKey()++
		ZVAL_LONG(&generator.key, generator.GetLargestUsedIntegerKey())
	}
	if RETURN_VALUE_USED(opline) {

		/* If the return value of yield is used set the send
		 * target and initialize it to NULL */

		generator.SetSendTarget(EX_VAR(opline.GetResult().GetVar()))
		ZVAL_NULL(generator.GetSendTarget())
	} else {
		generator.SetSendTarget(nil)
	}

	/* We increment to the next op, so we are at the correct position when the
	 * generator is resumed. */

	ZEND_VM_INC_OPCODE()

	/* The GOTO VM uses a local opline variable. We need to set the opline
	 * variable in execute_data so we don't resume at an old position. */

	return -1
}
func ZEND_FE_FETCH_R_SIMPLE_SPEC_VAR_CV_RETVAL_UNUSED_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var array *Zval
	var value *Zval
	var variable_ptr *Zval
	var value_type uint32
	var fe_ht *HashTable
	var pos HashPosition
	var p *Bucket
	array = EX_VAR(opline.GetOp1().GetVar())
	fe_ht = Z_ARRVAL_P(array)
	pos = Z_FE_POS_P(array)
	p = fe_ht.GetArData() + pos
	for true {
		if UNEXPECTED(pos >= fe_ht.GetNNumUsed()) {

			/* reached end of iteration */

			ZEND_VM_SET_RELATIVE_OPCODE(opline, opline.GetExtendedValue())
			return 0
		}
		value = &p.val
		value_type = Z_TYPE_INFO_P(value)
		if EXPECTED(value_type != IS_UNDEF) {
			if UNEXPECTED(value_type == IS_INDIRECT) {
				value = Z_INDIRECT_P(value)
				value_type = Z_TYPE_INFO_P(value)
				if EXPECTED(value_type != IS_UNDEF) {
					break
				}
			} else {
				break
			}
		}
		pos++
		p++
	}
	Z_FE_POS_P(array) = pos + 1

	variable_ptr = EX_VAR(opline.GetOp2().GetVar())
	ZendAssignToVariable(variable_ptr, value, IS_CV, EX_USES_STRICT_TYPES())
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
