func ZEND_CLONE_SPEC_UNUSED_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var obj *Zval
	var ce *ZendClassEntry
	var scope *ZendClassEntry
	var clone *ZendFunction
	var clone_call ZendObjectCloneObjT
	obj = &EX(This)
	if IS_UNUSED == IS_UNUSED && UNEXPECTED(Z_TYPE_P(obj) == IS_UNDEF) {
		return zend_this_not_in_object_context_helper_SPEC(execute_data)
	}
	for {
		if IS_UNUSED == IS_CONST || IS_UNUSED != IS_UNUSED && UNEXPECTED(Z_TYPE_P(obj) != IS_OBJECT) {
			if (IS_UNUSED&(IS_VAR|IS_CV)) != 0 && Z_ISREF_P(obj) {
				obj = Z_REFVAL_P(obj)
				if EXPECTED(Z_TYPE_P(obj) == IS_OBJECT) {
					break
				}
			}
			ZVAL_UNDEF(EX_VAR(opline.GetResult().GetVar()))
			if IS_UNUSED == IS_CV && UNEXPECTED(Z_TYPE_P(obj) == IS_UNDEF) {
				ZVAL_UNDEFINED_OP1()
				if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
					HANDLE_EXCEPTION()
				}
			}
			ZendThrowError(nil, "__clone method called on non-object")
			HANDLE_EXCEPTION()
		}
		break
	}
	ce = Z_OBJCE_P(obj)
	clone = ce.GetClone()
	clone_call = Z_OBJ_HT_P(obj).GetCloneObj()
	if UNEXPECTED(clone_call == nil) {
		ZendThrowError(nil, "Trying to clone an uncloneable object of class %s", ZSTR_VAL(ce.GetName()))
		ZVAL_UNDEF(EX_VAR(opline.GetResult().GetVar()))
		HANDLE_EXCEPTION()
	}
	if clone != nil && !clone.IsPublic() {
		scope = EX(func_).op_array.scope
		if clone.GetScope() != scope {
			if UNEXPECTED(clone.IsPrivate()) || UNEXPECTED(ZendCheckProtected(ZendGetFunctionRootClass(clone), scope) == 0) {
				ZendWrongCloneCall(clone, scope)
				ZVAL_UNDEF(EX_VAR(opline.GetResult().GetVar()))
				HANDLE_EXCEPTION()
			}
		}
	}
	ZVAL_OBJ(EX_VAR(opline.GetResult().GetVar()), clone_call(obj))
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_FETCH_CLASS_NAME_SPEC_UNUSED_HANDLER(execute_data *ZendExecuteData) int {
	var fetch_type uint32
	var called_scope *ZendClassEntry
	var scope *ZendClassEntry
	var opline *ZendOp = EX(opline)
	fetch_type = opline.GetOp1().GetNum()
	scope = EX(func_).op_array.scope
	if UNEXPECTED(scope == nil) {
		ZendThrowError(nil, "Cannot use \"%s\" when no class scope is active", b.Cond(b.Cond(fetch_type == ZEND_FETCH_CLASS_SELF, "self", fetch_type == ZEND_FETCH_CLASS_PARENT), "parent", "static"))
		ZVAL_UNDEF(EX_VAR(opline.GetResult().GetVar()))
		HANDLE_EXCEPTION()
	}
	switch fetch_type {
	case ZEND_FETCH_CLASS_SELF:
		ZVAL_STR_COPY(EX_VAR(opline.GetResult().GetVar()), scope.GetName())
		break
	case ZEND_FETCH_CLASS_PARENT:
		if UNEXPECTED(scope.parent == nil) {
			ZendThrowError(nil, "Cannot use \"parent\" when current class scope has no parent")
			ZVAL_UNDEF(EX_VAR(opline.GetResult().GetVar()))
			HANDLE_EXCEPTION()
		}
		ZVAL_STR_COPY(EX_VAR(opline.GetResult().GetVar()), scope.parent.name)
		break
	case ZEND_FETCH_CLASS_STATIC:
		if Z_TYPE(EX(This)) == IS_OBJECT {
			called_scope = Z_OBJCE(EX(This))
		} else {
			called_scope = Z_CE(EX(This))
		}
		ZVAL_STR_COPY(EX_VAR(opline.GetResult().GetVar()), called_scope.GetName())
		break
	default:
		break
	}
	ZEND_VM_NEXT_OPCODE()
}
func ZEND_ASSIGN_OBJ_OP_SPEC_UNUSED_CONST_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var free_op_data ZendFreeOp
	var object *Zval
	var property *Zval
	var value *Zval
	var zptr *Zval
	var cache_slot *any
	var prop_info *ZendPropertyInfo
	object = &EX(This)
	if IS_UNUSED == IS_UNUSED && UNEXPECTED(Z_TYPE_P(object) == IS_UNDEF) {
		return zend_this_not_in_object_context_helper_SPEC(execute_data)
	}
	property = RT_CONSTANT(opline, opline.GetOp2())
	for {
		value = GetOpDataZvalPtrR((opline + 1).GetOp1Type(), (opline + 1).GetOp1(), &free_op_data)
		if IS_UNUSED != IS_UNUSED && UNEXPECTED(Z_TYPE_P(object) != IS_OBJECT) {
			if Z_ISREF_P(object) && Z_TYPE_P(Z_REFVAL_P(object)) == IS_OBJECT {
				object = Z_REFVAL_P(object)
				goto assign_op_object
			}
			if IS_UNUSED == IS_CV && UNEXPECTED(Z_TYPE_P(object) == IS_UNDEF) {
				ZVAL_UNDEFINED_OP1()
			}
			object = MakeRealObject(object, property, OPLINE_C, EXECUTE_DATA_C)
			if UNEXPECTED(object == nil) {
				break
			}
		}
	assign_op_object:

		/* here we are sure we are dealing with an object */

		if IS_CONST == IS_CONST {
			cache_slot = CACHE_ADDR((opline + 1).GetExtendedValue())
		} else {
			cache_slot = nil
		}
		if EXPECTED(b.Assign(&zptr, Z_OBJ_HT_P(object).GetGetPropertyPtrPtr()(object, property, BP_VAR_RW, cache_slot)) != nil) {
			if UNEXPECTED(Z_ISERROR_P(zptr)) {
				if UNEXPECTED(RETURN_VALUE_USED(opline)) {
					ZVAL_NULL(EX_VAR(opline.GetResult().GetVar()))
				}
			} else {
				var orig_zptr *Zval = zptr
				var ref *ZendReference
				for {
					if UNEXPECTED(Z_ISREF_P(zptr)) {
						ref = Z_REF_P(zptr)
						zptr = Z_REFVAL_P(zptr)
						if UNEXPECTED(ZEND_REF_HAS_TYPE_SOURCES(ref)) {
							ZendBinaryAssignOpTypedRef(ref, value, OPLINE_C, EXECUTE_DATA_C)
							break
						}
					}
					if IS_CONST == IS_CONST {
						prop_info = (*ZendPropertyInfo)(CACHED_PTR_EX(cache_slot + 2))
					} else {
						prop_info = ZendObjectFetchPropertyTypeInfo(Z_OBJ_P(object), orig_zptr)
					}
					if UNEXPECTED(prop_info != nil) {

						/* special case for typed properties */

						ZendBinaryAssignOpTypedProp(prop_info, zptr, value, OPLINE_C, EXECUTE_DATA_C)

						/* special case for typed properties */

					} else {
						ZendBinaryOp(zptr, zptr, value, OPLINE_C)
					}
					break
				}
				if UNEXPECTED(RETURN_VALUE_USED(opline)) {
					ZVAL_COPY(EX_VAR(opline.GetResult().GetVar()), zptr)
				}
			}
		} else {
			ZendAssignOpOverloadedProperty(object, property, cache_slot, value, OPLINE_C, EXECUTE_DATA_C)
		}
		break
	}
	FREE_OP(free_op_data)

	/* assign_obj has two opcodes! */

	OPLINE = EX(opline) + 2
	return 0
}
