func ZEND_NEW_SPEC_UNUSED_UNUSED_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var result *Zval
	var constructor *ZendFunction
	var ce *ZendClassEntry
	var call *ZendExecuteData
	if IS_UNUSED == IS_CONST {
		ce = CACHED_PTR(opline.GetOp2().GetNum())
		if UNEXPECTED(ce == nil) {
			ce = ZendFetchClassByName(Z_STR_P(RT_CONSTANT(opline, opline.GetOp1())), Z_STR_P(RT_CONSTANT(opline, opline.GetOp1())+1), ZEND_FETCH_CLASS_DEFAULT|ZEND_FETCH_CLASS_EXCEPTION)
			if UNEXPECTED(ce == nil) {
				ZEND_ASSERT(ExecutorGlobals.GetException() != nil)
				ZVAL_UNDEF(EX_VAR(opline.GetResult().GetVar()))
				HANDLE_EXCEPTION()
			}
			CACHE_PTR(opline.GetOp2().GetNum(), ce)
		}
	} else if IS_UNUSED == IS_UNUSED {
		ce = ZendFetchClass(nil, opline.GetOp1().GetNum())
		if UNEXPECTED(ce == nil) {
			ZEND_ASSERT(ExecutorGlobals.GetException() != nil)
			ZVAL_UNDEF(EX_VAR(opline.GetResult().GetVar()))
			HANDLE_EXCEPTION()
		}
	} else {
		ce = Z_CE_P(EX_VAR(opline.GetOp1().GetVar()))
	}
	result = EX_VAR(opline.GetResult().GetVar())
	if UNEXPECTED(ObjectInitEx(result, ce) != SUCCESS) {
		ZVAL_UNDEF(result)
		HANDLE_EXCEPTION()
	}
	constructor = Z_OBJ_HT_P(result).GetGetConstructor()(Z_OBJ_P(result))
	if constructor == nil {
		if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
			HANDLE_EXCEPTION()
		}

		/* If there are no arguments, skip over the DO_FCALL opcode. We check if the next
		 * opcode is DO_FCALL in case EXT instructions are used. */

		if EXPECTED(opline.GetExtendedValue() == 0 && (opline+1).GetOpcode() == ZEND_DO_FCALL) {
			OPLINE = EX(opline) + 2
			return 0
		}

		/* Perform a dummy function call */

		call = ZendVmStackPushCallFrame(ZEND_CALL_FUNCTION, (*ZendFunction)(&ZendPassFunction), opline.GetExtendedValue(), nil)

		/* Perform a dummy function call */

	} else {
		if EXPECTED(constructor.GetType() == ZEND_USER_FUNCTION) && UNEXPECTED(!(RUN_TIME_CACHE(&constructor.op_array))) {
			InitFuncRunTimeCache(&constructor.op_array)
		}

		/* We are not handling overloaded classes right now */

		call = ZendVmStackPushCallFrame(ZEND_CALL_FUNCTION|ZEND_CALL_RELEASE_THIS|ZEND_CALL_HAS_THIS, constructor, opline.GetExtendedValue(), Z_OBJ_P(result))
		Z_ADDREF_P(result)
	}
	call.SetPrevExecuteData(EX(call))
	EX(call) = call
	ZEND_VM_NEXT_OPCODE()
}
func ZEND_INIT_ARRAY_SPEC_UNUSED_UNUSED_HANDLER(execute_data *ZendExecuteData) int {
	var array *Zval
	var size uint32
	var opline *ZendOp = EX(opline)
	array = EX_VAR(opline.GetResult().GetVar())
	if IS_UNUSED != IS_UNUSED {
		size = opline.GetExtendedValue() >> ZEND_ARRAY_SIZE_SHIFT
		ZVAL_ARR(array, ZendNewArray(size))

		/* Explicitly initialize array as not-packed if flag is set */

		if (opline.GetExtendedValue() & ZEND_ARRAY_NOT_PACKED) != 0 {
			Z_ARRVAL_P(array).RealInitMixed()
		}
		return ZEND_NULL_HANDLER(execute_data)
	} else {
		ZVAL_ARR(array, ZendNewArray(0))
		ZEND_VM_NEXT_OPCODE()
	}
}
func ZEND_YIELD_SPEC_UNUSED_UNUSED_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var generator *ZendGenerator = ZendGetRunningGenerator(EXECUTE_DATA_C)
	if UNEXPECTED(generator.IsForcedClose()) {
		return zend_yield_in_closed_generator_helper_SPEC(execute_data)
	}

	/* Destroy the previously yielded value */

	ZvalPtrDtor(&generator.value)

	/* Destroy the previously yielded key */

	ZvalPtrDtor(&generator.key)

	/* Set the new yielded value */

	if IS_UNUSED != IS_UNUSED {
		if UNEXPECTED((EX(func_).op_array.fn_flags & ZEND_ACC_RETURN_REFERENCE) != 0) {

			/* Constants and temporary variables aren't yieldable by reference,
			 * but we still allow them with a notice. */

			if (IS_UNUSED & (IS_CONST | IS_TMP_VAR)) != 0 {
				var value *Zval
				ZendError(E_NOTICE, "Only variable references should be yielded by reference")
				value = nil
				ZVAL_COPY_VALUE(&generator.value, value)
				if IS_UNUSED == IS_CONST {
					if UNEXPECTED(Z_OPT_REFCOUNTED(generator.GetValue())) {
						Z_ADDREF(generator.GetValue())
					}
				}
			} else {
				var value_ptr *Zval = nil

				/* If a function call result is yielded and the function did
				 * not return by reference we throw a notice. */

				for {
					if IS_UNUSED == IS_VAR {
						ZEND_ASSERT(value_ptr != &(ExecutorGlobals.GetUninitializedZval()))
						if opline.GetExtendedValue() == ZEND_RETURNS_FUNCTION && !(Z_ISREF_P(value_ptr)) {
							ZendError(E_NOTICE, "Only variable references should be yielded by reference")
							ZVAL_COPY(&generator.value, value_ptr)
							break
						}
					}
					if Z_ISREF_P(value_ptr) {
						Z_ADDREF_P(value_ptr)
					} else {
						ZVAL_MAKE_REF_EX(value_ptr, 2)
					}
					ZVAL_REF(&generator.value, Z_REF_P(value_ptr))
					break
				}

				/* If a function call result is yielded and the function did
				 * not return by reference we throw a notice. */

			}

			/* Constants and temporary variables aren't yieldable by reference,
			 * but we still allow them with a notice. */

		} else {
			var value *Zval = nil

			/* Consts, temporary variables and references need copying */

			if IS_UNUSED == IS_CONST {
				ZVAL_COPY_VALUE(&generator.value, value)
				if UNEXPECTED(Z_OPT_REFCOUNTED(generator.GetValue())) {
					Z_ADDREF(generator.GetValue())
				}
			} else if IS_UNUSED == IS_TMP_VAR {
				ZVAL_COPY_VALUE(&generator.value, value)
			} else if (IS_UNUSED&(IS_VAR|IS_CV)) != 0 && Z_ISREF_P(value) {
				ZVAL_COPY(&generator.value, Z_REFVAL_P(value))
			} else {
				ZVAL_COPY_VALUE(&generator.value, value)
				if IS_UNUSED == IS_CV {
					if Z_OPT_REFCOUNTED_P(value) {
						Z_ADDREF_P(value)
					}
				}
			}

			/* Consts, temporary variables and references need copying */

		}
	} else {

		/* If no value was specified yield null */

		ZVAL_NULL(&generator.value)

		/* If no value was specified yield null */

	}

	/* Set the new yielded key */

	if IS_UNUSED != IS_UNUSED {
		var key *Zval = nil

		/* Consts, temporary variables and references need copying */

		if IS_UNUSED == IS_CONST {
			ZVAL_COPY_VALUE(&generator.key, key)
			if UNEXPECTED(Z_OPT_REFCOUNTED(generator.GetKey())) {
				Z_ADDREF(generator.GetKey())
			}
		} else if IS_UNUSED == IS_TMP_VAR {
			ZVAL_COPY_VALUE(&generator.key, key)
		} else if (IS_UNUSED&(IS_VAR|IS_CV)) != 0 && Z_ISREF_P(key) {
			ZVAL_COPY(&generator.key, Z_REFVAL_P(key))
		} else {
			ZVAL_COPY_VALUE(&generator.key, key)
			if IS_UNUSED == IS_CV {
				if Z_OPT_REFCOUNTED_P(key) {
					Z_ADDREF_P(key)
				}
			}
		}
		if Z_TYPE(generator.GetKey()) == IS_LONG && Z_LVAL(generator.GetKey()) > generator.GetLargestUsedIntegerKey() {
			generator.SetLargestUsedIntegerKey(Z_LVAL(generator.GetKey()))
		}
	} else {

		/* If no key was specified we use auto-increment keys */

		generator.GetLargestUsedIntegerKey()++
		ZVAL_LONG(&generator.key, generator.GetLargestUsedIntegerKey())
	}
	if RETURN_VALUE_USED(opline) {

		/* If the return value of yield is used set the send
		 * target and initialize it to NULL */

		generator.SetSendTarget(EX_VAR(opline.GetResult().GetVar()))
		ZVAL_NULL(generator.GetSendTarget())
	} else {
		generator.SetSendTarget(nil)
	}

	/* We increment to the next op, so we are at the correct position when the
	 * generator is resumed. */

	ZEND_VM_INC_OPCODE()

	/* The GOTO VM uses a local opline variable. We need to set the opline
	 * variable in execute_data so we don't resume at an old position. */

	return -1
}
