func ZEND_GET_CLASS_SPEC_UNUSED_UNUSED_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	if IS_UNUSED == IS_UNUSED {
		if UNEXPECTED(!(EX(func_).common.scope)) {
			ZendError(E_WARNING, "get_class() called without object from outside a class")
			ZVAL_FALSE(EX_VAR(opline.GetResult().GetVar()))
			ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
		} else {
			ZVAL_STR_COPY(EX_VAR(opline.GetResult().GetVar()), EX(func_).common.scope.name)
			ZEND_VM_NEXT_OPCODE()
		}
	} else {
		var op1 *Zval
		op1 = nil
		for true {
			if Z_TYPE_P(op1) == IS_OBJECT {
				ZVAL_STR_COPY(EX_VAR(opline.GetResult().GetVar()), Z_OBJCE_P(op1).GetName())
			} else if (IS_UNUSED&(IS_VAR|IS_CV)) != 0 && Z_TYPE_P(op1) == IS_REFERENCE {
				op1 = Z_REFVAL_P(op1)
				continue
			} else {
				if IS_UNUSED == IS_CV && UNEXPECTED(Z_TYPE_P(op1) == IS_UNDEF) {
					ZVAL_UNDEFINED_OP1()
				}
				ZendError(E_WARNING, "get_class() expects parameter 1 to be object, %s given", ZendGetTypeByConst(Z_TYPE_P(op1)))
				ZVAL_FALSE(EX_VAR(opline.GetResult().GetVar()))
			}
			break
		}
		ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
	}
}
func ZEND_GET_CALLED_CLASS_SPEC_UNUSED_UNUSED_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	if Z_TYPE(EX(This)) == IS_OBJECT {
		ZVAL_STR_COPY(EX_VAR(opline.GetResult().GetVar()), Z_OBJCE(EX(This)).GetName())
	} else if Z_CE(EX(This)) != nil {
		ZVAL_STR_COPY(EX_VAR(opline.GetResult().GetVar()), Z_CE(EX(This)).GetName())
	} else {
		ZVAL_FALSE(EX_VAR(opline.GetResult().GetVar()))
		if UNEXPECTED(!(EX(func_).common.scope)) {
			ZendError(E_WARNING, "get_called_class() called from outside a class")
			ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
		}
	}
	ZEND_VM_NEXT_OPCODE()
}
