func ZEND_FETCH_CLASS_SPEC_UNUSED_CV_HANDLER(execute_data *ZendExecuteData) int {
	var class_name *Zval
	var opline *ZendOp = EX(opline)
	if IS_CV == IS_UNUSED {
		Z_CE_P(EX_VAR(opline.GetResult().GetVar())) = ZendFetchClass(nil, opline.GetOp1().GetNum())
		ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
	} else if IS_CV == IS_CONST {
		var ce *ZendClassEntry = CACHED_PTR(opline.GetExtendedValue())
		if UNEXPECTED(ce == nil) {
			class_name = EX_VAR(opline.GetOp2().GetVar())
			ce = ZendFetchClassByName(Z_STR_P(class_name), Z_STR_P(class_name+1), opline.GetOp1().GetNum())
			CACHE_PTR(opline.GetExtendedValue(), ce)
		}
		Z_CE_P(EX_VAR(opline.GetResult().GetVar())) = ce
	} else {
		class_name = EX_VAR(opline.GetOp2().GetVar())
	try_class_name:
		if Z_TYPE_P(class_name) == IS_OBJECT {
			Z_CE_P(EX_VAR(opline.GetResult().GetVar())) = Z_OBJCE_P(class_name)
		} else if Z_TYPE_P(class_name) == IS_STRING {
			Z_CE_P(EX_VAR(opline.GetResult().GetVar())) = ZendFetchClass(Z_STR_P(class_name), opline.GetOp1().GetNum())
		} else if (IS_CV&(IS_VAR|IS_CV)) != 0 && Z_TYPE_P(class_name) == IS_REFERENCE {
			class_name = Z_REFVAL_P(class_name)
			goto try_class_name
		} else {
			if IS_CV == IS_CV && UNEXPECTED(Z_TYPE_P(class_name) == IS_UNDEF) {
				ZVAL_UNDEFINED_OP2()
				if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
					HANDLE_EXCEPTION()
				}
			}
			ZendThrowError(nil, "Class name must be a valid object or a string")
		}
	}
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_INIT_METHOD_CALL_SPEC_UNUSED_CV_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var function_name *Zval
	var free_op1 ZendFreeOp
	var object *Zval
	var fbc *ZendFunction
	var called_scope *ZendClassEntry
	var obj *ZendObject
	var call *ZendExecuteData
	var call_info uint32
	object = &EX(This)
	if IS_UNUSED == IS_UNUSED && UNEXPECTED(Z_TYPE_P(object) == IS_UNDEF) {
		return zend_this_not_in_object_context_helper_SPEC(execute_data)
	}
	if IS_CV != IS_CONST {
		function_name = EX_VAR(opline.GetOp2().GetVar())
	}
	if IS_CV != IS_CONST && UNEXPECTED(Z_TYPE_P(function_name) != IS_STRING) {
		for {
			if (IS_CV&(IS_VAR|IS_CV)) != 0 && Z_ISREF_P(function_name) {
				function_name = Z_REFVAL_P(function_name)
				if EXPECTED(Z_TYPE_P(function_name) == IS_STRING) {
					break
				}
			} else if IS_CV == IS_CV && UNEXPECTED(Z_TYPE_P(function_name) == IS_UNDEF) {
				ZVAL_UNDEFINED_OP2()
				if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
					HANDLE_EXCEPTION()
				}
			}
			ZendThrowError(nil, "Method name must be a string")
			HANDLE_EXCEPTION()
			break
		}
	}
	if IS_UNUSED != IS_UNUSED {
		for {
			if IS_UNUSED == IS_CONST || UNEXPECTED(Z_TYPE_P(object) != IS_OBJECT) {
				if (IS_UNUSED&(IS_VAR|IS_CV)) != 0 && EXPECTED(Z_ISREF_P(object)) {
					object = Z_REFVAL_P(object)
					if EXPECTED(Z_TYPE_P(object) == IS_OBJECT) {
						break
					}
				}
				if IS_UNUSED == IS_CV && UNEXPECTED(Z_TYPE_P(object) == IS_UNDEF) {
					object = ZVAL_UNDEFINED_OP1()
					if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
						if IS_CV != IS_CONST {

						}
						HANDLE_EXCEPTION()
					}
				}
				if IS_CV == IS_CONST {
					function_name = EX_VAR(opline.GetOp2().GetVar())
				}
				ZendInvalidMethodCall(object, function_name)
				HANDLE_EXCEPTION()
			}
			break
		}
	}
	obj = Z_OBJ_P(object)
	called_scope = obj.GetCe()
	if IS_CV == IS_CONST && EXPECTED(CACHED_PTR(opline.GetResult().GetNum()) == called_scope) {
		fbc = CACHED_PTR(opline.GetResult().GetNum() + b.SizeOf("void *"))
	} else {
		var orig_obj *ZendObject = obj
		if IS_CV == IS_CONST {
			function_name = EX_VAR(opline.GetOp2().GetVar())
		}

		/* First, locate the function. */

		fbc = obj.GetHandlers().GetGetMethod()(&obj, Z_STR_P(function_name), b.CondF1(IS_CV == IS_CONST, func() *Zval { return RT_CONSTANT(opline, opline.GetOp2()) + 1 }, nil))
		if UNEXPECTED(fbc == nil) {
			if EXPECTED(ExecutorGlobals.GetException() == nil) {
				ZendUndefinedMethod(obj.GetCe(), Z_STR_P(function_name))
			}
			HANDLE_EXCEPTION()
		}
		if IS_CV == IS_CONST && EXPECTED(fbc.GetType() <= ZEND_USER_FUNCTION) && EXPECTED(!fbc.HasFnFlags(ZEND_ACC_CALL_VIA_TRAMPOLINE|ZEND_ACC_NEVER_CACHE)) && EXPECTED(obj == orig_obj) {
			CACHE_POLYMORPHIC_PTR(opline.GetResult().GetNum(), called_scope, fbc)
		}
		if (IS_UNUSED&(IS_VAR|IS_TMP_VAR)) != 0 && UNEXPECTED(obj != orig_obj) {

			/* Reset "object" to trigger reference counting */

			object = nil

			/* Reset "object" to trigger reference counting */

		}
		if EXPECTED(fbc.GetType() == ZEND_USER_FUNCTION) && UNEXPECTED(!(RUN_TIME_CACHE(&fbc.op_array))) {
			InitFuncRunTimeCache(&fbc.op_array)
		}
	}
	if IS_CV != IS_CONST {

	}
	call_info = ZEND_CALL_NESTED_FUNCTION | ZEND_CALL_HAS_THIS
	if UNEXPECTED(fbc.IsStatic()) {
		if (IS_UNUSED&(IS_VAR|IS_TMP_VAR)) != 0 && UNEXPECTED(ExecutorGlobals.GetException() != nil) {
			HANDLE_EXCEPTION()
		}

		/* call static method */

		obj = (*ZendObject)(called_scope)
		call_info = ZEND_CALL_NESTED_FUNCTION
	} else if (IS_UNUSED & (IS_VAR | IS_TMP_VAR | IS_CV)) != 0 {
		if IS_UNUSED == IS_CV {
			GC_ADDREF(obj)
		} else if free_op1 != object {
			GC_ADDREF(obj)
		}

		/* CV may be changed indirectly (e.g. when it's a reference) */

		call_info = ZEND_CALL_NESTED_FUNCTION | ZEND_CALL_HAS_THIS | ZEND_CALL_RELEASE_THIS

		/* CV may be changed indirectly (e.g. when it's a reference) */

	}
	call = ZendVmStackPushCallFrame(call_info, fbc, opline.GetExtendedValue(), obj)
	call.SetPrevExecuteData(EX(call))
	EX(call) = call
	ZEND_VM_NEXT_OPCODE()
}
