func ZEND_BOOL_SPEC_CV_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var val *Zval
	val = EX_VAR(opline.GetOp1().GetVar())
	if Z_TYPE_INFO_P(val) == IS_TRUE {
		ZVAL_TRUE(EX_VAR(opline.GetResult().GetVar()))
	} else if EXPECTED(Z_TYPE_INFO_P(val) <= IS_TRUE) {

		/* The result and op1 can be the same cv zval */

		var orig_val_type uint32 = Z_TYPE_INFO_P(val)
		ZVAL_FALSE(EX_VAR(opline.GetResult().GetVar()))
		if IS_CV == IS_CV && UNEXPECTED(orig_val_type == IS_UNDEF) {
			ZVAL_UNDEFINED_OP1()
			ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
		}
	} else {
		ZVAL_BOOL(EX_VAR(opline.GetResult().GetVar()), IZendIsTrue(val))
		ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
	}
	ZEND_VM_NEXT_OPCODE()
}
func ZEND_CLONE_SPEC_CV_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var obj *Zval
	var ce *ZendClassEntry
	var scope *ZendClassEntry
	var clone *ZendFunction
	var clone_call ZendObjectCloneObjT
	obj = EX_VAR(opline.GetOp1().GetVar())
	if IS_CV == IS_UNUSED && UNEXPECTED(Z_TYPE_P(obj) == IS_UNDEF) {
		return zend_this_not_in_object_context_helper_SPEC(execute_data)
	}
	for {
		if IS_CV == IS_CONST || IS_CV != IS_UNUSED && UNEXPECTED(Z_TYPE_P(obj) != IS_OBJECT) {
			if (IS_CV&(IS_VAR|IS_CV)) != 0 && Z_ISREF_P(obj) {
				obj = Z_REFVAL_P(obj)
				if EXPECTED(Z_TYPE_P(obj) == IS_OBJECT) {
					break
				}
			}
			ZVAL_UNDEF(EX_VAR(opline.GetResult().GetVar()))
			if IS_CV == IS_CV && UNEXPECTED(Z_TYPE_P(obj) == IS_UNDEF) {
				ZVAL_UNDEFINED_OP1()
				if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
					HANDLE_EXCEPTION()
				}
			}
			ZendThrowError(nil, "__clone method called on non-object")
			HANDLE_EXCEPTION()
		}
		break
	}
	ce = Z_OBJCE_P(obj)
	clone = ce.GetClone()
	clone_call = Z_OBJ_HT_P(obj).GetCloneObj()
	if UNEXPECTED(clone_call == nil) {
		ZendThrowError(nil, "Trying to clone an uncloneable object of class %s", ZSTR_VAL(ce.GetName()))
		ZVAL_UNDEF(EX_VAR(opline.GetResult().GetVar()))
		HANDLE_EXCEPTION()
	}
	if clone != nil && !clone.IsPublic() {
		scope = EX(func_).op_array.scope
		if clone.GetScope() != scope {
			if UNEXPECTED(clone.IsPrivate()) || UNEXPECTED(ZendCheckProtected(ZendGetFunctionRootClass(clone), scope) == 0) {
				ZendWrongCloneCall(clone, scope)
				ZVAL_UNDEF(EX_VAR(opline.GetResult().GetVar()))
				HANDLE_EXCEPTION()
			}
		}
	}
	ZVAL_OBJ(EX_VAR(opline.GetResult().GetVar()), clone_call(obj))
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_CAST_SPEC_CV_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var expr *Zval
	var result *Zval = EX_VAR(opline.GetResult().GetVar())
	var ht *HashTable
	expr = _get_zval_ptr_cv_BP_VAR_R(opline.GetOp1().GetVar(), EXECUTE_DATA_C)
	switch opline.GetExtendedValue() {
	case IS_NULL:
		ZVAL_NULL(result)
		break
	case _IS_BOOL:
		ZVAL_BOOL(result, ZendIsTrue(expr))
		break
	case IS_LONG:
		ZVAL_LONG(result, ZvalGetLong(expr))
		break
	case IS_DOUBLE:
		ZVAL_DOUBLE(result, ZvalGetDouble(expr))
		break
	case IS_STRING:
		ZVAL_STR(result, ZvalGetString(expr))
		break
	default:
		if (IS_CV & (IS_VAR | IS_CV)) != 0 {
			ZVAL_DEREF(expr)
		}

		/* If value is already of correct type, return it directly */

		if Z_TYPE_P(expr) == opline.GetExtendedValue() {
			ZVAL_COPY_VALUE(result, expr)
			if IS_CV == IS_CONST {
				if UNEXPECTED(Z_OPT_REFCOUNTED_P(result)) {
					Z_ADDREF_P(result)
				}
			} else if IS_CV != IS_TMP_VAR {
				if Z_OPT_REFCOUNTED_P(result) {
					Z_ADDREF_P(result)
				}
			}
			ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
		}
		if opline.GetExtendedValue() == IS_ARRAY {
			if IS_CV == IS_CONST || Z_TYPE_P(expr) != IS_OBJECT || Z_OBJCE_P(expr) == ZendCeClosure {
				if Z_TYPE_P(expr) != IS_NULL {
					ZVAL_ARR(result, ZendNewArray(1))
					expr = Z_ARRVAL_P(result).IndexAddNew(0, expr)
					if IS_CV == IS_CONST {
						if UNEXPECTED(Z_OPT_REFCOUNTED_P(expr)) {
							Z_ADDREF_P(expr)
						}
					} else {
						if Z_OPT_REFCOUNTED_P(expr) {
							Z_ADDREF_P(expr)
						}
					}
				} else {
					ZVAL_EMPTY_ARRAY(result)
				}
			} else {
				var obj_ht *HashTable = ZendGetPropertiesFor(expr, ZEND_PROP_PURPOSE_ARRAY_CAST)
				if obj_ht != nil {

					/* fast copy */

					ZVAL_ARR(result, ZendProptableToSymtable(obj_ht, Z_OBJCE_P(expr).GetDefaultPropertiesCount() != 0 || Z_OBJ_P(expr).GetHandlers() != &StdObjectHandlers || GC_IS_RECURSIVE(obj_ht) != 0))
					ZendReleaseProperties(obj_ht)
				} else {
					ZVAL_EMPTY_ARRAY(result)
				}
			}
		} else {
			ZVAL_OBJ(result, ZendObjectsNew(ZendStandardClassDef))
			if Z_TYPE_P(expr) == IS_ARRAY {
				ht = ZendSymtableToProptable(Z_ARR_P(expr))
				if (GC_FLAGS(ht) & IS_ARRAY_IMMUTABLE) != 0 {

					/* TODO: try not to duplicate immutable arrays as well ??? */

					ht = ZendArrayDup(ht)

					/* TODO: try not to duplicate immutable arrays as well ??? */

				}
				Z_OBJ_P(result).SetProperties(ht)
			} else if Z_TYPE_P(expr) != IS_NULL {
				ht = ZendNewArray(1)
				Z_OBJ_P(result).SetProperties(ht)
				expr = ht.AddNew(ZSTR_KNOWN(ZEND_STR_SCALAR), expr)
				if IS_CV == IS_CONST {
					if UNEXPECTED(Z_OPT_REFCOUNTED_P(expr)) {
						Z_ADDREF_P(expr)
					}
				} else {
					if Z_OPT_REFCOUNTED_P(expr) {
						Z_ADDREF_P(expr)
					}
				}
			}
		}
	}
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_INCLUDE_OR_EVAL_SPEC_CV_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var new_op_array *ZendOpArray
	var inc_filename *Zval
	inc_filename = _get_zval_ptr_cv_BP_VAR_R(opline.GetOp1().GetVar(), EXECUTE_DATA_C)
	new_op_array = ZendIncludeOrEval(inc_filename, opline.GetExtendedValue())
	if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
		if new_op_array != ZEND_FAKE_OP_ARRAY && new_op_array != nil {
			DestroyOpArray(new_op_array)
			EfreeSize(new_op_array, b.SizeOf("zend_op_array"))
		}
		UNDEF_RESULT()
		HANDLE_EXCEPTION()
	} else if new_op_array == ZEND_FAKE_OP_ARRAY {
		if RETURN_VALUE_USED(opline) {
			ZVAL_TRUE(EX_VAR(opline.GetResult().GetVar()))
		}
	} else if EXPECTED(new_op_array != nil) {
		var return_value *Zval = nil
		var call *ZendExecuteData
		if RETURN_VALUE_USED(opline) {
			return_value = EX_VAR(opline.GetResult().GetVar())
		}
		new_op_array.SetScope(EX(func_).op_array.scope)
		call = ZendVmStackPushCallFrame(Z_TYPE_INFO(EX(This))&ZEND_CALL_HAS_THIS|ZEND_CALL_NESTED_CODE|ZEND_CALL_HAS_SYMBOL_TABLE, (*ZendFunction)(new_op_array), 0, Z_PTR(EX(This)))
		if (EX_CALL_INFO() & ZEND_CALL_HAS_SYMBOL_TABLE) != 0 {
			call.SetSymbolTable(EX(symbol_table))
		} else {
			call.SetSymbolTable(ZendRebuildSymbolTable())
		}
		call.SetPrevExecuteData(execute_data)
		IInitCodeExecuteData(call, new_op_array, return_value)
		if EXPECTED(ZendExecuteEx == ExecuteEx) {
			return 1
		} else {
			ZEND_ADD_CALL_FLAG(call, ZEND_CALL_TOP)
			ZendExecuteEx(call)
			ZendVmStackFreeCallFrame(call)
		}
		DestroyOpArray(new_op_array)
		EfreeSize(new_op_array, b.SizeOf("zend_op_array"))
		if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
			ZendRethrowException(execute_data)
			UNDEF_RESULT()
			HANDLE_EXCEPTION()
		}
	} else if RETURN_VALUE_USED(opline) {
		ZVAL_FALSE(EX_VAR(opline.GetResult().GetVar()))
	}
	ZEND_VM_NEXT_OPCODE()
}
func ZEND_FE_RESET_R_SPEC_CV_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var array_ptr *Zval
	var result *Zval
	array_ptr = _get_zval_ptr_cv_deref_BP_VAR_R(opline.GetOp1().GetVar(), EXECUTE_DATA_C)
	if EXPECTED(Z_TYPE_P(array_ptr) == IS_ARRAY) {
		result = EX_VAR(opline.GetResult().GetVar())
		ZVAL_COPY_VALUE(result, array_ptr)
		if IS_CV != IS_TMP_VAR && Z_OPT_REFCOUNTED_P(result) {
			Z_ADDREF_P(array_ptr)
		}
		Z_FE_POS_P(result) = 0
		ZEND_VM_NEXT_OPCODE()
	} else if IS_CV != IS_CONST && EXPECTED(Z_TYPE_P(array_ptr) == IS_OBJECT) {
		if Z_OBJCE_P(array_ptr).GetGetIterator() == nil {
			var properties *HashTable
			if Z_OBJ_P(array_ptr).GetProperties() != nil && UNEXPECTED(GC_REFCOUNT(Z_OBJ_P(array_ptr).GetProperties()) > 1) {
				if EXPECTED((GC_FLAGS(Z_OBJ_P(array_ptr).GetProperties()) & IS_ARRAY_IMMUTABLE) == 0) {
					GC_DELREF(Z_OBJ_P(array_ptr).GetProperties())
				}
				Z_OBJ_P(array_ptr).SetProperties(ZendArrayDup(Z_OBJ_P(array_ptr).GetProperties()))
			}
			properties = Z_OBJPROP_P(array_ptr)
			result = EX_VAR(opline.GetResult().GetVar())
			ZVAL_COPY_VALUE(result, array_ptr)
			if IS_CV != IS_TMP_VAR {
				Z_ADDREF_P(array_ptr)
			}
			if properties.NumElements() == 0 {
				Z_FE_ITER_P(result) = uint32_t - 1
				ZEND_VM_JMP(OP_JMP_ADDR(opline, opline.GetOp2()))
			}
			Z_FE_ITER_P(result) = properties.IteratorAdd(0)
			ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
		} else {
			var is_empty ZendBool = ZendFeResetIterator(array_ptr, 0, OPLINE_C, EXECUTE_DATA_C)
			if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
				HANDLE_EXCEPTION()
			} else if is_empty != 0 {
				ZEND_VM_JMP_EX(OP_JMP_ADDR(opline, opline.GetOp2()), 0)
			} else {
				ZEND_VM_NEXT_OPCODE()
			}
		}
	} else {
		ZendError(E_WARNING, "Invalid argument supplied for foreach()")
		ZVAL_UNDEF(EX_VAR(opline.GetResult().GetVar()))
		Z_FE_ITER_P(EX_VAR(opline.GetResult().GetVar())) = uint32_t - 1
		ZEND_VM_JMP(OP_JMP_ADDR(opline, opline.GetOp2()))
	}
}
func ZEND_FE_RESET_RW_SPEC_CV_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var array_ptr *Zval
	var array_ref *Zval
	if IS_CV == IS_VAR || IS_CV == IS_CV {
		array_ptr = _get_zval_ptr_cv_BP_VAR_R(opline.GetOp1().GetVar(), EXECUTE_DATA_C)
		array_ref = array_ptr
		if Z_ISREF_P(array_ref) {
			array_ptr = Z_REFVAL_P(array_ref)
		}
	} else {
		array_ptr = _get_zval_ptr_cv_BP_VAR_R(opline.GetOp1().GetVar(), EXECUTE_DATA_C)
		array_ref = array_ptr
	}
	if EXPECTED(Z_TYPE_P(array_ptr) == IS_ARRAY) {
		if IS_CV == IS_VAR || IS_CV == IS_CV {
			if array_ptr == array_ref {
				ZVAL_NEW_REF(array_ref, array_ref)
				array_ptr = Z_REFVAL_P(array_ref)
			}
			Z_ADDREF_P(array_ref)
			ZVAL_COPY_VALUE(EX_VAR(opline.GetResult().GetVar()), array_ref)
		} else {
			array_ref = EX_VAR(opline.GetResult().GetVar())
			ZVAL_NEW_REF(array_ref, array_ptr)
			array_ptr = Z_REFVAL_P(array_ref)
		}
		if IS_CV == IS_CONST {
			ZVAL_ARR(array_ptr, ZendArrayDup(Z_ARRVAL_P(array_ptr)))
		} else {
			SEPARATE_ARRAY(array_ptr)
		}
		Z_FE_ITER_P(EX_VAR(opline.GetResult().GetVar())) = Z_ARRVAL_P(array_ptr).IteratorAdd(0)
		if IS_CV == IS_VAR {

		}
		ZEND_VM_NEXT_OPCODE()
	} else if IS_CV != IS_CONST && EXPECTED(Z_TYPE_P(array_ptr) == IS_OBJECT) {
		if Z_OBJCE_P(array_ptr).GetGetIterator() == nil {
			var properties *HashTable
			if IS_CV == IS_VAR || IS_CV == IS_CV {
				if array_ptr == array_ref {
					ZVAL_NEW_REF(array_ref, array_ref)
					array_ptr = Z_REFVAL_P(array_ref)
				}
				Z_ADDREF_P(array_ref)
				ZVAL_COPY_VALUE(EX_VAR(opline.GetResult().GetVar()), array_ref)
			} else {
				array_ptr = EX_VAR(opline.GetResult().GetVar())
				ZVAL_COPY_VALUE(array_ptr, array_ref)
			}
			if Z_OBJ_P(array_ptr).GetProperties() != nil && UNEXPECTED(GC_REFCOUNT(Z_OBJ_P(array_ptr).GetProperties()) > 1) {
				if EXPECTED((GC_FLAGS(Z_OBJ_P(array_ptr).GetProperties()) & IS_ARRAY_IMMUTABLE) == 0) {
					GC_DELREF(Z_OBJ_P(array_ptr).GetProperties())
				}
				Z_OBJ_P(array_ptr).SetProperties(ZendArrayDup(Z_OBJ_P(array_ptr).GetProperties()))
			}
			properties = Z_OBJPROP_P(array_ptr)
			if properties.NumElements() == 0 {
				Z_FE_ITER_P(EX_VAR(opline.GetResult().GetVar())) = uint32_t - 1
				ZEND_VM_JMP(OP_JMP_ADDR(opline, opline.GetOp2()))
			}
			Z_FE_ITER_P(EX_VAR(opline.GetResult().GetVar())) = properties.IteratorAdd(0)
			ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
		} else {
			var is_empty ZendBool = ZendFeResetIterator(array_ptr, 1, OPLINE_C, EXECUTE_DATA_C)
			if IS_CV == IS_VAR {

			}
			if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
				HANDLE_EXCEPTION()
			} else if is_empty != 0 {
				ZEND_VM_JMP_EX(OP_JMP_ADDR(opline, opline.GetOp2()), 0)
			} else {
				ZEND_VM_NEXT_OPCODE()
			}
		}
	} else {
		ZendError(E_WARNING, "Invalid argument supplied for foreach()")
		ZVAL_UNDEF(EX_VAR(opline.GetResult().GetVar()))
		Z_FE_ITER_P(EX_VAR(opline.GetResult().GetVar())) = uint32_t - 1
		if IS_CV == IS_VAR {

		}
		ZEND_VM_JMP(OP_JMP_ADDR(opline, opline.GetOp2()))
	}
}
func ZEND_JMP_SET_SPEC_CV_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var value *Zval
	var ref *Zval = nil
	var ret int
	value = _get_zval_ptr_cv_BP_VAR_R(opline.GetOp1().GetVar(), EXECUTE_DATA_C)
	if (IS_CV == IS_VAR || IS_CV == IS_CV) && Z_ISREF_P(value) {
		if IS_CV == IS_VAR {
			ref = value
		}
		value = Z_REFVAL_P(value)
	}
	ret = IZendIsTrue(value)
	if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
		ZVAL_UNDEF(EX_VAR(opline.GetResult().GetVar()))
		HANDLE_EXCEPTION()
	}
	if ret != 0 {
		var result *Zval = EX_VAR(opline.GetResult().GetVar())
		ZVAL_COPY_VALUE(result, value)
		if IS_CV == IS_CONST {
			if UNEXPECTED(Z_OPT_REFCOUNTED_P(result)) {
				Z_ADDREF_P(result)
			}
		} else if IS_CV == IS_CV {
			if Z_OPT_REFCOUNTED_P(result) {
				Z_ADDREF_P(result)
			}
		} else if IS_CV == IS_VAR && ref != nil {
			var r *ZendReference = Z_REF_P(ref)
			if UNEXPECTED(GC_DELREF(r) == 0) {
				EfreeSize(r, b.SizeOf("zend_reference"))
			} else if Z_OPT_REFCOUNTED_P(result) {
				Z_ADDREF_P(result)
			}
		}
		ZEND_VM_JMP_EX(OP_JMP_ADDR(opline, opline.GetOp2()), 0)
	}
	ZEND_VM_NEXT_OPCODE()
}
func ZEND_COALESCE_SPEC_CV_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var value *Zval
	var ref *Zval = nil
	value = _get_zval_ptr_cv_BP_VAR_IS(opline.GetOp1().GetVar(), EXECUTE_DATA_C)
	if (IS_CV&(IS_VAR|IS_CV)) != 0 && Z_ISREF_P(value) {
		if (IS_CV & IS_VAR) != 0 {
			ref = value
		}
		value = Z_REFVAL_P(value)
	}
	if Z_TYPE_P(value) > IS_NULL {
		var result *Zval = EX_VAR(opline.GetResult().GetVar())
		ZVAL_COPY_VALUE(result, value)
		if IS_CV == IS_CONST {
			if UNEXPECTED(Z_OPT_REFCOUNTED_P(result)) {
				Z_ADDREF_P(result)
			}
		} else if IS_CV == IS_CV {
			if Z_OPT_REFCOUNTED_P(result) {
				Z_ADDREF_P(result)
			}
		} else if (IS_CV&IS_VAR) != 0 && ref != nil {
			var r *ZendReference = Z_REF_P(ref)
			if UNEXPECTED(GC_DELREF(r) == 0) {
				EfreeSize(r, b.SizeOf("zend_reference"))
			} else if Z_OPT_REFCOUNTED_P(result) {
				Z_ADDREF_P(result)
			}
		}
		ZEND_VM_JMP_EX(OP_JMP_ADDR(opline, opline.GetOp2()), 0)
	}
	ZEND_VM_NEXT_OPCODE()
}
func ZEND_QM_ASSIGN_SPEC_CV_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var value *Zval
	var result *Zval = EX_VAR(opline.GetResult().GetVar())
	value = EX_VAR(opline.GetOp1().GetVar())
	if IS_CV == IS_CV && UNEXPECTED(Z_TYPE_P(value) == IS_UNDEF) {
		ZVAL_UNDEFINED_OP1()
		ZVAL_NULL(result)
		ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
	}
	if IS_CV == IS_CV {
		ZVAL_COPY_DEREF(result, value)
	} else if IS_CV == IS_VAR {
		if UNEXPECTED(Z_ISREF_P(value)) {
			ZVAL_COPY_VALUE(result, Z_REFVAL_P(value))
			if UNEXPECTED(Z_DELREF_P(value) == 0) {
				EfreeSize(Z_REF_P(value), b.SizeOf("zend_reference"))
			} else if Z_OPT_REFCOUNTED_P(result) {
				Z_ADDREF_P(result)
			}
		} else {
			ZVAL_COPY_VALUE(result, value)
		}
	} else {
		ZVAL_COPY_VALUE(result, value)
		if IS_CV == IS_CONST {
			if UNEXPECTED(Z_OPT_REFCOUNTED_P(result)) {
				Z_ADDREF_P(result)
			}
		}
	}
	ZEND_VM_NEXT_OPCODE()
}
func ZEND_YIELD_FROM_SPEC_CV_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var generator *ZendGenerator = ZendGetRunningGenerator(EXECUTE_DATA_C)
	var val *Zval
	val = _get_zval_ptr_cv_deref_BP_VAR_R(opline.GetOp1().GetVar(), EXECUTE_DATA_C)
	if UNEXPECTED(generator.IsForcedClose()) {
		ZendThrowError(nil, "Cannot use \"yield from\" in a force-closed generator")
		UNDEF_RESULT()
		HANDLE_EXCEPTION()
	}
	if Z_TYPE_P(val) == IS_ARRAY {
		ZVAL_COPY_VALUE(&generator.values, val)
		if IS_CV != IS_TMP_VAR && Z_OPT_REFCOUNTED_P(val) {
			Z_ADDREF_P(val)
		}
		Z_FE_POS(generator.GetValues()) = 0
	} else if IS_CV != IS_CONST && Z_TYPE_P(val) == IS_OBJECT && Z_OBJCE_P(val).GetGetIterator() != nil {
		var ce *ZendClassEntry = Z_OBJCE_P(val)
		if ce == ZendCeGenerator {
			var new_gen *ZendGenerator = (*ZendGenerator)(Z_OBJ_P(val))
			if IS_CV != IS_TMP_VAR {
				Z_ADDREF_P(val)
			}
			if Z_ISUNDEF(new_gen.GetRetval()) {
				if UNEXPECTED(ZendGeneratorGetCurrent(new_gen) == generator) {
					ZendThrowError(nil, "Impossible to yield from the Generator being currently run")
					ZvalPtrDtor(val)
					UNDEF_RESULT()
					HANDLE_EXCEPTION()
				} else {
					ZendGeneratorYieldFrom(generator, new_gen)
				}
			} else if UNEXPECTED(new_gen.GetExecuteData() == nil) {
				ZendThrowError(nil, "Generator passed to yield from was aborted without proper return and is unable to continue")
				ZvalPtrDtor(val)
				UNDEF_RESULT()
				HANDLE_EXCEPTION()
			} else {
				if RETURN_VALUE_USED(opline) {
					ZVAL_COPY(EX_VAR(opline.GetResult().GetVar()), &new_gen.retval)
				}
				ZEND_VM_NEXT_OPCODE()
			}
		} else {
			var iter *ZendObjectIterator = ce.GetGetIterator()(ce, val, 0)
			if UNEXPECTED(iter == nil) || UNEXPECTED(ExecutorGlobals.GetException() != nil) {
				if ExecutorGlobals.GetException() == nil {
					ZendThrowError(nil, "Object of type %s did not create an Iterator", ZSTR_VAL(ce.GetName()))
				}
				UNDEF_RESULT()
				HANDLE_EXCEPTION()
			}
			iter.SetIndex(0)
			if iter.GetFuncs().GetRewind() != nil {
				iter.GetFuncs().GetRewind()(iter)
				if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
					OBJ_RELEASE(&iter.std)
					UNDEF_RESULT()
					HANDLE_EXCEPTION()
				}
			}
			ZVAL_OBJ(&generator.values, &iter.std)
		}
	} else {
		ZendThrowError(nil, "Can use \"yield from\" only with arrays and Traversables")
		UNDEF_RESULT()
		HANDLE_EXCEPTION()
	}

	/* This is the default return value
	 * when the expression is a Generator, it will be overwritten in zend_generator_resume() */

	if RETURN_VALUE_USED(opline) {
		ZVAL_NULL(EX_VAR(opline.GetResult().GetVar()))
	}

	/* This generator has no send target (though the generator we delegate to might have one) */

	generator.SetSendTarget(nil)

	/* We increment to the next op, so we are at the correct position when the
	 * generator is resumed. */

	ZEND_VM_INC_OPCODE()

	/* The GOTO VM uses a local opline variable. We need to set the opline
	 * variable in execute_data so we don't resume at an old position. */

	return -1
}
func ZEND_STRLEN_SPEC_CV_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var value *Zval
	value = EX_VAR(opline.GetOp1().GetVar())
	if EXPECTED(Z_TYPE_P(value) == IS_STRING) {
		ZVAL_LONG(EX_VAR(opline.GetResult().GetVar()), Z_STRLEN_P(value))
		ZEND_VM_NEXT_OPCODE()
	} else {
		var strict ZendBool
		if (IS_CV&(IS_VAR|IS_CV)) != 0 && Z_TYPE_P(value) == IS_REFERENCE {
			value = Z_REFVAL_P(value)
			if EXPECTED(Z_TYPE_P(value) == IS_STRING) {
				ZVAL_LONG(EX_VAR(opline.GetResult().GetVar()), Z_STRLEN_P(value))
				ZEND_VM_NEXT_OPCODE()
			}
		}
		if IS_CV == IS_CV && UNEXPECTED(Z_TYPE_P(value) == IS_UNDEF) {
			value = ZVAL_UNDEFINED_OP1()
		}
		strict = EX_USES_STRICT_TYPES()
		for {
			if EXPECTED(strict == 0) {
				var str *ZendString
				var tmp Zval
				ZVAL_COPY(&tmp, value)
				if ZendParseArgStrWeak(&tmp, &str) != 0 {
					ZVAL_LONG(EX_VAR(opline.GetResult().GetVar()), ZSTR_LEN(str))
					ZvalPtrDtor(&tmp)
					break
				}
				ZvalPtrDtor(&tmp)
			}
			if ExecutorGlobals.GetException() == nil {
				ZendInternalTypeError(strict, "strlen() expects parameter 1 to be string, %s given", ZendGetTypeByConst(Z_TYPE_P(value)))
			}
			ZVAL_NULL(EX_VAR(opline.GetResult().GetVar()))
			break
		}
	}
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_TYPE_CHECK_SPEC_CV_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var value *Zval
	var result int = 0
	value = EX_VAR(opline.GetOp1().GetVar())
	if (opline.GetExtendedValue() >> uint32(Z_TYPE_P(value)) & 1) != 0 {
	type_check_resource:
		if EXPECTED(Z_TYPE_P(value) != IS_RESOURCE) || EXPECTED(nil != ZendRsrcListGetRsrcType(Z_RES_P(value))) {
			result = 1
		}
	} else if (IS_CV&(IS_CV|IS_VAR)) != 0 && Z_ISREF_P(value) {
		value = Z_REFVAL_P(value)
		if (opline.GetExtendedValue() >> uint32(Z_TYPE_P(value)) & 1) != 0 {
			goto type_check_resource
		}
	} else if IS_CV == IS_CV && UNEXPECTED(Z_TYPE_P(value) == IS_UNDEF) {
		result = (1 << IS_NULL & opline.GetExtendedValue()) != 0
		ZVAL_UNDEFINED_OP1()
		if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
			ZVAL_UNDEF(EX_VAR(opline.GetResult().GetVar()))
			HANDLE_EXCEPTION()
		}
	}
	if (IS_CV & (IS_TMP_VAR | IS_VAR)) != 0 {
		ZEND_VM_SMART_BRANCH(result, 1)
		ZVAL_BOOL(EX_VAR(opline.GetResult().GetVar()), result)
		ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
	} else {
		ZEND_VM_SMART_BRANCH(result, 0)
		ZVAL_BOOL(EX_VAR(opline.GetResult().GetVar()), result)
		ZEND_VM_NEXT_OPCODE()
	}
}
