func ZEND_ASSIGN_OBJ_SPEC_CV_CONST_OP_DATA_CONST_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var object *Zval
	var property *Zval
	var value *Zval
	var tmp Zval
	object = EX_VAR(opline.GetOp1().GetVar())
	if IS_CV == IS_UNUSED && UNEXPECTED(Z_TYPE_P(object) == IS_UNDEF) {
		return zend_this_not_in_object_context_helper_SPEC(execute_data)
	}
	property = RT_CONSTANT(opline, opline.GetOp2())
	value = RT_CONSTANT(opline+1, (opline + 1).GetOp1())
	if IS_CV != IS_UNUSED && UNEXPECTED(Z_TYPE_P(object) != IS_OBJECT) {
		if Z_ISREF_P(object) && Z_TYPE_P(Z_REFVAL_P(object)) == IS_OBJECT {
			object = Z_REFVAL_P(object)
			goto assign_object
		}
		object = MakeRealObject(object, property, OPLINE_C, EXECUTE_DATA_C)
		if UNEXPECTED(object == nil) {
			value = &(ExecutorGlobals.GetUninitializedZval())
			goto free_and_exit_assign_obj
		}
	}
assign_object:
	if IS_CONST == IS_CONST && EXPECTED(Z_OBJCE_P(object) == CACHED_PTR(opline.GetExtendedValue())) {
		var cache_slot *any = CACHE_ADDR(opline.GetExtendedValue())
		var prop_offset uintPtr = uintPtr(CACHED_PTR_EX(cache_slot + 1))
		var zobj *ZendObject = Z_OBJ_P(object)
		var property_val *Zval
		if EXPECTED(IS_VALID_PROPERTY_OFFSET(prop_offset)) {
			property_val = OBJ_PROP(zobj, prop_offset)
			if Z_TYPE_P(property_val) != IS_UNDEF {
				var prop_info *ZendPropertyInfo = (*ZendPropertyInfo)(CACHED_PTR_EX(cache_slot + 2))
				if UNEXPECTED(prop_info != nil) {
					value = ZendAssignToTypedProp(prop_info, property_val, value, EXECUTE_DATA_C)
					goto free_and_exit_assign_obj
				} else {
				fast_assign_obj:
					value = ZendAssignToVariable(property_val, value, IS_CONST, EX_USES_STRICT_TYPES())
					if UNEXPECTED(RETURN_VALUE_USED(opline)) {
						ZVAL_COPY(EX_VAR(opline.GetResult().GetVar()), value)
					}
					goto exit_assign_obj
				}
			}
		} else {
			if EXPECTED(zobj.GetProperties() != nil) {
				if UNEXPECTED(GC_REFCOUNT(zobj.GetProperties()) > 1) {
					if EXPECTED((GC_FLAGS(zobj.GetProperties()) & IS_ARRAY_IMMUTABLE) == 0) {
						GC_DELREF(zobj.GetProperties())
					}
					zobj.SetProperties(ZendArrayDup(zobj.GetProperties()))
				}
				property_val = zobj.GetProperties().FindEx(Z_STR_P(property), 1)
				if property_val != nil {
					goto fast_assign_obj
				}
			}
			if zobj.GetCe().GetSet() == nil {
				if EXPECTED(zobj.GetProperties() == nil) {
					RebuildObjectProperties(zobj)
				}
				if IS_CONST == IS_CONST {
					if UNEXPECTED(Z_OPT_REFCOUNTED_P(value)) {
						Z_ADDREF_P(value)
					}
				} else if IS_CONST != IS_TMP_VAR {
					if Z_ISREF_P(value) {
						if IS_CONST == IS_VAR {
							var ref *ZendReference = Z_REF_P(value)
							if GC_DELREF(ref) == 0 {
								ZVAL_COPY_VALUE(&tmp, Z_REFVAL_P(value))
								EfreeSize(ref, b.SizeOf("zend_reference"))
								value = &tmp
							} else {
								value = Z_REFVAL_P(value)
								Z_TRY_ADDREF_P(value)
							}
						} else {
							value = Z_REFVAL_P(value)
							Z_TRY_ADDREF_P(value)
						}
					} else if IS_CONST == IS_CV {
						Z_TRY_ADDREF_P(value)
					}
				}
				zobj.GetProperties().AddNew(Z_STR_P(property), value)
				if UNEXPECTED(RETURN_VALUE_USED(opline)) {
					ZVAL_COPY(EX_VAR(opline.GetResult().GetVar()), value)
				}
				goto exit_assign_obj
			}
		}
	}
	if IS_CONST == IS_CV || IS_CONST == IS_VAR {
		ZVAL_DEREF(value)
	}
	value = Z_OBJ_HT_P(object).GetWriteProperty()(object, property, value, b.CondF1(IS_CONST == IS_CONST, func() *any { return CACHE_ADDR(opline.GetExtendedValue()) }, nil))
free_and_exit_assign_obj:
	if UNEXPECTED(RETURN_VALUE_USED(opline)) {
		ZVAL_COPY(EX_VAR(opline.GetResult().GetVar()), value)
	}
exit_assign_obj:

	/* assign_obj has two opcodes! */

	OPLINE = EX(opline) + 2
	return 0
}
