func ZEND_FAST_CONCAT_SPEC_CV_CONST_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var op1 *Zval
	var op2 *Zval
	var op1_str *ZendString
	var op2_str *ZendString
	var str *ZendString
	op1 = EX_VAR(opline.GetOp1().GetVar())
	op2 = RT_CONSTANT(opline, opline.GetOp2())
	if (IS_CV == IS_CONST || EXPECTED(Z_TYPE_P(op1) == IS_STRING)) && (IS_CONST == IS_CONST || EXPECTED(Z_TYPE_P(op2) == IS_STRING)) {
		var op1_str *ZendString = Z_STR_P(op1)
		var op2_str *ZendString = Z_STR_P(op2)
		var str *ZendString
		if IS_CV != IS_CONST && UNEXPECTED(ZSTR_LEN(op1_str) == 0) {
			if IS_CONST == IS_CONST || IS_CONST == IS_CV {
				ZVAL_STR_COPY(EX_VAR(opline.GetResult().GetVar()), op2_str)
			} else {
				ZVAL_STR(EX_VAR(opline.GetResult().GetVar()), op2_str)
			}
			if (IS_CV & (IS_TMP_VAR | IS_VAR)) != 0 {
				ZendStringReleaseEx(op1_str, 0)
			}
		} else if IS_CONST != IS_CONST && UNEXPECTED(ZSTR_LEN(op2_str) == 0) {
			if IS_CV == IS_CONST || IS_CV == IS_CV {
				ZVAL_STR_COPY(EX_VAR(opline.GetResult().GetVar()), op1_str)
			} else {
				ZVAL_STR(EX_VAR(opline.GetResult().GetVar()), op1_str)
			}
			if (IS_CONST & (IS_TMP_VAR | IS_VAR)) != 0 {
				ZendStringReleaseEx(op2_str, 0)
			}
		} else if IS_CV != IS_CONST && IS_CV != IS_CV && ZSTR_IS_INTERNED(op1_str) == 0 && GC_REFCOUNT(op1_str) == 1 {
			var len_ int = ZSTR_LEN(op1_str)
			if UNEXPECTED(len_ > ZSTR_MAX_LEN-ZSTR_LEN(op2_str)) {
				ZendErrorNoreturn(E_ERROR, "Integer overflow in memory allocation")
			}
			str = ZendStringExtend(op1_str, len_+ZSTR_LEN(op2_str), 0)
			memcpy(ZSTR_VAL(str)+len_, ZSTR_VAL(op2_str), ZSTR_LEN(op2_str)+1)
			ZVAL_NEW_STR(EX_VAR(opline.GetResult().GetVar()), str)
			if (IS_CONST & (IS_TMP_VAR | IS_VAR)) != 0 {
				ZendStringReleaseEx(op2_str, 0)
			}
		} else {
			str = ZendStringAlloc(ZSTR_LEN(op1_str)+ZSTR_LEN(op2_str), 0)
			memcpy(ZSTR_VAL(str), ZSTR_VAL(op1_str), ZSTR_LEN(op1_str))
			memcpy(ZSTR_VAL(str)+ZSTR_LEN(op1_str), ZSTR_VAL(op2_str), ZSTR_LEN(op2_str)+1)
			ZVAL_NEW_STR(EX_VAR(opline.GetResult().GetVar()), str)
			if (IS_CV & (IS_TMP_VAR | IS_VAR)) != 0 {
				ZendStringReleaseEx(op1_str, 0)
			}
			if (IS_CONST & (IS_TMP_VAR | IS_VAR)) != 0 {
				ZendStringReleaseEx(op2_str, 0)
			}
		}
		ZEND_VM_NEXT_OPCODE()
	}
	if IS_CV == IS_CONST {
		op1_str = Z_STR_P(op1)
	} else if EXPECTED(Z_TYPE_P(op1) == IS_STRING) {
		op1_str = ZendStringCopy(Z_STR_P(op1))
	} else {
		if IS_CV == IS_CV && UNEXPECTED(Z_TYPE_P(op1) == IS_UNDEF) {
			ZVAL_UNDEFINED_OP1()
		}
		op1_str = ZvalGetStringFunc(op1)
	}
	if IS_CONST == IS_CONST {
		op2_str = Z_STR_P(op2)
	} else if EXPECTED(Z_TYPE_P(op2) == IS_STRING) {
		op2_str = ZendStringCopy(Z_STR_P(op2))
	} else {
		if IS_CONST == IS_CV && UNEXPECTED(Z_TYPE_P(op2) == IS_UNDEF) {
			ZVAL_UNDEFINED_OP2()
		}
		op2_str = ZvalGetStringFunc(op2)
	}
	for {
		if IS_CV != IS_CONST {
			if UNEXPECTED(ZSTR_LEN(op1_str) == 0) {
				if IS_CONST == IS_CONST {
					if UNEXPECTED(Z_REFCOUNTED_P(op2)) {
						GC_ADDREF(op2_str)
					}
				}
				ZVAL_STR(EX_VAR(opline.GetResult().GetVar()), op2_str)
				ZendStringReleaseEx(op1_str, 0)
				break
			}
		}
		if IS_CONST != IS_CONST {
			if UNEXPECTED(ZSTR_LEN(op2_str) == 0) {
				if IS_CV == IS_CONST {
					if UNEXPECTED(Z_REFCOUNTED_P(op1)) {
						GC_ADDREF(op1_str)
					}
				}
				ZVAL_STR(EX_VAR(opline.GetResult().GetVar()), op1_str)
				ZendStringReleaseEx(op2_str, 0)
				break
			}
		}
		str = ZendStringAlloc(ZSTR_LEN(op1_str)+ZSTR_LEN(op2_str), 0)
		memcpy(ZSTR_VAL(str), ZSTR_VAL(op1_str), ZSTR_LEN(op1_str))
		memcpy(ZSTR_VAL(str)+ZSTR_LEN(op1_str), ZSTR_VAL(op2_str), ZSTR_LEN(op2_str)+1)
		ZVAL_NEW_STR(EX_VAR(opline.GetResult().GetVar()), str)
		if IS_CV != IS_CONST {
			ZendStringReleaseEx(op1_str, 0)
		}
		if IS_CONST != IS_CONST {
			ZendStringReleaseEx(op2_str, 0)
		}
		break
	}
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_INIT_METHOD_CALL_SPEC_CV_CONST_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var function_name *Zval
	var free_op1 ZendFreeOp
	var object *Zval
	var fbc *ZendFunction
	var called_scope *ZendClassEntry
	var obj *ZendObject
	var call *ZendExecuteData
	var call_info uint32
	object = EX_VAR(opline.GetOp1().GetVar())
	if IS_CV == IS_UNUSED && UNEXPECTED(Z_TYPE_P(object) == IS_UNDEF) {
		return zend_this_not_in_object_context_helper_SPEC(execute_data)
	}
	if IS_CONST != IS_CONST {
		function_name = RT_CONSTANT(opline, opline.GetOp2())
	}
	if IS_CONST != IS_CONST && UNEXPECTED(Z_TYPE_P(function_name) != IS_STRING) {
		for {
			if (IS_CONST&(IS_VAR|IS_CV)) != 0 && Z_ISREF_P(function_name) {
				function_name = Z_REFVAL_P(function_name)
				if EXPECTED(Z_TYPE_P(function_name) == IS_STRING) {
					break
				}
			} else if IS_CONST == IS_CV && UNEXPECTED(Z_TYPE_P(function_name) == IS_UNDEF) {
				ZVAL_UNDEFINED_OP2()
				if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
					HANDLE_EXCEPTION()
				}
			}
			ZendThrowError(nil, "Method name must be a string")
			HANDLE_EXCEPTION()
			break
		}
	}
	if IS_CV != IS_UNUSED {
		for {
			if IS_CV == IS_CONST || UNEXPECTED(Z_TYPE_P(object) != IS_OBJECT) {
				if (IS_CV&(IS_VAR|IS_CV)) != 0 && EXPECTED(Z_ISREF_P(object)) {
					object = Z_REFVAL_P(object)
					if EXPECTED(Z_TYPE_P(object) == IS_OBJECT) {
						break
					}
				}
				if IS_CV == IS_CV && UNEXPECTED(Z_TYPE_P(object) == IS_UNDEF) {
					object = ZVAL_UNDEFINED_OP1()
					if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
						if IS_CONST != IS_CONST {

						}
						HANDLE_EXCEPTION()
					}
				}
				if IS_CONST == IS_CONST {
					function_name = RT_CONSTANT(opline, opline.GetOp2())
				}
				ZendInvalidMethodCall(object, function_name)
				HANDLE_EXCEPTION()
			}
			break
		}
	}
	obj = Z_OBJ_P(object)
	called_scope = obj.GetCe()
	if IS_CONST == IS_CONST && EXPECTED(CACHED_PTR(opline.GetResult().GetNum()) == called_scope) {
		fbc = CACHED_PTR(opline.GetResult().GetNum() + b.SizeOf("void *"))
	} else {
		var orig_obj *ZendObject = obj
		if IS_CONST == IS_CONST {
			function_name = RT_CONSTANT(opline, opline.GetOp2())
		}

		/* First, locate the function. */

		fbc = obj.GetHandlers().GetGetMethod()(&obj, Z_STR_P(function_name), b.CondF1(IS_CONST == IS_CONST, func() *Zval { return RT_CONSTANT(opline, opline.GetOp2()) + 1 }, nil))
		if UNEXPECTED(fbc == nil) {
			if EXPECTED(ExecutorGlobals.GetException() == nil) {
				ZendUndefinedMethod(obj.GetCe(), Z_STR_P(function_name))
			}
			HANDLE_EXCEPTION()
		}
		if IS_CONST == IS_CONST && EXPECTED(fbc.GetType() <= ZEND_USER_FUNCTION) && EXPECTED(!fbc.HasFnFlags(ZEND_ACC_CALL_VIA_TRAMPOLINE|ZEND_ACC_NEVER_CACHE)) && EXPECTED(obj == orig_obj) {
			CACHE_POLYMORPHIC_PTR(opline.GetResult().GetNum(), called_scope, fbc)
		}
		if (IS_CV&(IS_VAR|IS_TMP_VAR)) != 0 && UNEXPECTED(obj != orig_obj) {

			/* Reset "object" to trigger reference counting */

			object = nil

			/* Reset "object" to trigger reference counting */

		}
		if EXPECTED(fbc.GetType() == ZEND_USER_FUNCTION) && UNEXPECTED(!(RUN_TIME_CACHE(&fbc.op_array))) {
			InitFuncRunTimeCache(&fbc.op_array)
		}
	}
	if IS_CONST != IS_CONST {

	}
	call_info = ZEND_CALL_NESTED_FUNCTION | ZEND_CALL_HAS_THIS
	if UNEXPECTED(fbc.IsStatic()) {
		if (IS_CV&(IS_VAR|IS_TMP_VAR)) != 0 && UNEXPECTED(ExecutorGlobals.GetException() != nil) {
			HANDLE_EXCEPTION()
		}

		/* call static method */

		obj = (*ZendObject)(called_scope)
		call_info = ZEND_CALL_NESTED_FUNCTION
	} else if (IS_CV & (IS_VAR | IS_TMP_VAR | IS_CV)) != 0 {
		if IS_CV == IS_CV {
			GC_ADDREF(obj)
		} else if free_op1 != object {
			GC_ADDREF(obj)
		}

		/* CV may be changed indirectly (e.g. when it's a reference) */

		call_info = ZEND_CALL_NESTED_FUNCTION | ZEND_CALL_HAS_THIS | ZEND_CALL_RELEASE_THIS

		/* CV may be changed indirectly (e.g. when it's a reference) */

	}
	call = ZendVmStackPushCallFrame(call_info, fbc, opline.GetExtendedValue(), obj)
	call.SetPrevExecuteData(EX(call))
	EX(call) = call
	ZEND_VM_NEXT_OPCODE()
}
func ZEND_ADD_ARRAY_ELEMENT_SPEC_CV_CONST_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var expr_ptr *Zval
	var new_expr Zval
	if (IS_CV == IS_VAR || IS_CV == IS_CV) && UNEXPECTED((opline.GetExtendedValue()&ZEND_ARRAY_ELEMENT_REF) != 0) {
		expr_ptr = _get_zval_ptr_cv_BP_VAR_W(opline.GetOp1().GetVar(), EXECUTE_DATA_C)
		if Z_ISREF_P(expr_ptr) {
			Z_ADDREF_P(expr_ptr)
		} else {
			ZVAL_MAKE_REF_EX(expr_ptr, 2)
		}
	} else {
		expr_ptr = _get_zval_ptr_cv_BP_VAR_R(opline.GetOp1().GetVar(), EXECUTE_DATA_C)
		if IS_CV == IS_TMP_VAR {

		} else if IS_CV == IS_CONST {
			Z_TRY_ADDREF_P(expr_ptr)
		} else if IS_CV == IS_CV {
			ZVAL_DEREF(expr_ptr)
			Z_TRY_ADDREF_P(expr_ptr)
		} else {
			if UNEXPECTED(Z_ISREF_P(expr_ptr)) {
				var ref *ZendRefcounted = Z_COUNTED_P(expr_ptr)
				expr_ptr = Z_REFVAL_P(expr_ptr)
				if UNEXPECTED(GC_DELREF(ref) == 0) {
					ZVAL_COPY_VALUE(&new_expr, expr_ptr)
					expr_ptr = &new_expr
					EfreeSize(ref, b.SizeOf("zend_reference"))
				} else if Z_OPT_REFCOUNTED_P(expr_ptr) {
					Z_ADDREF_P(expr_ptr)
				}
			}
		}
	}
	if IS_CONST != IS_UNUSED {
		var offset *Zval = RT_CONSTANT(opline, opline.GetOp2())
		var str *ZendString
		var hval ZendUlong
	add_again:
		if EXPECTED(Z_TYPE_P(offset) == IS_STRING) {
			str = Z_STR_P(offset)
			if IS_CONST != IS_CONST {
				if ZEND_HANDLE_NUMERIC(str, hval) != 0 {
					goto num_index
				}
			}
		str_index:
			Z_ARRVAL_P(EX_VAR(opline.GetResult().GetVar())).Update(str, expr_ptr)
		} else if EXPECTED(Z_TYPE_P(offset) == IS_LONG) {
			hval = Z_LVAL_P(offset)
		num_index:
			Z_ARRVAL_P(EX_VAR(opline.GetResult().GetVar())).IndexUpdate(hval, expr_ptr)
		} else if (IS_CONST&(IS_VAR|IS_CV)) != 0 && EXPECTED(Z_TYPE_P(offset) == IS_REFERENCE) {
			offset = Z_REFVAL_P(offset)
			goto add_again
		} else if Z_TYPE_P(offset) == IS_NULL {
			str = ZSTR_EMPTY_ALLOC()
			goto str_index
		} else if Z_TYPE_P(offset) == IS_DOUBLE {
			hval = ZendDvalToLval(Z_DVAL_P(offset))
			goto num_index
		} else if Z_TYPE_P(offset) == IS_FALSE {
			hval = 0
			goto num_index
		} else if Z_TYPE_P(offset) == IS_TRUE {
			hval = 1
			goto num_index
		} else if Z_TYPE_P(offset) == IS_RESOURCE {
			ZendUseResourceAsOffset(offset)
			hval = Z_RES_HANDLE_P(offset)
			goto num_index
		} else if IS_CONST == IS_CV && Z_TYPE_P(offset) == IS_UNDEF {
			ZVAL_UNDEFINED_OP2()
			str = ZSTR_EMPTY_ALLOC()
			goto str_index
		} else {
			ZendIllegalOffset()
			ZvalPtrDtorNogc(expr_ptr)
		}
	} else {
		if Z_ARRVAL_P(EX_VAR(opline.GetResult().GetVar())).NextIndexInsert(expr_ptr) == nil {
			ZendCannotAddElement()
			ZvalPtrDtorNogc(expr_ptr)
		}
	}
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_INIT_ARRAY_SPEC_CV_CONST_HANDLER(execute_data *ZendExecuteData) int {
	var array *Zval
	var size uint32
	var opline *ZendOp = EX(opline)
	array = EX_VAR(opline.GetResult().GetVar())
	if IS_CV != IS_UNUSED {
		size = opline.GetExtendedValue() >> ZEND_ARRAY_SIZE_SHIFT
		ZVAL_ARR(array, ZendNewArray(size))

		/* Explicitly initialize array as not-packed if flag is set */

		if (opline.GetExtendedValue() & ZEND_ARRAY_NOT_PACKED) != 0 {
			Z_ARRVAL_P(array).RealInitMixed()
		}
		return ZEND_ADD_ARRAY_ELEMENT_SPEC_CV_CONST_HANDLER(execute_data)
	} else {
		ZVAL_ARR(array, ZendNewArray(0))
		ZEND_VM_NEXT_OPCODE()
	}
}
func ZEND_UNSET_DIM_SPEC_CV_CONST_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var container *Zval
	var offset *Zval
	var hval ZendUlong
	var key *ZendString
	container = EX_VAR(opline.GetOp1().GetVar())
	offset = RT_CONSTANT(opline, opline.GetOp2())
	for {
		if EXPECTED(Z_TYPE_P(container) == IS_ARRAY) {
			var ht *HashTable
		unset_dim_array:
			SEPARATE_ARRAY(container)
			ht = Z_ARRVAL_P(container)
		offset_again:
			if EXPECTED(Z_TYPE_P(offset) == IS_STRING) {
				key = Z_STR_P(offset)
				if IS_CONST != IS_CONST {
					if ZEND_HANDLE_NUMERIC(key, hval) != 0 {
						goto num_index_dim
					}
				}
			str_index_dim:
				if ht == &(ExecutorGlobals.GetSymbolTable()) {
					ZendDeleteGlobalVariable(key)
				} else {
					ht.Del(key)
				}
			} else if EXPECTED(Z_TYPE_P(offset) == IS_LONG) {
				hval = Z_LVAL_P(offset)
			num_index_dim:
				ht.IndexDel(hval)
			} else if (IS_CONST&(IS_VAR|IS_CV)) != 0 && EXPECTED(Z_TYPE_P(offset) == IS_REFERENCE) {
				offset = Z_REFVAL_P(offset)
				goto offset_again
			} else if Z_TYPE_P(offset) == IS_DOUBLE {
				hval = ZendDvalToLval(Z_DVAL_P(offset))
				goto num_index_dim
			} else if Z_TYPE_P(offset) == IS_NULL {
				key = ZSTR_EMPTY_ALLOC()
				goto str_index_dim
			} else if Z_TYPE_P(offset) == IS_FALSE {
				hval = 0
				goto num_index_dim
			} else if Z_TYPE_P(offset) == IS_TRUE {
				hval = 1
				goto num_index_dim
			} else if Z_TYPE_P(offset) == IS_RESOURCE {
				hval = Z_RES_HANDLE_P(offset)
				goto num_index_dim
			} else if IS_CONST == IS_CV && Z_TYPE_P(offset) == IS_UNDEF {
				ZVAL_UNDEFINED_OP2()
				key = ZSTR_EMPTY_ALLOC()
				goto str_index_dim
			} else {
				ZendError(E_WARNING, "Illegal offset type in unset")
			}
			break
		} else if Z_ISREF_P(container) {
			container = Z_REFVAL_P(container)
			if EXPECTED(Z_TYPE_P(container) == IS_ARRAY) {
				goto unset_dim_array
			}
		}
		if IS_CV == IS_CV && UNEXPECTED(Z_TYPE_P(container) == IS_UNDEF) {
			container = ZVAL_UNDEFINED_OP1()
		}
		if IS_CONST == IS_CV && UNEXPECTED(Z_TYPE_P(offset) == IS_UNDEF) {
			offset = ZVAL_UNDEFINED_OP2()
		}
		if EXPECTED(Z_TYPE_P(container) == IS_OBJECT) {
			if IS_CONST == IS_CONST && Z_EXTRA_P(offset) == ZEND_EXTRA_VALUE {
				offset++
			}
			Z_OBJ_HT_P(container).GetUnsetDimension()(container, offset)
		} else if IS_CV != IS_UNUSED && UNEXPECTED(Z_TYPE_P(container) == IS_STRING) {
			ZendThrowError(nil, "Cannot unset string offsets")
		}
		break
	}
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_UNSET_OBJ_SPEC_CV_CONST_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var container *Zval
	var offset *Zval
	container = EX_VAR(opline.GetOp1().GetVar())
	if IS_CV == IS_UNUSED && UNEXPECTED(Z_TYPE_P(container) == IS_UNDEF) {
		return zend_this_not_in_object_context_helper_SPEC(execute_data)
	}
	offset = RT_CONSTANT(opline, opline.GetOp2())
	for {
		if IS_CV != IS_UNUSED && UNEXPECTED(Z_TYPE_P(container) != IS_OBJECT) {
			if Z_ISREF_P(container) {
				container = Z_REFVAL_P(container)
				if Z_TYPE_P(container) != IS_OBJECT {
					if IS_CV == IS_CV && UNEXPECTED(Z_TYPE_P(container) == IS_UNDEF) {
						ZVAL_UNDEFINED_OP1()
					}
					break
				}
			} else {
				break
			}
		}
		Z_OBJ_HT_P(container).GetUnsetProperty()(container, offset, b.CondF1(IS_CONST == IS_CONST, func() *any { return CACHE_ADDR(opline.GetExtendedValue()) }, nil))
		break
	}
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_ISSET_ISEMPTY_DIM_OBJ_SPEC_CV_CONST_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var container *Zval
	var result int
	var hval ZendUlong
	var offset *Zval
	container = EX_VAR(opline.GetOp1().GetVar())
	offset = RT_CONSTANT(opline, opline.GetOp2())
	if EXPECTED(Z_TYPE_P(container) == IS_ARRAY) {
		var ht *HashTable
		var value *Zval
		var str *ZendString
	isset_dim_obj_array:
		ht = Z_ARRVAL_P(container)
	isset_again:
		if EXPECTED(Z_TYPE_P(offset) == IS_STRING) {
			str = Z_STR_P(offset)
			if IS_CONST != IS_CONST {
				if ZEND_HANDLE_NUMERIC(str, hval) != 0 {
					goto num_index_prop
				}
			}
			value = ht.FindExInd(str, IS_CONST == IS_CONST)
		} else if EXPECTED(Z_TYPE_P(offset) == IS_LONG) {
			hval = Z_LVAL_P(offset)
		num_index_prop:
			value = ht.IndexFind(hval)
		} else if (IS_CONST&(IS_VAR|IS_CV)) != 0 && EXPECTED(Z_ISREF_P(offset)) {
			offset = Z_REFVAL_P(offset)
			goto isset_again
		} else {
			value = ZendFindArrayDimSlow(ht, offset, EXECUTE_DATA_C)
			if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
				result = 0
				goto isset_dim_obj_exit
			}
		}
		if (opline.GetExtendedValue() & ZEND_ISEMPTY) == 0 {

			/* > IS_NULL means not IS_UNDEF and not IS_NULL */

			result = value != nil && Z_TYPE_P(value) > IS_NULL && (!(Z_ISREF_P(value)) || Z_TYPE_P(Z_REFVAL_P(value)) != IS_NULL)
			if (IS_CV & (IS_CONST | IS_CV)) != 0 {

				/* avoid exception check */

				ZEND_VM_SMART_BRANCH(result, 0)
				ZVAL_BOOL(EX_VAR(opline.GetResult().GetVar()), result)
				ZEND_VM_NEXT_OPCODE()
			}
		} else {
			result = value == nil || IZendIsTrue(value) == 0
		}
		goto isset_dim_obj_exit
	} else if (IS_CV&(IS_VAR|IS_CV)) != 0 && EXPECTED(Z_ISREF_P(container)) {
		container = Z_REFVAL_P(container)
		if EXPECTED(Z_TYPE_P(container) == IS_ARRAY) {
			goto isset_dim_obj_array
		}
	}
	if IS_CONST == IS_CONST && Z_EXTRA_P(offset) == ZEND_EXTRA_VALUE {
		offset++
	}
	if (opline.GetExtendedValue() & ZEND_ISEMPTY) == 0 {
		result = ZendIssetDimSlow(container, offset, EXECUTE_DATA_C)
	} else {
		result = ZendIsemptyDimSlow(container, offset, EXECUTE_DATA_C)
	}
isset_dim_obj_exit:
	ZEND_VM_SMART_BRANCH(result, 1)
	ZVAL_BOOL(EX_VAR(opline.GetResult().GetVar()), result)
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_ISSET_ISEMPTY_PROP_OBJ_SPEC_CV_CONST_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var container *Zval
	var result int
	var offset *Zval
	container = _get_zval_ptr_cv_BP_VAR_IS(opline.GetOp1().GetVar(), EXECUTE_DATA_C)
	if IS_CV == IS_UNUSED && UNEXPECTED(Z_TYPE_P(container) == IS_UNDEF) {
		return zend_this_not_in_object_context_helper_SPEC(execute_data)
	}
	offset = RT_CONSTANT(opline, opline.GetOp2())
	if IS_CV == IS_CONST || IS_CV != IS_UNUSED && UNEXPECTED(Z_TYPE_P(container) != IS_OBJECT) {
		if (IS_CV&(IS_VAR|IS_CV)) != 0 && Z_ISREF_P(container) {
			container = Z_REFVAL_P(container)
			if UNEXPECTED(Z_TYPE_P(container) != IS_OBJECT) {
				result = opline.GetExtendedValue() & ZEND_ISEMPTY
				goto isset_object_finish
			}
		} else {
			result = opline.GetExtendedValue() & ZEND_ISEMPTY
			goto isset_object_finish
		}
	}
	result = opline.GetExtendedValue()&ZEND_ISEMPTY ^ Z_OBJ_HT_P(container).GetHasProperty()(container, offset, opline.GetExtendedValue()&ZEND_ISEMPTY, b.CondF1(IS_CONST == IS_CONST, func() *any { return CACHE_ADDR(opline.GetExtendedValue() & ^ZEND_ISEMPTY) }, nil))
isset_object_finish:
	ZEND_VM_SMART_BRANCH(result, 1)
	ZVAL_BOOL(EX_VAR(opline.GetResult().GetVar()), result)
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_ARRAY_KEY_EXISTS_SPEC_CV_CONST_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var key *Zval
	var subject *Zval
	var ht *HashTable
	var result uint32
	key = EX_VAR(opline.GetOp1().GetVar())
	subject = RT_CONSTANT(opline, opline.GetOp2())
	if EXPECTED(Z_TYPE_P(subject) == IS_ARRAY) {
	array_key_exists_array:
		ht = Z_ARRVAL_P(subject)
		result = ZendArrayKeyExistsFast(ht, key, OPLINE_C, EXECUTE_DATA_C)
	} else {
		if (IS_CONST&(IS_VAR|IS_CV)) != 0 && EXPECTED(Z_ISREF_P(subject)) {
			subject = Z_REFVAL_P(subject)
			if EXPECTED(Z_TYPE_P(subject) == IS_ARRAY) {
				goto array_key_exists_array
			}
		}
		result = ZendArrayKeyExistsSlow(subject, key, OPLINE_C, EXECUTE_DATA_C)
	}
	ZEND_VM_SMART_BRANCH(result == IS_TRUE, 1)
	Z_TYPE_INFO_P(EX_VAR(opline.GetResult().GetVar())) = result
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_INSTANCEOF_SPEC_CV_CONST_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var expr *Zval
	var result ZendBool
	expr = EX_VAR(opline.GetOp1().GetVar())
try_instanceof:
	if Z_TYPE_P(expr) == IS_OBJECT {
		var ce *ZendClassEntry
		if IS_CONST == IS_CONST {
			ce = CACHED_PTR(opline.GetExtendedValue())
			if UNEXPECTED(ce == nil) {
				ce = ZendFetchClassByName(Z_STR_P(RT_CONSTANT(opline, opline.GetOp2())), Z_STR_P(RT_CONSTANT(opline, opline.GetOp2())+1), ZEND_FETCH_CLASS_NO_AUTOLOAD)
				if EXPECTED(ce != nil) {
					CACHE_PTR(opline.GetExtendedValue(), ce)
				}
			}
		} else if IS_CONST == IS_UNUSED {
			ce = ZendFetchClass(nil, opline.GetOp2().GetNum())
			if UNEXPECTED(ce == nil) {
				ZEND_ASSERT(ExecutorGlobals.GetException() != nil)
				ZVAL_UNDEF(EX_VAR(opline.GetResult().GetVar()))
				HANDLE_EXCEPTION()
			}
		} else {
			ce = Z_CE_P(EX_VAR(opline.GetOp2().GetVar()))
		}
		result = ce != nil && InstanceofFunction(Z_OBJCE_P(expr), ce) != 0
	} else if (IS_CV&(IS_VAR|IS_CV)) != 0 && Z_TYPE_P(expr) == IS_REFERENCE {
		expr = Z_REFVAL_P(expr)
		goto try_instanceof
	} else {
		if IS_CV == IS_CV && UNEXPECTED(Z_TYPE_P(expr) == IS_UNDEF) {
			ZVAL_UNDEFINED_OP1()
		}
		result = 0
	}
	ZEND_VM_SMART_BRANCH(result, 1)
	ZVAL_BOOL(EX_VAR(opline.GetResult().GetVar()), result)
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_YIELD_SPEC_CV_CONST_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var generator *ZendGenerator = ZendGetRunningGenerator(EXECUTE_DATA_C)
	if UNEXPECTED(generator.IsForcedClose()) {
		return zend_yield_in_closed_generator_helper_SPEC(execute_data)
	}

	/* Destroy the previously yielded value */

	ZvalPtrDtor(&generator.value)

	/* Destroy the previously yielded key */

	ZvalPtrDtor(&generator.key)

	/* Set the new yielded value */

	if IS_CV != IS_UNUSED {
		if UNEXPECTED((EX(func_).op_array.fn_flags & ZEND_ACC_RETURN_REFERENCE) != 0) {

			/* Constants and temporary variables aren't yieldable by reference,
			 * but we still allow them with a notice. */

			if (IS_CV & (IS_CONST | IS_TMP_VAR)) != 0 {
				var value *Zval
				ZendError(E_NOTICE, "Only variable references should be yielded by reference")
				value = _get_zval_ptr_cv_BP_VAR_R(opline.GetOp1().GetVar(), EXECUTE_DATA_C)
				ZVAL_COPY_VALUE(&generator.value, value)
				if IS_CV == IS_CONST {
					if UNEXPECTED(Z_OPT_REFCOUNTED(generator.GetValue())) {
						Z_ADDREF(generator.GetValue())
					}
				}
			} else {
				var value_ptr *Zval = _get_zval_ptr_cv_BP_VAR_W(opline.GetOp1().GetVar(), EXECUTE_DATA_C)

				/* If a function call result is yielded and the function did
				 * not return by reference we throw a notice. */

				for {
					if IS_CV == IS_VAR {
						ZEND_ASSERT(value_ptr != &(ExecutorGlobals.GetUninitializedZval()))
						if opline.GetExtendedValue() == ZEND_RETURNS_FUNCTION && !(Z_ISREF_P(value_ptr)) {
							ZendError(E_NOTICE, "Only variable references should be yielded by reference")
							ZVAL_COPY(&generator.value, value_ptr)
							break
						}
					}
					if Z_ISREF_P(value_ptr) {
						Z_ADDREF_P(value_ptr)
					} else {
						ZVAL_MAKE_REF_EX(value_ptr, 2)
					}
					ZVAL_REF(&generator.value, Z_REF_P(value_ptr))
					break
				}

				/* If a function call result is yielded and the function did
				 * not return by reference we throw a notice. */

			}

			/* Constants and temporary variables aren't yieldable by reference,
			 * but we still allow them with a notice. */

		} else {
			var value *Zval = _get_zval_ptr_cv_BP_VAR_R(opline.GetOp1().GetVar(), EXECUTE_DATA_C)

			/* Consts, temporary variables and references need copying */

			if IS_CV == IS_CONST {
				ZVAL_COPY_VALUE(&generator.value, value)
				if UNEXPECTED(Z_OPT_REFCOUNTED(generator.GetValue())) {
					Z_ADDREF(generator.GetValue())
				}
			} else if IS_CV == IS_TMP_VAR {
				ZVAL_COPY_VALUE(&generator.value, value)
			} else if (IS_CV&(IS_VAR|IS_CV)) != 0 && Z_ISREF_P(value) {
				ZVAL_COPY(&generator.value, Z_REFVAL_P(value))
			} else {
				ZVAL_COPY_VALUE(&generator.value, value)
				if IS_CV == IS_CV {
					if Z_OPT_REFCOUNTED_P(value) {
						Z_ADDREF_P(value)
					}
				}
			}

			/* Consts, temporary variables and references need copying */

		}
	} else {

		/* If no value was specified yield null */

		ZVAL_NULL(&generator.value)

		/* If no value was specified yield null */

	}

	/* Set the new yielded key */

	if IS_CONST != IS_UNUSED {
		var key *Zval = RT_CONSTANT(opline, opline.GetOp2())

		/* Consts, temporary variables and references need copying */

		if IS_CONST == IS_CONST {
			ZVAL_COPY_VALUE(&generator.key, key)
			if UNEXPECTED(Z_OPT_REFCOUNTED(generator.GetKey())) {
				Z_ADDREF(generator.GetKey())
			}
		} else if IS_CONST == IS_TMP_VAR {
			ZVAL_COPY_VALUE(&generator.key, key)
		} else if (IS_CONST&(IS_VAR|IS_CV)) != 0 && Z_ISREF_P(key) {
			ZVAL_COPY(&generator.key, Z_REFVAL_P(key))
		} else {
			ZVAL_COPY_VALUE(&generator.key, key)
			if IS_CONST == IS_CV {
				if Z_OPT_REFCOUNTED_P(key) {
					Z_ADDREF_P(key)
				}
			}
		}
		if Z_TYPE(generator.GetKey()) == IS_LONG && Z_LVAL(generator.GetKey()) > generator.GetLargestUsedIntegerKey() {
			generator.SetLargestUsedIntegerKey(Z_LVAL(generator.GetKey()))
		}
	} else {

		/* If no key was specified we use auto-increment keys */

		generator.GetLargestUsedIntegerKey()++
		ZVAL_LONG(&generator.key, generator.GetLargestUsedIntegerKey())
	}
	if RETURN_VALUE_USED(opline) {

		/* If the return value of yield is used set the send
		 * target and initialize it to NULL */

		generator.SetSendTarget(EX_VAR(opline.GetResult().GetVar()))
		ZVAL_NULL(generator.GetSendTarget())
	} else {
		generator.SetSendTarget(nil)
	}

	/* We increment to the next op, so we are at the correct position when the
	 * generator is resumed. */

	ZEND_VM_INC_OPCODE()

	/* The GOTO VM uses a local opline variable. We need to set the opline
	 * variable in execute_data so we don't resume at an old position. */

	return -1
}
func ZEND_BIND_GLOBAL_SPEC_CV_CONST_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var varname *ZendString
	var value *Zval
	var variable_ptr *Zval
	var idx uintPtr
	var ref *ZendReference
	for {
		varname = Z_STR_P(RT_CONSTANT(opline, opline.GetOp2()))

		/* We store "hash slot index" + 1 (NULL is a mark of uninitialized cache slot) */

		idx = uintPtr(CACHED_PTR(opline.GetExtendedValue()) - 1)
		if EXPECTED(idx < ExecutorGlobals.GetSymbolTable().GetNNumUsed()*b.SizeOf("Bucket")) {
			var p *Bucket = (*Bucket)((*byte)(ExecutorGlobals.GetSymbolTable().GetArData() + idx))
			if EXPECTED(Z_TYPE(p.GetVal()) != IS_UNDEF) && (EXPECTED(p.GetKey() == varname) || EXPECTED(p.GetH() == ZSTR_H(varname)) && EXPECTED(p.GetKey() != nil) && EXPECTED(ZendStringEqualContent(p.GetKey(), varname) != 0)) {
				value = (*Zval)(p)
				goto check_indirect
			}
		}
		value = &(ExecutorGlobals.GetSymbolTable()).FindEx(varname, 1)
		if UNEXPECTED(value == nil) {
			value = &(ExecutorGlobals.GetSymbolTable()).AddNew(varname, &(ExecutorGlobals.GetUninitializedZval()))
			idx = (*byte)(value - (*byte)(ExecutorGlobals.GetSymbolTable().GetArData()))

			/* Store "hash slot index" + 1 (NULL is a mark of uninitialized cache slot) */

			CACHE_PTR(opline.GetExtendedValue(), any(idx+1))

			/* Store "hash slot index" + 1 (NULL is a mark of uninitialized cache slot) */

		} else {
			idx = (*byte)(value - (*byte)(ExecutorGlobals.GetSymbolTable().GetArData()))

			/* Store "hash slot index" + 1 (NULL is a mark of uninitialized cache slot) */

			CACHE_PTR(opline.GetExtendedValue(), any(idx+1))
		check_indirect:

			/* GLOBAL variable may be an INDIRECT pointer to CV */

			if UNEXPECTED(Z_TYPE_P(value) == IS_INDIRECT) {
				value = Z_INDIRECT_P(value)
				if UNEXPECTED(Z_TYPE_P(value) == IS_UNDEF) {
					ZVAL_NULL(value)
				}
			}

			/* GLOBAL variable may be an INDIRECT pointer to CV */

		}
		if UNEXPECTED(!(Z_ISREF_P(value))) {
			ZVAL_MAKE_REF_EX(value, 2)
			ref = Z_REF_P(value)
		} else {
			ref = Z_REF_P(value)
			GC_ADDREF(ref)
		}
		variable_ptr = EX_VAR(opline.GetOp1().GetVar())
		if UNEXPECTED(Z_REFCOUNTED_P(variable_ptr)) {
			var ref *ZendRefcounted = Z_COUNTED_P(variable_ptr)
			var refcnt uint32 = GC_DELREF(ref)
			if EXPECTED(variable_ptr != value) {
				if refcnt == 0 {
					RcDtorFunc(ref)
					if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
						ZVAL_NULL(variable_ptr)
						HANDLE_EXCEPTION()
					}
				} else {
					GcCheckPossibleRoot(ref)
				}
			}
		}
		ZVAL_REF(variable_ptr, ref)
		if !(UNEXPECTED(b.PreInc(&opline).opcode == ZEND_BIND_GLOBAL)) {
			break
		}
	}
	OPLINE = opline
	return 0
	ZEND_VM_NEXT_OPCODE()
}
func ZEND_IN_ARRAY_SPEC_CV_CONST_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var op1 *Zval
	var ht *HashTable = Z_ARRVAL_P(RT_CONSTANT(opline, opline.GetOp2()))
	var result *Zval
	op1 = _get_zval_ptr_cv_deref_BP_VAR_R(opline.GetOp1().GetVar(), EXECUTE_DATA_C)
	if EXPECTED(Z_TYPE_P(op1) == IS_STRING) {
		result = ht.FindEx(Z_STR_P(op1), IS_CV == IS_CONST)
	} else if opline.GetExtendedValue() != 0 {
		if EXPECTED(Z_TYPE_P(op1) == IS_LONG) {
			result = ht.IndexFind(Z_LVAL_P(op1))
		} else {
			result = nil
		}
	} else if Z_TYPE_P(op1) <= IS_FALSE {
		result = ht.FindEx(ZSTR_EMPTY_ALLOC(), 1)
	} else {
		var key *ZendString
		var key_tmp Zval
		var result_tmp Zval
		var val *Zval
		result = nil
		for {
			var __ht *HashTable = ht
			var _p *Bucket = __ht.GetArData()
			var _end *Bucket = _p + __ht.GetNNumUsed()
			for ; _p != _end; _p++ {
				var _z *Zval = &_p.val

				if UNEXPECTED(Z_TYPE_P(_z) == IS_UNDEF) {
					continue
				}
				key = _p.GetKey()
				val = _z
				ZVAL_STR(&key_tmp, key)
				CompareFunction(&result_tmp, op1, &key_tmp)
				if Z_LVAL(result_tmp) == 0 {
					result = val
					break
				}
			}
			break
		}
	}
	ZEND_VM_SMART_BRANCH(result, 1)
	ZVAL_BOOL(EX_VAR(opline.GetResult().GetVar()), result != nil)
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
