func ZEND_ASSIGN_SPEC_CV_TMP_RETVAL_UNUSED_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var free_op2 ZendFreeOp
	var value *Zval
	var variable_ptr *Zval
	value = _getZvalPtrTmp(opline.GetOp2().GetVar(), &free_op2, EXECUTE_DATA_C)
	variable_ptr = EX_VAR(opline.GetOp1().GetVar())
	if IS_CV == IS_VAR && UNEXPECTED(Z_ISERROR_P(variable_ptr)) {
		ZvalPtrDtorNogc(free_op2)
		if UNEXPECTED(false) {
			ZVAL_NULL(EX_VAR(opline.GetResult().GetVar()))
		}
	} else {
		value = ZendAssignToVariable(variable_ptr, value, IS_TMP_VAR, EX_USES_STRICT_TYPES())
		if UNEXPECTED(false) {
			ZVAL_COPY(EX_VAR(opline.GetResult().GetVar()), value)
		}
	}
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
