func ZEND_ASSIGN_REF_SPEC_CV_VAR_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var free_op2 ZendFreeOp
	var variable_ptr *Zval
	var value_ptr *Zval
	value_ptr = _getZvalPtrPtrVar(opline.GetOp2().GetVar(), &free_op2, EXECUTE_DATA_C)
	variable_ptr = EX_VAR(opline.GetOp1().GetVar())
	if IS_CV == IS_VAR && UNEXPECTED(Z_ISERROR_P(variable_ptr)) {
		variable_ptr = &(ExecutorGlobals.GetUninitializedZval())
	} else if IS_CV == IS_VAR && UNEXPECTED(Z_TYPE_P(EX_VAR(opline.GetOp1().GetVar())) != IS_INDIRECT) {
		ZendThrowError(nil, "Cannot assign by reference to an array dimension of an object")
		variable_ptr = &(ExecutorGlobals.GetUninitializedZval())
	} else if IS_VAR == IS_VAR && UNEXPECTED(Z_ISERROR_P(value_ptr)) {
		variable_ptr = &(ExecutorGlobals.GetUninitializedZval())
	} else if IS_VAR == IS_VAR && opline.GetExtendedValue() == ZEND_RETURNS_FUNCTION && UNEXPECTED(!(Z_ISREF_P(value_ptr))) {
		variable_ptr = ZendWrongAssignToVariableReference(variable_ptr, value_ptr, OPLINE_C, EXECUTE_DATA_C)
	} else {
		ZendAssignToVariableReference(variable_ptr, value_ptr)
	}
	if UNEXPECTED(RETURN_VALUE_USED(opline)) {
		ZVAL_COPY(EX_VAR(opline.GetResult().GetVar()), variable_ptr)
	}
	if UNEXPECTED(free_op2 != nil) {
		ZvalPtrDtorNogc(free_op2)
	}
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_INSTANCEOF_SPEC_CV_VAR_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var expr *Zval
	var result ZendBool
	expr = EX_VAR(opline.GetOp1().GetVar())
try_instanceof:
	if Z_TYPE_P(expr) == IS_OBJECT {
		var ce *ZendClassEntry
		if IS_VAR == IS_CONST {
			ce = CACHED_PTR(opline.GetExtendedValue())
			if UNEXPECTED(ce == nil) {
				ce = ZendFetchClassByName(Z_STR_P(RT_CONSTANT(opline, opline.GetOp2())), Z_STR_P(RT_CONSTANT(opline, opline.GetOp2())+1), ZEND_FETCH_CLASS_NO_AUTOLOAD)
				if EXPECTED(ce != nil) {
					CACHE_PTR(opline.GetExtendedValue(), ce)
				}
			}
		} else if IS_VAR == IS_UNUSED {
			ce = ZendFetchClass(nil, opline.GetOp2().GetNum())
			if UNEXPECTED(ce == nil) {
				ZEND_ASSERT(ExecutorGlobals.GetException() != nil)
				ZVAL_UNDEF(EX_VAR(opline.GetResult().GetVar()))
				HANDLE_EXCEPTION()
			}
		} else {
			ce = Z_CE_P(EX_VAR(opline.GetOp2().GetVar()))
		}
		result = ce != nil && InstanceofFunction(Z_OBJCE_P(expr), ce) != 0
	} else if (IS_CV&(IS_VAR|IS_CV)) != 0 && Z_TYPE_P(expr) == IS_REFERENCE {
		expr = Z_REFVAL_P(expr)
		goto try_instanceof
	} else {
		if IS_CV == IS_CV && UNEXPECTED(Z_TYPE_P(expr) == IS_UNDEF) {
			ZVAL_UNDEFINED_OP1()
		}
		result = 0
	}
	ZEND_VM_SMART_BRANCH(result, 1)
	ZVAL_BOOL(EX_VAR(opline.GetResult().GetVar()), result)
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_YIELD_SPEC_CV_VAR_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var generator *ZendGenerator = ZendGetRunningGenerator(EXECUTE_DATA_C)
	if UNEXPECTED(generator.IsForcedClose()) {
		return zend_yield_in_closed_generator_helper_SPEC(execute_data)
	}

	/* Destroy the previously yielded value */

	ZvalPtrDtor(&generator.value)

	/* Destroy the previously yielded key */

	ZvalPtrDtor(&generator.key)

	/* Set the new yielded value */

	if IS_CV != IS_UNUSED {
		if UNEXPECTED((EX(func_).op_array.fn_flags & ZEND_ACC_RETURN_REFERENCE) != 0) {

			/* Constants and temporary variables aren't yieldable by reference,
			 * but we still allow them with a notice. */

			if (IS_CV & (IS_CONST | IS_TMP_VAR)) != 0 {
				var value *Zval
				ZendError(E_NOTICE, "Only variable references should be yielded by reference")
				value = _get_zval_ptr_cv_BP_VAR_R(opline.GetOp1().GetVar(), EXECUTE_DATA_C)
				ZVAL_COPY_VALUE(&generator.value, value)
				if IS_CV == IS_CONST {
					if UNEXPECTED(Z_OPT_REFCOUNTED(generator.GetValue())) {
						Z_ADDREF(generator.GetValue())
					}
				}
			} else {
				var value_ptr *Zval = _get_zval_ptr_cv_BP_VAR_W(opline.GetOp1().GetVar(), EXECUTE_DATA_C)

				/* If a function call result is yielded and the function did
				 * not return by reference we throw a notice. */

				for {
					if IS_CV == IS_VAR {
						ZEND_ASSERT(value_ptr != &(ExecutorGlobals.GetUninitializedZval()))
						if opline.GetExtendedValue() == ZEND_RETURNS_FUNCTION && !(Z_ISREF_P(value_ptr)) {
							ZendError(E_NOTICE, "Only variable references should be yielded by reference")
							ZVAL_COPY(&generator.value, value_ptr)
							break
						}
					}
					if Z_ISREF_P(value_ptr) {
						Z_ADDREF_P(value_ptr)
					} else {
						ZVAL_MAKE_REF_EX(value_ptr, 2)
					}
					ZVAL_REF(&generator.value, Z_REF_P(value_ptr))
					break
				}

				/* If a function call result is yielded and the function did
				 * not return by reference we throw a notice. */

			}

			/* Constants and temporary variables aren't yieldable by reference,
			 * but we still allow them with a notice. */

		} else {
			var value *Zval = _get_zval_ptr_cv_BP_VAR_R(opline.GetOp1().GetVar(), EXECUTE_DATA_C)

			/* Consts, temporary variables and references need copying */

			if IS_CV == IS_CONST {
				ZVAL_COPY_VALUE(&generator.value, value)
				if UNEXPECTED(Z_OPT_REFCOUNTED(generator.GetValue())) {
					Z_ADDREF(generator.GetValue())
				}
			} else if IS_CV == IS_TMP_VAR {
				ZVAL_COPY_VALUE(&generator.value, value)
			} else if (IS_CV&(IS_VAR|IS_CV)) != 0 && Z_ISREF_P(value) {
				ZVAL_COPY(&generator.value, Z_REFVAL_P(value))
			} else {
				ZVAL_COPY_VALUE(&generator.value, value)
				if IS_CV == IS_CV {
					if Z_OPT_REFCOUNTED_P(value) {
						Z_ADDREF_P(value)
					}
				}
			}

			/* Consts, temporary variables and references need copying */

		}
	} else {

		/* If no value was specified yield null */

		ZVAL_NULL(&generator.value)

		/* If no value was specified yield null */

	}

	/* Set the new yielded key */

	if IS_VAR != IS_UNUSED {
		var free_op2 ZendFreeOp
		var key *Zval = _getZvalPtrVar(opline.GetOp2().GetVar(), &free_op2, EXECUTE_DATA_C)

		/* Consts, temporary variables and references need copying */

		if IS_VAR == IS_CONST {
			ZVAL_COPY_VALUE(&generator.key, key)
			if UNEXPECTED(Z_OPT_REFCOUNTED(generator.GetKey())) {
				Z_ADDREF(generator.GetKey())
			}
		} else if IS_VAR == IS_TMP_VAR {
			ZVAL_COPY_VALUE(&generator.key, key)
		} else if (IS_VAR&(IS_VAR|IS_CV)) != 0 && Z_ISREF_P(key) {
			ZVAL_COPY(&generator.key, Z_REFVAL_P(key))
			ZvalPtrDtorNogc(free_op2)
		} else {
			ZVAL_COPY_VALUE(&generator.key, key)
			if IS_VAR == IS_CV {
				if Z_OPT_REFCOUNTED_P(key) {
					Z_ADDREF_P(key)
				}
			}
		}
		if Z_TYPE(generator.GetKey()) == IS_LONG && Z_LVAL(generator.GetKey()) > generator.GetLargestUsedIntegerKey() {
			generator.SetLargestUsedIntegerKey(Z_LVAL(generator.GetKey()))
		}
	} else {

		/* If no key was specified we use auto-increment keys */

		generator.GetLargestUsedIntegerKey()++
		ZVAL_LONG(&generator.key, generator.GetLargestUsedIntegerKey())
	}
	if RETURN_VALUE_USED(opline) {

		/* If the return value of yield is used set the send
		 * target and initialize it to NULL */

		generator.SetSendTarget(EX_VAR(opline.GetResult().GetVar()))
		ZVAL_NULL(generator.GetSendTarget())
	} else {
		generator.SetSendTarget(nil)
	}

	/* We increment to the next op, so we are at the correct position when the
	 * generator is resumed. */

	ZEND_VM_INC_OPCODE()

	/* The GOTO VM uses a local opline variable. We need to set the opline
	 * variable in execute_data so we don't resume at an old position. */

	return -1
}
func ZEND_ASSIGN_DIM_OP_SPEC_CV_UNUSED_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var free_op_data1 ZendFreeOp
	var var_ptr *Zval
	var value *Zval
	var container *Zval
	var dim *Zval
	container = EX_VAR(opline.GetOp1().GetVar())
	if EXPECTED(Z_TYPE_P(container) == IS_ARRAY) {
	assign_dim_op_array:
		SEPARATE_ARRAY(container)
	assign_dim_op_new_array:
		dim = nil
		if IS_UNUSED == IS_UNUSED {
			var_ptr = Z_ARRVAL_P(container).NextIndexInsert(&(ExecutorGlobals.GetUninitializedZval()))
			if UNEXPECTED(var_ptr == nil) {
				ZendCannotAddElement()
				goto assign_dim_op_ret_null
			}
		} else {
			if IS_UNUSED == IS_CONST {
				var_ptr = zend_fetch_dimension_address_inner_RW_CONST(Z_ARRVAL_P(container), dim, EXECUTE_DATA_C)
			} else {
				var_ptr = zend_fetch_dimension_address_inner_RW(Z_ARRVAL_P(container), dim, EXECUTE_DATA_C)
			}
			if UNEXPECTED(var_ptr == nil) {
				goto assign_dim_op_ret_null
			}
		}
		value = GetOpDataZvalPtrR((opline + 1).GetOp1Type(), (opline + 1).GetOp1(), &free_op_data1)
		for {
			if IS_UNUSED != IS_UNUSED && UNEXPECTED(Z_ISREF_P(var_ptr)) {
				var ref *ZendReference = Z_REF_P(var_ptr)
				var_ptr = Z_REFVAL_P(var_ptr)
				if UNEXPECTED(ZEND_REF_HAS_TYPE_SOURCES(ref)) {
					ZendBinaryAssignOpTypedRef(ref, value, OPLINE_C, EXECUTE_DATA_C)
					break
				}
			}
			ZendBinaryOp(var_ptr, var_ptr, value, OPLINE_C)
			break
		}
		if UNEXPECTED(RETURN_VALUE_USED(opline)) {
			ZVAL_COPY(EX_VAR(opline.GetResult().GetVar()), var_ptr)
		}
		FREE_OP(free_op_data1)
	} else {
		if EXPECTED(Z_ISREF_P(container)) {
			container = Z_REFVAL_P(container)
			if EXPECTED(Z_TYPE_P(container) == IS_ARRAY) {
				goto assign_dim_op_array
			}
		}
		dim = nil
		if EXPECTED(Z_TYPE_P(container) == IS_OBJECT) {
			if IS_UNUSED == IS_CONST && Z_EXTRA_P(dim) == ZEND_EXTRA_VALUE {
				dim++
			}
			ZendBinaryAssignOpObjDim(container, dim, OPLINE_C, EXECUTE_DATA_C)
		} else if EXPECTED(Z_TYPE_P(container) <= IS_FALSE) {
			if IS_CV == IS_CV && UNEXPECTED(Z_TYPE_INFO_P(container) == IS_UNDEF) {
				ZVAL_UNDEFINED_OP1()
			}
			ZVAL_ARR(container, ZendNewArray(8))
			goto assign_dim_op_new_array
		} else {
			ZendBinaryAssignOpDimSlow(container, dim, OPLINE_C, EXECUTE_DATA_C)
		assign_dim_op_ret_null:
			FREE_UNFETCHED_OP((opline + 1).GetOp1Type(), (opline + 1).GetOp1().GetVar())
			if UNEXPECTED(RETURN_VALUE_USED(opline)) {
				ZVAL_NULL(EX_VAR(opline.GetResult().GetVar()))
			}
		}
	}
	OPLINE = EX(opline) + 2
	return 0
}
func zend_fetch_var_address_helper_SPEC_CV_UNUSED(type_ int, execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var varname *Zval
	var retval *Zval
	var name *ZendString
	var tmp_name *ZendString
	var target_symbol_table *HashTable
	varname = EX_VAR(opline.GetOp1().GetVar())
	if IS_CV == IS_CONST {
		name = Z_STR_P(varname)
	} else if EXPECTED(Z_TYPE_P(varname) == IS_STRING) {
		name = Z_STR_P(varname)
		tmp_name = nil
	} else {
		if IS_CV == IS_CV && UNEXPECTED(Z_TYPE_P(varname) == IS_UNDEF) {
			ZVAL_UNDEFINED_OP1()
		}
		name = ZvalTryGetTmpString(varname, &tmp_name)
		if UNEXPECTED(name == nil) {
			ZVAL_UNDEF(EX_VAR(opline.GetResult().GetVar()))
			HANDLE_EXCEPTION()
		}
	}
	target_symbol_table = ZendGetTargetSymbolTable(opline.GetExtendedValue(), EXECUTE_DATA_C)
	retval = target_symbol_table.FindEx(name, IS_CV == IS_CONST)
	if retval == nil {
		if UNEXPECTED(ZendStringEquals(name, ZSTR_KNOWN(ZEND_STR_THIS)) != 0) {
		fetch_this:
			ZendFetchThisVar(type_, OPLINE_C, EXECUTE_DATA_C)
			if IS_CV != IS_CONST {
				ZendTmpStringRelease(tmp_name)
			}
			ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
		}
		if type_ == BP_VAR_W {
			retval = target_symbol_table.AddNew(name, &(ExecutorGlobals.GetUninitializedZval()))
		} else if type_ == BP_VAR_IS {
			retval = &(ExecutorGlobals.GetUninitializedZval())
		} else {
			ZendError(E_NOTICE, "Undefined variable: %s", ZSTR_VAL(name))
			if type_ == BP_VAR_RW {
				retval = target_symbol_table.Update(name, &(ExecutorGlobals.GetUninitializedZval()))
			} else {
				retval = &(ExecutorGlobals.GetUninitializedZval())
			}
		}
	} else if Z_TYPE_P(retval) == IS_INDIRECT {
		retval = Z_INDIRECT_P(retval)
		if Z_TYPE_P(retval) == IS_UNDEF {
			if UNEXPECTED(ZendStringEquals(name, ZSTR_KNOWN(ZEND_STR_THIS)) != 0) {
				goto fetch_this
			}
			if type_ == BP_VAR_W {
				ZVAL_NULL(retval)
			} else if type_ == BP_VAR_IS {
				retval = &(ExecutorGlobals.GetUninitializedZval())
			} else {
				ZendError(E_NOTICE, "Undefined variable: %s", ZSTR_VAL(name))
				if type_ == BP_VAR_RW {
					ZVAL_NULL(retval)
				} else {
					retval = &(ExecutorGlobals.GetUninitializedZval())
				}
			}
		}
	}
	if (opline.GetExtendedValue() & ZEND_FETCH_GLOBAL_LOCK) == 0 {

	}
	if IS_CV != IS_CONST {
		ZendTmpStringRelease(tmp_name)
	}
	ZEND_ASSERT(retval != nil)
	if type_ == BP_VAR_R || type_ == BP_VAR_IS {
		ZVAL_COPY_DEREF(EX_VAR(opline.GetResult().GetVar()), retval)
	} else {
		ZVAL_INDIRECT(EX_VAR(opline.GetResult().GetVar()), retval)
	}
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
