func ZEND_MAKE_REF_SPEC_CV_UNUSED_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var op1 *Zval = EX_VAR(opline.GetOp1().GetVar())
	if IS_CV == IS_CV {
		if UNEXPECTED(Z_TYPE_P(op1) == IS_UNDEF) {
			ZVAL_NEW_EMPTY_REF(op1)
			Z_SET_REFCOUNT_P(op1, 2)
			ZVAL_NULL(Z_REFVAL_P(op1))
			ZVAL_REF(EX_VAR(opline.GetResult().GetVar()), Z_REF_P(op1))
		} else {
			if Z_ISREF_P(op1) {
				Z_ADDREF_P(op1)
			} else {
				ZVAL_MAKE_REF_EX(op1, 2)
			}
			ZVAL_REF(EX_VAR(opline.GetResult().GetVar()), Z_REF_P(op1))
		}
	} else if EXPECTED(Z_TYPE_P(op1) == IS_INDIRECT) {
		op1 = Z_INDIRECT_P(op1)
		if EXPECTED(!(Z_ISREF_P(op1))) {
			ZVAL_MAKE_REF_EX(op1, 2)
		} else {
			GC_ADDREF(Z_REF_P(op1))
		}
		ZVAL_REF(EX_VAR(opline.GetResult().GetVar()), Z_REF_P(op1))
	} else {
		ZVAL_COPY_VALUE(EX_VAR(opline.GetResult().GetVar()), op1)
	}
	ZEND_VM_NEXT_OPCODE()
}
func ZEND_COUNT_SPEC_CV_UNUSED_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	var op1 *Zval
	var count ZendLong
	op1 = EX_VAR(opline.GetOp1().GetVar())
	for true {
		if Z_TYPE_P(op1) == IS_ARRAY {
			count = ZendArrayCount(Z_ARRVAL_P(op1))
			break
		} else if Z_TYPE_P(op1) == IS_OBJECT {

			/* first, we check if the handler is defined */

			if Z_OBJ_HT_P(op1).GetCountElements() != nil {
				if SUCCESS == Z_OBJ_HT_P(op1).GetCountElements()(op1, &count) {
					break
				}
				if UNEXPECTED(ExecutorGlobals.GetException() != nil) {
					count = 0
					break
				}
			}

			/* if not and the object implements Countable we call its count() method */

			if InstanceofFunction(Z_OBJCE_P(op1), ZendCeCountable) != 0 {
				var retval Zval
				ZendCallMethodWith0Params(op1, nil, nil, "count", &retval)
				count = ZvalGetLong(&retval)
				ZvalPtrDtor(&retval)
				break
			}

			/* If There's no handler and it doesn't implement Countable then add a warning */

			count = 1

			/* If There's no handler and it doesn't implement Countable then add a warning */

		} else if (IS_CV&(IS_VAR|IS_CV)) != 0 && Z_TYPE_P(op1) == IS_REFERENCE {
			op1 = Z_REFVAL_P(op1)
			continue
		} else if Z_TYPE_P(op1) <= IS_NULL {
			if IS_CV == IS_CV && UNEXPECTED(Z_TYPE_P(op1) == IS_UNDEF) {
				ZVAL_UNDEFINED_OP1()
			}
			count = 0
		} else {
			count = 1
		}
		ZendError(E_WARNING, "%s(): Parameter must be an array or an object that implements Countable", b.Cond(opline.GetExtendedValue() != 0, "sizeof", "count"))
		break
	}
	ZVAL_LONG(EX_VAR(opline.GetResult().GetVar()), count)
	ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
}
func ZEND_GET_CLASS_SPEC_CV_UNUSED_HANDLER(execute_data *ZendExecuteData) int {
	var opline *ZendOp = EX(opline)
	if IS_CV == IS_UNUSED {
		if UNEXPECTED(!(EX(func_).common.scope)) {
			ZendError(E_WARNING, "get_class() called without object from outside a class")
			ZVAL_FALSE(EX_VAR(opline.GetResult().GetVar()))
			ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
		} else {
			ZVAL_STR_COPY(EX_VAR(opline.GetResult().GetVar()), EX(func_).common.scope.name)
			ZEND_VM_NEXT_OPCODE()
		}
	} else {
		var op1 *Zval
		op1 = EX_VAR(opline.GetOp1().GetVar())
		for true {
			if Z_TYPE_P(op1) == IS_OBJECT {
				ZVAL_STR_COPY(EX_VAR(opline.GetResult().GetVar()), Z_OBJCE_P(op1).GetName())
			} else if (IS_CV&(IS_VAR|IS_CV)) != 0 && Z_TYPE_P(op1) == IS_REFERENCE {
				op1 = Z_REFVAL_P(op1)
				continue
			} else {
				if IS_CV == IS_CV && UNEXPECTED(Z_TYPE_P(op1) == IS_UNDEF) {
					ZVAL_UNDEFINED_OP1()
				}
				ZendError(E_WARNING, "get_class() expects parameter 1 to be object, %s given", ZendGetTypeByConst(Z_TYPE_P(op1)))
				ZVAL_FALSE(EX_VAR(opline.GetResult().GetVar()))
			}
			break
		}
		ZEND_VM_NEXT_OPCODE_CHECK_EXCEPTION()
	}
}
